{
  "name": "Invoice → X12 810 EDI + Barcode Sheet",
  "description": "A professional tool for converting invoice images into structured X12 810 EDI data and generating barcode label sheets for detected logistics codes.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Invoice {
  invoice_number: string;
  invoice_date: string;
  seller: { name: string; address: string; tax_id: string };
  buyer: { name: string; address: string; tax_id: string };
  ship_to: { name: string; address: string };
  po_number: string;
  currency: string;
  payment_terms: string;
  totals: { subtotal: number | null; tax: number | null; total: number | null };
  line_items: Array<{
    description: string;
    sku: string;
    qty: number | null;
    uom: string;
    unit_price: number | null;
    line_total: number | null;
  }>;
}

export interface ProcessingResult {
  invoice: Invoice;
  edi_810: string;
  missing_fields: string[];
  warnings: string[];
  needs_review: boolean;
}

export interface DetectedCode {
  type: string;
  value: string;
}

export enum ProcessingStep {
  IDLE = 'IDLE',
  SCANNING_BARCODES = 'Scanning barcode locally...',
  UNDERSTANDING_INVOICE = 'Understanding invoice...',
  GENERATING_EDI = 'Generating EDI...',
  GENERATING_PDF = 'Generating barcode PDF...',
  COMPLETED = 'Completed',
  ERROR = 'Error'
}

import React, { useState, useCallback } from 'react';
import { 
  FileText, 
  BarChart3, 
  Upload, 
  AlertCircle, 
  CheckCircle2, 
  RefreshCcw, 
  ArrowRight,
  Clipboard,
  Download,
  FileDigit,
  LayoutGrid
} from 'lucide-react';
import { FileUploader } from './components/FileUploader';
import { ResultsPanel } from './components/ResultsPanel';
import { StepProgress } from './components/StepProgress';
import { ValidationBadge } from './components/ValidationBadge';
import { ProcessingStep, ProcessingResult, DetectedCode } from './types';
import { scanBarcodes } from './services/barcodeScanner';
import { processInvoiceWithGemini } from './services/geminiService';
import { generateBarcodePDF } from './services/pdfGenerator';

const App: React.FC = () => {
  const [file, setFile] = useState<File | null>(null);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const [currentStep, setCurrentStep] = useState<ProcessingStep>(ProcessingStep.IDLE);
  const [result, setResult] = useState<ProcessingResult | null>(null);
  const [detectedCodes, setDetectedCodes] = useState<DetectedCode[]>([]);
  const [pdfBlob, setPdfBlob] = useState<Blob | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleFileSelect = (selectedFile: File) => {
    setFile(selectedFile);
    setPreviewUrl(URL.createObjectURL(selectedFile));
    setResult(null);
    setDetectedCodes([]);
    setPdfBlob(null);
    setError(null);
    setCurrentStep(ProcessingStep.IDLE);
  };

  const handleReset = () => {
    setFile(null);
    setPreviewUrl(null);
    setResult(null);
    setDetectedCodes([]);
    setPdfBlob(null);
    setError(null);
    setCurrentStep(ProcessingStep.IDLE);
  };

  const handleSubmit = async () => {
    if (!file) return;

    try {
      setError(null);

      // Step 1: Scanning Barcode Locally
      setCurrentStep(ProcessingStep.SCANING_BARCODES);
      const codes = await scanBarcodes(file);
      setDetectedCodes(codes);

      // Step 2 & 3: Understanding Invoice & Generating EDI via Gemini
      setCurrentStep(ProcessingStep.UNDERSTANDING_INVOICE);
      const geminiResult = await processInvoiceWithGemini(file);
      setResult(geminiResult);

      // Step 4: Generating Barcode PDF if needed
      if (codes.length > 0) {
        setCurrentStep(ProcessingStep.GENERATING_PDF);
        const pdf = await generateBarcodePDF(codes);
        setPdfBlob(pdf);
      }

      setCurrentStep(ProcessingStep.COMPLETED);
    } catch (err: any) {
      console.error(err);
      setError(err.message || 'An unexpected error occurred processing the invoice.');
      setCurrentStep(ProcessingStep.ERROR);
    }
  };

  return (
    <div className="min-h-screen flex flex-col">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-10">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center space-x-3">
            <div className="bg-indigo-600 p-2 rounded-lg">
              <FileDigit className="text-white w-6 h-6" />
            </div>
            <div>
              <h1 className="text-xl font-bold text-slate-900 tracking-tight">Invoice → EDI + Barcode</h1>
              <p className="text-xs text-slate-500 font-medium">X12 810 Automation & Logistics Labelling</p>
            </div>
          </div>
          <div className="flex items-center space-x-4">
            {result && (
              <ValidationBadge 
                needsReview={result.needs_review} 
                missingCount={result.missing_fields.length}
              />
            )}
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 max-w-7xl mx-auto w-full px-4 sm:px-6 lg:px-8 py-8">
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 items-start">

          {/* Left Panel: Upload & Preview */}
          <div className="lg:col-span-5 space-y-6">
            <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
              <div className="p-6">
                <h2 className="text-lg font-semibold text-slate-900 mb-4 flex items-center">
                  <Upload className="w-5 h-5 mr-2 text-indigo-500" />
                  Invoice Upload
                </h2>

                {!file ? (
                  <FileUploader onFileSelect={handleFileSelect} />
                ) : (
                  <div className="space-y-4">
                    <div className="relative group rounded-xl overflow-hidden border border-slate-200 bg-slate-50 aspect-[3/4] flex items-center justify-center">
                      <img 
                        src={previewUrl!} 
                        alt="Invoice Preview" 
                        className="max-w-full max-h-full object-contain"
                      />
                      <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                        <button 
                          onClick={handleReset}
                          className="bg-white text-slate-900 px-4 py-2 rounded-lg font-medium shadow-lg hover:bg-slate-50 flex items-center"
                        >
                          <RefreshCcw className="w-4 h-4 mr-2" />
                          Replace
                        </button>
                      </div>
                    </div>
                    <div className="flex items-center justify-between text-sm">
                      <span className="text-slate-500 truncate max-w-[200px]">{file.name}</span>
                      <span className="text-slate-400">{(file.size / 1024).toFixed(1)} KB</span>
                    </div>

                    {currentStep === ProcessingStep.IDLE && (
                      <button
                        onClick={handleSubmit}
                        className="w-full bg-indigo-600 hover:bg-indigo-700 text-white font-bold py-3 px-6 rounded-xl shadow-lg shadow-indigo-200 transition-all flex items-center justify-center group"
                      >
                        Process Invoice
                        <ArrowRight className="ml-2 w-5 h-5 group-hover:translate-x-1 transition-transform" />
                      </button>
                    )}
                  </div>
                )}
              </div>
            </div>

            {/* Step Progress Display */}
            {(currentStep !== ProcessingStep.IDLE) && (
              <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6">
                <h3 className="text-sm font-semibold text-slate-900 mb-4 uppercase tracking-wider">Processing Timeline</h3>
                <StepProgress currentStep={currentStep} error={error} />
              </div>
            )}
          </div>

          {/* Right Panel: Results */}
          <div className="lg:col-span-7 space-y-6">
            {result ? (
              <ResultsPanel 
                result={result} 
                detectedCodes={detectedCodes}
                pdfBlob={pdfBlob}
              />
            ) : (
              <div className="bg-white rounded-2xl border-2 border-dashed border-slate-200 p-12 text-center flex flex-col items-center justify-center min-h-[400px]">
                <div className="bg-slate-50 p-4 rounded-full mb-4">
                  <BarChart3 className="w-12 h-12 text-slate-300" />
                </div>
                <h3 className="text-lg font-medium text-slate-900">Analysis Results</h3>
                <p className="text-slate-500 max-w-sm mt-2">
                  Process an invoice to view generated EDI data, validation reports, and barcode label sheets.
                </p>
              </div>
            )}
          </div>
        </div>
      </main>

      <footer className="bg-white border-t border-slate-200 py-6">
        <div className="max-w-7xl mx-auto px-4 text-center text-sm text-slate-400">
          Built with Gemini AI & Local Barcode Scanning Technology
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useRef, useState } from 'react';
import { Upload, Image as ImageIcon } from 'lucide-react';

interface FileUploaderProps {
  onFileSelect: (file: File) => void;
}

export const FileUploader: React.FC<FileUploaderProps> = ({ onFileSelect }) => {
  const [isDragging, setIsDragging] = useState(false);
  const inputRef = useRef<HTMLInputElement>(null);

  const handleDrag = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === 'dragenter' || e.type === 'dragover') {
      setIsDragging(true);
    } else if (e.type === 'dragleave') {
      setIsDragging(false);
    }
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDragging(false);
    if (e.dataTransfer.files && e.dataTransfer.files[0]) {
      onFileSelect(e.dataTransfer.files[0]);
    }
  };

  return (
    <div
      onDragEnter={handleDrag}
      onDragLeave={handleDrag}
      onDragOver={handleDrag}
      onDrop={handleDrop}
      className={`
        relative border-2 border-dashed rounded-xl p-12 transition-all cursor-pointer text-center
        ${isDragging ? 'border-indigo-500 bg-indigo-50' : 'border-slate-300 hover:border-slate-400 bg-slate-50'}
      `}
      onClick={() => inputRef.current?.click()}
    >
      <input
        ref={inputRef}
        type="file"
        className="hidden"
        accept="image/png, image/jpeg"
        onChange={(e) => e.target.files?.[0] && onFileSelect(e.target.files[0])}
      />
      <div className="flex flex-col items-center">
        <div className="bg-white p-4 rounded-2xl shadow-sm mb-4">
          <Upload className="w-8 h-8 text-indigo-600" />
        </div>
        <p className="text-slate-900 font-semibold mb-1">Click to upload or drag and drop</p>
        <p className="text-slate-500 text-sm">SVG, PNG, JPG (MAX. 800x400px)</p>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { ProcessingResult, DetectedCode } from '../types';
import { 
  FileText, 
  Grid, 
  Clipboard, 
  Download, 
  AlertTriangle, 
  CheckCircle2, 
  Info,
  XCircle
} from 'lucide-react';

interface ResultsPanelProps {
  result: ProcessingResult;
  detectedCodes: DetectedCode[];
  pdfBlob: Blob | null;
}

export const ResultsPanel: React.FC<ResultsPanelProps> = ({ result, detectedCodes, pdfBlob }) => {
  const [activeTab, setActiveTab] = useState<'edi' | 'barcodes' | 'validation'>('edi');

  const copyToClipboard = () => {
    navigator.clipboard.writeText(result.edi_810);
    alert('EDI 810 text copied to clipboard!');
  };

  const downloadEdi = () => {
    const blob = new Blob([result.edi_810], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `invoice_${result.invoice.invoice_number || 'export'}.edi`;
    a.click();
  };

  const downloadPdf = () => {
    if (!pdfBlob) return;
    const url = URL.createObjectURL(pdfBlob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `barcodes_${result.invoice.invoice_number || 'labels'}.pdf`;
    a.click();
  };

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-slate-200 flex flex-col h-[700px]">
      {/* Tabs */}
      <div className="flex border-b border-slate-200 px-4 pt-4">
        <button
          onClick={() => setActiveTab('edi')}
          className={`flex items-center px-4 py-2 text-sm font-medium border-b-2 transition-colors ${
            activeTab === 'edi' ? 'border-indigo-600 text-indigo-600' : 'border-transparent text-slate-500 hover:text-slate-700'
          }`}
        >
          <FileText className="w-4 h-4 mr-2" />
          EDI Preview
        </button>
        <button
          onClick={() => setActiveTab('barcodes')}
          className={`flex items-center px-4 py-2 text-sm font-medium border-b-2 transition-colors ${
            activeTab === 'barcodes' ? 'border-indigo-600 text-indigo-600' : 'border-transparent text-slate-500 hover:text-slate-700'
          }`}
        >
          <Grid className="w-4 h-4 mr-2" />
          Barcode Sheet
          {detectedCodes.length > 0 && (
            <span className="ml-2 px-2 py-0.5 bg-indigo-100 text-indigo-700 rounded-full text-[10px]">
              {detectedCodes.length}
            </span>
          )}
        </button>
        <button
          onClick={() => setActiveTab('validation')}
          className={`flex items-center px-4 py-2 text-sm font-medium border-b-2 transition-colors ${
            activeTab === 'validation' ? 'border-indigo-600 text-indigo-600' : 'border-transparent text-slate-500 hover:text-slate-700'
          }`}
        >
          <AlertTriangle className="w-4 h-4 mr-2" />
          Validation
        </button>
      </div>

      {/* Tab Content */}
      <div className="flex-1 overflow-hidden p-6">
        {activeTab === 'edi' && (
          <div className="h-full flex flex-col space-y-4">
            <div className="flex items-center justify-between">
              <h3 className="text-sm font-semibold text-slate-900 flex items-center">
                X12 810 INVOICE Transaction Set
              </h3>
              <div className="flex space-x-2">
                <button 
                  onClick={copyToClipboard}
                  className="flex items-center px-3 py-1.5 text-xs font-medium bg-slate-100 text-slate-700 rounded-lg hover:bg-slate-200"
                >
                  <Clipboard className="w-3.5 h-3.5 mr-1.5" />
                  Copy
                </button>
                <button 
                  onClick={downloadEdi}
                  className="flex items-center px-3 py-1.5 text-xs font-medium bg-indigo-600 text-white rounded-lg hover:bg-indigo-700"
                >
                  <Download className="w-3.5 h-3.5 mr-1.5" />
                  Download .edi
                </button>
              </div>
            </div>
            <div className="flex-1 bg-slate-900 rounded-xl p-4 overflow-auto scrollbar-thin scrollbar-thumb-slate-700">
              <pre className="mono text-indigo-300 text-sm whitespace-pre-wrap leading-relaxed">
                {result.edi_810}
              </pre>
            </div>
          </div>
        )}

        {activeTab === 'barcodes' && (
          <div className="h-full flex flex-col space-y-4">
            <div className="flex items-center justify-between">
              <h3 className="text-sm font-semibold text-slate-900">Detected Logistic Codes</h3>
              {detectedCodes.length > 0 && (
                <button 
                  onClick={downloadPdf}
                  className="flex items-center px-3 py-1.5 text-xs font-medium bg-indigo-600 text-white rounded-lg hover:bg-indigo-700"
                >
