import Tesseract from 'tesseract.js';
import { DetectedCode } from '../types';

export const performOCR = async (file: File): Promise<{ text: string; codes: DetectedCode[] }> => {
  const { data: { text } } = await Tesseract.recognize(file, 'eng', {
    logger: m => console.debug(m)
  });

  const codes: DetectedCode[] = [];

  // Regex patterns
  // UPC-A: 12 digits
  const upcA = /\b\d{12}\b/g;
  // EAN-13: 13 digits
  const ean13 = /\b\d{13}\b/g;
  // UCI: specific label or 10-20 digit near UCI
  const uciLabel = /UCI\s*:?\s*([A-Z0-9]{10,20})/gi;
  const uciFallback = /\b\d{10,20}\b/g; // Very loose, we'll verify if 'UCI' is nearby in text

  // Extract UPC
  const upcMatches = text.match(upcA) || [];
  upcMatches.forEach(val => codes.push({ type: 'UPC-A', value: val }));

  // Extract EAN
  const eanMatches = text.match(ean13) || [];
  eanMatches.forEach(val => codes.push({ type: 'EAN-13', value: val }));

  // Extract UCI from label
  let match;
  while ((match = uciLabel.exec(text)) !== null) {
    codes.push({ type: 'UCI', value: match[1] });
  }

  // Deduplicate
  const uniqueCodes = Array.from(new Set(codes.map(c => `${c.type}:${c.value}`)))
    .map(key => {
      const [type, value] = key.split(':');
      return { type, value } as DetectedCode;
    });

  return { text, codes: uniqueCodes };
};

import { GoogleGenAI, Type } from "@google/genai";
import { ProcessingResult, DetectedCode } from "../types";

export const processInvoiceWithGemini = async (
  file: File, 
  ocrText: string, 
  preExtractedCodes: DetectedCode[]
): Promise<ProcessingResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const base64Data = await fileToBase64(file);

  const systemInstruction = `
    You are an expert EDI specialist and invoice processing agent.

    STRICT JSON OUTPUT ONLY. DO NOT INCLUDE ANY MARKDOWN CODE BLOCKS OR EXTRA TEXT.

    TASK:
    1. Analyze the invoice image and provided OCR text.
    2. Extract data into the JSON structure.
    3. Generate a complete X12 810 EDI transaction set (ST..SE) based ONLY on visible facts.

    SOURCE DATA:
    - Image: Primary source.
    - OCR Text: Helper source for reading digits.
    - Pre-extracted Codes: List of UPC/UCI detected.

    NON-HALLUCINATION RULES:
    - Use ONLY what is visible.
    - DO NOT infer/invent vendor/buyer addresses, dates, or totals.
    - If not found, leave blank/null and add to 'missing_fields'.
    - Seller/Supplier: Printed at top/header.
    - Buyer: Customer/Account block.

    EDI RULES:
    - ST*810*0001~
    - BIG*<yyyymmdd>*<invoice_number>~
    - N1*SU*<name>~, N3*<addr>~, N4*<city>*<st>*<zip>~
    - N1*BY*<name>~, N3*<addr>~, N4*<city>*<st>*<zip>~
    - IT1 loops: IT1*<line_no>*<qty>*<uom>*<price>**UP*<upc>~
    - PID*F****<desc>~
    - TDS*<total_cents>~
    - CTT*<line_count>~
    - SE*<seg_count>*0001~
    - Use '*' as separator, '~' as segment terminator.

    VALIDATION:
    - Set 'needs_review': true if invoice_number, date, or total are missing.
    - Add warnings for mismatches.
  `;

  const prompt = `
    Analyze this invoice. 
    OCR Text: ${ocrText}
    Detected UPC/UCI codes: ${JSON.stringify(preExtractedCodes)}
    Generate the JSON with EDI.
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { inlineData: { mimeType: file.type, data: base64Data } },
        { text: prompt }
      ]
    },
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          invoice: {
            type: Type.OBJECT,
            properties: {
              invoice_number: { type: Type.STRING },
              invoice_date: { type: Type.STRING },
              seller: {
                type: Type.OBJECT,
                properties: { 
                  name: { type: Type.STRING }, address: { type: Type.STRING }, 
                  city: { type: Type.STRING }, state: { type: Type.STRING }, zip: { type: Type.STRING },
                  tax_id: { type: Type.STRING } 
                }
              },
              buyer: {
                type: Type.OBJECT,
                properties: { 
                  name: { type: Type.STRING }, address: { type: Type.STRING }, 
                  city: { type: Type.STRING }, state: { type: Type.STRING }, zip: { type: Type.STRING },
                  tax_id: { type: Type.STRING } 
                }
              },
              po_number: { type: Type.STRING },
              currency: { type: Type.STRING },
              totals: {
                type: Type.OBJECT,
                properties: { 
                  subtotal: { type: Type.NUMBER }, tax: { type: Type.NUMBER }, 
                  total: { type: Type.NUMBER }, discount: { type: Type.NUMBER } 
                }
              },
              line_items: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    line_no: { type: Type.NUMBER },
                    description: { type: Type.STRING },
                    qty: { type: Type.NUMBER },
                    uom: { type: Type.STRING },
                    unit_price: { type: Type.NUMBER },
                    line_total: { type: Type.NUMBER },
                    upc: { type: Type.STRING }
                  }
                }
              }
            }
          },
          edi_810: { type: Type.STRING },
          missing_fields: { type: Type.ARRAY, items: { type: Type.STRING } },
          warnings: { type: Type.ARRAY, items: { type: Type.STRING } },
          needs_review: { type: Type.BOOLEAN },
          detected_codes: {
             type: Type.ARRAY,
             items: {
               type: Type.OBJECT,
               properties: {
                 type: { type: Type.STRING },
                 value: { type: Type.STRING }
               }
             }
          }
        },
        required: ["invoice", "edi_810", "missing_fields", "warnings", "needs_review", "detected_codes"]
      }
    }
  });

  try {
    const text = response.text || '';
    return JSON.parse(text.trim()) as ProcessingResult;
  } catch (err) {
    throw new Error("Failed to parse Gemini response as valid JSON.");
  }
};

const fileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => resolve((reader.result as string).split(',')[1]);
    reader.onerror = (error) => reject(error);
  });
};

import { jsPDF } from 'jspdf';
import JsBarcode from 'jsbarcode';
import QRCode from 'qrcode';
import { DetectedCode } from '../types';

export const generateBarcodePDF = async (codes: DetectedCode[]): Promise<Blob> => {
  const doc = new jsPDF({
    orientation: 'p',
    unit: 'mm',
    format: 'a4'
  });

  const margin = 10;
  const colWidth = 60;
  const rowHeight = 45;
  const cols = 3;

  doc.setFont('helvetica', 'bold');
  doc.setFontSize(14);
  doc.text('Logistic Label Sheet', margin, margin);
  doc.line(margin, margin + 2, 200, margin + 2);

  let currentX = margin;
  let currentY = margin + 10;

  for (let i = 0; i < codes.length; i++) {
    const code = codes[i];

    // Label Box
    doc.setDrawColor(220);
    doc.setLineWidth(0.1);
    doc.rect(currentX, currentY, colWidth - 2, rowHeight - 2);

    // Type Label
    doc.setFontSize(6);
    doc.setTextColor(100);
    doc.setFont('helvetica', 'bold');
    doc.text(code.type.toUpperCase(), currentX + 3, currentY + 6);

    try {
      if (code.type === 'QR') {
        const qrDataUrl = await QRCode.toDataURL(code.value, { margin: 1 });
        doc.addImage(qrDataUrl, 'PNG', currentX + (colWidth/2) - 10, currentY + 8, 20, 20);
      } else {
        // Render 1D barcode to canvas
        const canvas = document.createElement('canvas');
        let format: string = 'CODE128';
        if (code.type === 'UPC-A') format = 'UPC';
        if (code.type === 'EAN-13') format = 'EAN13';

        JsBarcode(canvas, code.value, {
          format,
          displayValue: false,
          margin: 0,
          width: 2,
          height: 40
        });
        const barcodeDataUrl = canvas.toDataURL('image/png');
        doc.addImage(barcodeDataUrl, 'PNG', currentX + 5, currentY + 10, colWidth - 12, 18);
      }
    } catch (err) {
      console.warn('Barcode rendering failed for', code.value, err);
      doc.setFontSize(8);
      doc.setTextColor(200, 0, 0);
      doc.text('[RENDER ERROR]', currentX + 5, currentY + 15);
    }

    // Human Readable Value
    doc.setFontSize(8);
    doc.setTextColor(0);
    doc.setFont('helvetica', 'normal');
    const displayVal = code.value.length > 20 ? code.value.substring(0, 18) + '...' : code.value;
    doc.text(displayVal, currentX + (colWidth/2) - (doc.getTextWidth(displayVal)/2), currentY + rowHeight - 6);

    // Grid Management
    if ((i + 1) % cols === 0) {
      currentX = margin;
      currentY += rowHeight;
    } else {
      currentX += colWidth;
    }

    if (currentY + rowHeight > 280) {
      doc.addPage();
      currentX = margin;
      currentY = margin + 10;
    }
  }

  return doc.output('blob');
};

import React, { useState } from 'react';
