import React from 'react';
import { ProcessingStep } from '../types';
import { CheckCircle2, Circle, Loader2, XCircle } from 'lucide-react';

interface StepProgressProps {
  currentStep: ProcessingStep;
  error: string | null;
}

export const StepProgress: React.FC<StepProgressProps> = ({ currentStep, error }) => {
  const steps = [
    // Fix: Using RUNNING_OCR instead of the non-existent SCANNING_BARCODES
    { id: ProcessingStep.RUNNING_OCR, label: 'Barcode Scan' },
    { id: ProcessingStep.UNDERSTANDING_INVOICE, label: 'AI Extraction' },
    { id: ProcessingStep.GENERATING_EDI, label: 'EDI Generation' },
    { id: ProcessingStep.GENERATING_PDF, label: 'Barcode Sheet' }
  ];

  const getStepStatus = (stepId: string) => {
    if (error && currentStep === stepId) return 'error';
    if (currentStep === ProcessingStep.COMPLETED) return 'completed';

    const stepOrder = Object.values(ProcessingStep);
    const currentIndex = stepOrder.indexOf(currentStep);
    const stepIndex = stepOrder.indexOf(stepId as ProcessingStep);

    if (currentIndex > stepIndex) return 'completed';
    if (currentIndex === stepIndex) return 'active';
    return 'pending';
  };

  return (
    <div className="space-y-4">
      {steps.map((step, index) => {
        const status = getStepStatus(step.id);

        return (
          <div key={index} className="flex items-center space-x-3">
            <div className="relative">
              {status === 'completed' && <CheckCircle2 className="w-5 h-5 text-green-500" />}
              {status === 'active' && <Loader2 className="w-5 h-5 text-indigo-600 animate-spin" />}
              {status === 'pending' && <Circle className="w-5 h-5 text-slate-200" />}
              {status === 'error' && <XCircle className="w-5 h-5 text-red-500" />}
            </div>
            <span className={`text-sm font-medium ${
              status === 'active' ? 'text-indigo-600' : 
              status === 'completed' ? 'text-slate-900' : 'text-slate-400'
            }`}>
              {step.label}
            </span>
          </div>
        );
      })}

      {error && (
        <div className="mt-4 p-3 bg-red-50 border border-red-100 rounded-lg text-red-600 text-xs">
          <strong>Process Failed:</strong> {error}
        </div>
      )}
    </div>
  );
};

import { BrowserMultiFormatReader } from '@zxing/library';
import { DetectedCode } from '../types';

export const scanBarcodes = async (file: File): Promise<DetectedCode[]> => {
  const reader = new BrowserMultiFormatReader();
  const imageUrl = URL.createObjectURL(file);

  try {
    // Attempt multiple decodes or common results
    // NOTE: ZXing's browser reader usually expects a video element or canvas, 
    // but can handle static image elements.
    const img = new Image();
    img.src = imageUrl;

    await new Promise((resolve) => {
      img.onload = resolve;
    });

    const canvas = document.createElement('canvas');
    canvas.width = img.width;
    canvas.height = img.height;
    const ctx = canvas.getContext('2d');
    if (!ctx) throw new Error('Could not get canvas context');
    ctx.drawImage(img, 0, 0);

    const results: DetectedCode[] = [];

    try {
      // Decode the whole image
      const decodeResult = await reader.decodeFromImageElement(img);
      if (decodeResult) {
        results.push({
          // Force cast as we handle valid types later in the logic
          type: decodeResult.getBarcodeFormat().toString() as any,
          value: decodeResult.getText()
        });
      }
    } catch (e) {
      console.debug("Single decode failed, proceeding with logic...");
    }

    // Heuristic: Check for UCI (Uniquely Code Identifier) patterns in decoded results
    // E.g., [UCI:123456789]
    results.forEach(res => {
      if (res.value.match(/^[A-Z0-9]{12,20}$/)) {
        // Potential UCI match
        // Fix: Changed 'UCI / Serial' to 'UCI' to match the DetectedCode type
        res.type = 'UCI';
      }
    });

    return results;
  } catch (error) {
    console.error("Barcode scan failed:", error);
    return []; // Return empty instead of crashing as per requirements
  } finally {
    URL.revokeObjectURL(imageUrl);
  }
};

