import { jsPDF } from 'jspdf';
import JsBarcode from 'jsbarcode';
import QRCode from 'qrcode';
import { DetectedCode } from '../types';

export const generateBarcodePDF = async (codes: DetectedCode[]): Promise<Blob> => {
  const doc = new jsPDF({
    orientation: 'p',
    unit: 'mm',
    format: 'a4'
  });

  const margin = 10;
  const colWidth = 64; // Slightly wider for dates
  const rowHeight = 48; // Taller for the retail tag layout
  const cols = 3;

  doc.setFont('helvetica', 'bold');
  doc.setFontSize(14);
  doc.text('Retail Tag Label Sheet', margin, margin);
  doc.line(margin, margin + 2, 200, margin + 2);

  let currentX = margin;
  let currentY = margin + 10;

  for (let i = 0; i < codes.length; i++) {
    const code = codes[i];

    // Label Boundary Box (Subtle)
    doc.setDrawColor(230);
    doc.setLineWidth(0.1);
    doc.rect(currentX, currentY, colWidth - 2, rowHeight - 2);

    // --- Vertical Dates (Sides) ---
    doc.setFontSize(7);
    doc.setTextColor(100);
    doc.setFont('helvetica', 'normal');

    const dLeft = code.dateLeft || '09/04/2025';
    const dRight = code.dateRight || '09/08/2025';

    // Left Date (Rotated)
    doc.text(dLeft, currentX + 4, currentY + (rowHeight / 2) + 10, { angle: 90 });
    // Right Date (Rotated)
    doc.text(dRight, currentX + colWidth - 4, currentY + (rowHeight / 2) + 10, { angle: 90 });

    // --- Price Header ---
    if (code.price !== undefined) {
      doc.setFontSize(22);
      doc.setTextColor(0);
      doc.setFont('helvetica', 'bold');
      const priceText = `$${code.price.toFixed(2)}`;
      doc.text(priceText, currentX + (colWidth / 2), currentY + 10, { align: 'center' });

      // "each" label
      doc.setFontSize(7);
      doc.setFont('helvetica', 'normal');
      doc.text(code.unit || 'each', currentX + (colWidth / 2) + (doc.getTextWidth(priceText) / 2) + 2, currentY + 7);
    }

    // --- Description ---
    doc.setFontSize(9);
    doc.setTextColor(0);
    doc.setFont('helvetica', 'bold');
    const desc = (code.description || 'ITEM DESCRIPTION').toUpperCase();
    const truncatedDesc = desc.length > 25 ? desc.substring(0, 22) + '...' : desc;
    doc.text(truncatedDesc, currentX + (colWidth / 2), currentY + 16, { align: 'center' });

    // --- Barcode ---
    try {
      if (code.type === 'QR') {
        const qrDataUrl = await QRCode.toDataURL(code.value, { margin: 1 });
        doc.addImage(qrDataUrl, 'PNG', currentX + (colWidth/2) - 10, currentY + 18, 20, 20);
      } else {
        const canvas = document.createElement('canvas');
        let format: string = 'CODE128';
        if (code.type === 'UPC-A') format = 'UPC';
        if (code.type === 'EAN-13') format = 'EAN13';

        JsBarcode(canvas, code.value, {
          format,
          displayValue: false,
          margin: 0,
          width: 3,
          height: 50
        });
        const barcodeDataUrl = canvas.toDataURL('image/png');
        // Center the barcode relative to the side dates
        doc.addImage(barcodeDataUrl, 'PNG', currentX + 8, currentY + 20, colWidth - 18, 18);
      }
    } catch (err) {
      doc.setFontSize(8);
      doc.setTextColor(200, 0, 0);
      doc.text('[BARCODE ERROR]', currentX + (colWidth/2), currentY + 28, { align: 'center' });
    }

    // --- Human Readable Value (Grouped format like image) ---
    doc.setFontSize(9);
    doc.setTextColor(0);
    doc.setFont('helvetica', 'normal');

    let displayVal = code.value;
    if (code.type === 'UPC-A' && displayVal.length === 12) {
      // Format 8 18094 00587 6 style
      displayVal = `${displayVal[0]}   ${displayVal.substring(1, 6)}   ${displayVal.substring(6, 11)}   ${displayVal[11]}`;
    }

    doc.text(displayVal, currentX + (colWidth/2), currentY + rowHeight - 6, { align: 'center' });

    // --- Grid Management ---
    if ((i + 1) % cols === 0) {
      currentX = margin;
      currentY += rowHeight;
    } else {
      currentX += colWidth;
    }

    if (currentY + rowHeight > 280) {
      doc.addPage();
      currentX = margin;
      currentY = margin + 10;
    }
  }

  return doc.output('blob');
};

import React, { useState } from 'react';
import { 
  FileText, 
  BarChart3, 
  Upload, 
  RefreshCcw, 
  ArrowRight,
  FileDigit,
  Info
} from 'lucide-react';
import { FileUploader } from './components/FileUploader';
import { ResultsPanel } from './components/ResultsPanel';
import { StepProgress } from './components/StepProgress';
import { ValidationBadge } from './components/ValidationBadge';
import { ProcessingStep, ProcessingResult, DetectedCode } from './types';
import { performOCR } from './services/ocrService';
import { processInvoiceWithGemini } from './services/geminiService';
import { generateBarcodePDF } from './services/pdfGenerator';

const App: React.FC = () => {
  const [file, setFile] = useState<File | null>(null);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const [currentStep, setCurrentStep] = useState<ProcessingStep>(ProcessingStep.IDLE);
  const [result, setResult] = useState<ProcessingResult | null>(null);
  const [pdfBlob, setPdfBlob] = useState<Blob | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleFileSelect = (selectedFile: File) => {
    setFile(selectedFile);
    setPreviewUrl(URL.createObjectURL(selectedFile));
    setResult(null);
    setPdfBlob(null);
    setError(null);
    setCurrentStep(ProcessingStep.IDLE);
  };

  const handleReset = () => {
    setFile(null);
    setPreviewUrl(null);
    setResult(null);
    setPdfBlob(null);
    setError(null);
    setCurrentStep(ProcessingStep.IDLE);
  };

  const handleSubmit = async () => {
    if (!file) return;

    try {
      setError(null);

      // Step 1: Running OCR
      setCurrentStep(ProcessingStep.RUNNING_OCR);
      const { text: ocrText, codes: ocrCodes } = await performOCR(file);

      // Step 2 & 3: Understanding Invoice & Generating EDI
      setCurrentStep(ProcessingStep.UNDERSTANDING_INVOICE);
      const geminiResult = await processInvoiceWithGemini(file, ocrText, ocrCodes);
      setResult(geminiResult);

      // Step 4: Generating Barcode PDF
      // We prioritize generating labels from AI-extracted line items because they have descriptions and prices.
      const labelsToGenerate: DetectedCode[] = [];

      const today = new Date();
      const nextWeek = new Date(today.getTime() + 7 * 24 * 60 * 60 * 1000);
      const formatDate = (d: Date) => d.toLocaleDateString('en-US', { month: '2-digit', day: '2-digit', year: 'numeric' });

      if (geminiResult.invoice.line_items.length > 0) {
        geminiResult.invoice.line_items.forEach(item => {
          if (item.upc && item.upc.trim().length >= 10) {
            labelsToGenerate.push({
              type: item.upc.length === 12 ? 'UPC-A' : (item.upc.length === 13 ? 'EAN-13' : 'CODE128'),
              value: item.upc,
              description: item.description,
              price: item.unit_price || 0,
              unit: item.uom || 'each',
              dateLeft: formatDate(today),
              dateRight: formatDate(nextWeek)
            });
          }
        });
      }

      // If no line item codes were found, use the raw OCR detected codes as a fallback
      if (labelsToGenerate.length === 0 && ocrCodes.length > 0) {
        ocrCodes.forEach(code => {
          labelsToGenerate.push({
            ...code,
            dateLeft: formatDate(today),
            dateRight: formatDate(nextWeek)
          });
        });
      }

      if (labelsToGenerate.length > 0) {
        setCurrentStep(ProcessingStep.GENERATING_PDF);
        const pdf = await generateBarcodePDF(labelsToGenerate);
        setPdfBlob(pdf);
      }

      setCurrentStep(ProcessingStep.COMPLETED);
    } catch (err: any) {
      console.error(err);
      setError(err.message || 'An error occurred during invoice processing.');
      setCurrentStep(ProcessingStep.ERROR);
    }
  };

  return (
    <div className="min-h-screen flex flex-col bg-slate-50 text-slate-900">
      <header className="bg-white border-b border-slate-200 sticky top-0 z-20 backdrop-blur-md bg-white/80">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center space-x-3">
            <div className="bg-indigo-600 p-2 rounded-xl shadow-lg shadow-indigo-100">
              <FileDigit className="text-white w-6 h-6" />
            </div>
            <div>
              <h1 className="text-lg font-bold tracking-tight text-slate-900 leading-none">Invoice Automation</h1>
              <p className="text-[10px] text-slate-500 font-semibold uppercase tracking-wider mt-1">Retail Tag & EDI Engine</p>
            </div>
          </div>
          <div className="flex items-center space-x-4">
            {result && (
              <ValidationBadge 
                needsReview={result.needs_review} 
                missingCount={result.missing_fields.length}
              />
            )}
          </div>
        </div>
      </header>

      <main className="flex-1 max-w-7xl mx-auto w-full px-4 sm:px-6 lg:px-8 py-8">
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 items-start">
          <div className="lg:col-span-5 space-y-6">
            <div className="bg-white rounded-3xl shadow-sm border border-slate-200 overflow-hidden">
              <div className="p-8">
                <div className="flex items-center justify-between mb-6">
                  <h2 className="text-xl font-bold text-slate-900">Source Invoice</h2>
                  {file && (
                    <button onClick={handleReset} className="text-slate-400 hover:text-red-500 transition-colors">
                      <RefreshCcw className="w-5 h-5" />
                    </button>
                  )}
                </div>

                {!file ? (
                  <FileUploader onFileSelect={handleFileSelect} />
                ) : (
                  <div className="space-y-6">
                    <div className="relative group rounded-2xl overflow-hidden border border-slate-200 bg-white shadow-inner aspect-[3/4] flex items-center justify-center">
                      <img 
                        src={previewUrl!} 
                        alt="Invoice Preview" 
                        className="max-w-full max-h-full object-contain p-2"
                      />
                    </div>

                    <div className="p-4 bg-slate-50 rounded-2xl border border-slate-200 flex items-center justify-between text-sm">
                      <div className="flex items-center space-x-3">
                        <div className="bg-white p-2 rounded-lg border border-slate-200">
                          <FileText className="w-4 h-4 text-slate-400" />
                        </div>
                        <span className="text-slate-700 font-medium truncate max-w-[150px]">{file.name}</span>
                      </div>
                      <span className="text-slate-400 font-mono text-xs">{(file.size / 1024).toFixed(1)} KB</span>
                    </div>

                    {currentStep === ProcessingStep.IDLE && (
                      <button
                        onClick={handleSubmit}
                        className="w-full bg-indigo-600 hover:bg-indigo-700 active:scale-[0.98] text-white font-bold py-4 px-6 rounded-2xl shadow-xl shadow-indigo-100 transition-all flex items-center justify-center group"
                      >
                        Start Processing
                        <ArrowRight className="ml-2 w-5 h-5 group-hover:translate-x-1 transition-transform" />
                      </button>
                    )}
                  </div>
                )}
              </div>
            </div>

            {(currentStep !== ProcessingStep.IDLE) && (
              <div className="bg-white rounded-3xl shadow-sm border border-slate-200 p-8">
                <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-6">Processing Status</h3>
                <StepProgress currentStep={currentStep} error={error} />
              </div>
            )}
          </div>

          <div className="lg:col-span-7 h-full">
            {result ? (
              <ResultsPanel 
                result={result} 
                pdfBlob={pdfBlob}
              />
            ) : (
              <div className="bg-white rounded-3xl border-2 border-dashed border-slate-200 p-12 text-center flex flex-col items-center justify-center min-h-[500px]">
                <div className="bg-indigo-50 p-6 rounded-3xl mb-6">
                  <BarChart3 className="w-16 h-16 text-indigo-400" />
