                <div className="mt-8 grid grid-cols-2 gap-4 w-full max-w-md">
                   <div className="p-4 bg-slate-50 rounded-2xl text-left border border-slate-100">
                      <div className="w-8 h-8 bg-white rounded-lg flex items-center justify-center border border-slate-200 mb-3">
                         <Info className="w-4 h-4 text-indigo-500" />
                      </div>
                      <p className="text-xs font-bold text-slate-900 uppercase tracking-tight mb-1">Retail Tags</p>
                      <p className="text-[10px] text-slate-500">Generate tags with price, description, and dates.</p>
                   </div>
                   <div className="p-4 bg-slate-50 rounded-2xl text-left border border-slate-100">
                      <div className="w-8 h-8 bg-white rounded-lg flex items-center justify-center border border-slate-200 mb-3">
                         <FileText className="w-4 h-4 text-indigo-500" />
