import { CodeValidationResult } from '../types';

export const validateUPC = (code: string): boolean => {
  const clean = code.replace(/\s+/g, '');
  if (clean.length !== 12) return false;
  if (!/^\d+$/.test(clean)) return false;

  let sum = 0;
  for (let i = 0; i < 11; i++) {
    sum += parseInt(clean[i]) * (i % 2 === 0 ? 3 : 1);
  }
  const checkDigit = (10 - (sum % 10)) % 10;
  return checkDigit === parseInt(clean[11]);
};

export const validateEAN = (code: string): boolean => {
  const clean = code.replace(/\s+/g, '');
  if (clean.length !== 13) return false;
  if (!/^\d+$/.test(clean)) return false;

  let sum = 0;
  for (let i = 0; i < 12; i++) {
    sum += parseInt(clean[i]) * (i % 2 === 0 ? 1 : 3);
  }
  const checkDigit = (10 - (sum % 10)) % 10;
  return checkDigit === parseInt(clean[12]);
};

export const validateCode = (value: string): CodeValidationResult => {
  const clean = value.replace(/\s+/g, '');

  if (clean.length === 12 && /^\d+$/.test(clean)) {
    return { value: clean, type: 'UPC-A', isValid: validateUPC(clean) };
  }

  if (clean.length === 13 && /^\d+$/.test(clean)) {
    return { value: clean, type: 'EAN-13', isValid: validateEAN(clean) };
  }

  if (clean.length >= 10 && clean.length <= 20) {
    return { value: clean, type: 'UCI', isValid: true }; // UCI is usually alphanumeric, flexible validation
  }

  return { value: clean, type: 'UNKNOWN', isValid: false };
};

import { InvoiceData } from '../types';

export const generateEDI810 = (data: InvoiceData, strictMode: boolean): string => {
  const segments: string[] = [];

  // ST - Transaction Set Header
  segments.push(`ST*810*0001`);

  // BIG - Beginning Segment for Invoice
  const dateStr = data.invoice_date.replace(/[-/]/g, ''); // Format: YYYYMMDD
  const invNo = data.invoice_number || 'UNKNOWN';
  const poNo = data.po_number ? `*${data.po_number}` : '';
  segments.push(`BIG*${dateStr}*${invNo}*${poNo}***`);

  // N1 - Name Loops
  if (data.seller.name) {
    segments.push(`N1*SU*${data.seller.name.substring(0, 35)}`);
    if (data.seller.address) segments.push(`N3*${data.seller.address.substring(0, 35)}`);
    if (data.seller.city) segments.push(`N4*${data.seller.city}*${data.seller.state}*${data.seller.zip}`);
  }

  if (data.buyer.name) {
    segments.push(`N1*BY*${data.buyer.name.substring(0, 35)}`);
    if (data.buyer.address) segments.push(`N3*${data.buyer.address.substring(0, 35)}`);
    if (data.buyer.city) segments.push(`N4*${data.buyer.city}*${data.buyer.state}*${data.buyer.zip}`);
  }

  // IT1 - Line Item Loops
  data.line_items.forEach(item => {
    const qty = item.qty || 0;
    const price = item.unit_price || 0;
    const uom = item.uom || 'EA';

    // Check if code is valid in strict mode
    let codePart = '';
    if (item.code_value && item.code_status === 'VALID') {
      codePart = `**UP*${item.code_value}`;
    } else if (item.code_value && !strictMode) {
      codePart = `**UP*${item.code_value}`;
    }

    segments.push(`IT1*${item.line_no}*${qty}*${uom}*${price}${codePart}`);
    if (item.description) {
      segments.push(`PID*F****${item.description.substring(0, 80)}`);
    }
  });

  // TDS - Total Amount
  if (data.totals.total !== null) {
    const totalCents = Math.round(data.totals.total * 100);
    segments.push(`TDS*${totalCents}`);
  }

  // CTT - Transaction Totals
  segments.push(`CTT*${data.line_items.length}`);

  // SE - Transaction Set Trailer
  // +1 for SE segment itself
  const segCount = segments.length + 1;
  segments.push(`SE*${segCount}*0001`);

  return segments.join('~') + '~';
};

import { jsPDF } from 'jspdf';
import JsBarcode from 'jsbarcode';
import QRCode from 'qrcode';
import { InvoiceData } from '../types';

export const generateLabelPDF = async (data: InvoiceData, strictMode: boolean, allowFallback: boolean): Promise<Blob> => {
  const doc = new jsPDF({ orientation: 'p', unit: 'mm', format: 'a4' });
  const margin = 10;
  const colWidth = 64;
  const rowHeight = 48;
  const cols = 3;

  doc.setFont('helvetica', 'bold');
  doc.setFontSize(14);
  doc.text(`Labels: ${data.invoice_number || 'Invoice'}`, margin, margin);
  doc.line(margin, margin + 2, 200, margin + 2);

  let currentX = margin;
  let currentY = margin + 10;

  const today = new Date().toLocaleDateString();

  for (let i = 0; i < data.line_items.length; i++) {
    const item = data.line_items[i];
    if (!item.code_value) continue;

    // Label Frame
    doc.setDrawColor(230);
    doc.setLineWidth(0.1);
    doc.rect(currentX, currentY, colWidth - 2, rowHeight - 2);

    // Sidebar dates (Retail style)
    doc.setFontSize(6);
    doc.setTextColor(150);
    doc.text(today, currentX + 4, currentY + rowHeight / 2 + 5, { angle: 90 });
    doc.text('01/01/2026', currentX + colWidth - 4, currentY + rowHeight / 2 + 5, { angle: 90 });

    // Price
    doc.setFontSize(18);
    doc.setTextColor(0);
    doc.setFont('helvetica', 'bold');
    const price = item.unit_price ? `$${item.unit_price.toFixed(2)}` : '$---';
    doc.text(price, currentX + colWidth / 2, currentY + 10, { align: 'center' });

    // Description
    doc.setFontSize(8);
    const desc = item.description.toUpperCase().substring(0, 25);
    doc.text(desc, currentX + colWidth / 2, currentY + 16, { align: 'center' });

    // Barcode Rendering
    const isValid = item.code_status === 'VALID';

    if (!isValid && strictMode && !allowFallback) {
      // INVALID TILE
      doc.setDrawColor(255, 0, 0);
      doc.setLineWidth(0.5);
      doc.rect(currentX + 10, currentY + 20, colWidth - 20, 15);
      doc.setFontSize(7);
      doc.setTextColor(255, 0, 0);
      doc.text('INVALID CODE', currentX + colWidth / 2, currentY + 26, { align: 'center' });
      doc.text('EDIT REQUIRED', currentX + colWidth / 2, currentY + 30, { align: 'center' });
    } else {
      try {
        const canvas = document.createElement('canvas');
        let format = 'CODE128';
        if (item.code_type === 'UPC' || item.code_value.length === 12) format = 'UPC';
        if (item.code_value.length === 13) format = 'EAN13';

        // If invalid but fallback is on, use Code128
        if (!isValid && allowFallback) format = 'CODE128';

        JsBarcode(canvas, item.code_value, {
          format,
          displayValue: false,
          margin: 0,
          width: 3,
          height: 50
        });

        const imgData = canvas.toDataURL('image/png');
        doc.addImage(imgData, 'PNG', currentX + 8, currentY + 20, colWidth - 18, 15);

        if (!isValid && allowFallback) {
          doc.setTextColor(255, 0, 0);
          doc.setFontSize(6);
          doc.text('FALLBACK', currentX + colWidth / 2, currentY + 21, { align: 'center' });
        }
      } catch (err) {
        // Fallback tile on tech failure
        doc.setFontSize(7);
        doc.setTextColor(255, 0, 0);
        doc.text('RENDER ERROR', currentX + colWidth / 2, currentY + 28, { align: 'center' });
      }
    }

    // Human Readable
    doc.setFontSize(8);
    doc.setTextColor(0);
    doc.setFont('helvetica', 'normal');
    doc.text(item.code_value, currentX + colWidth / 2, currentY + rowHeight - 6, { align: 'center' });

    // Grid increment
    if ((i + 1) % cols === 0) {
      currentX = margin;
      currentY += rowHeight;
    } else {
      currentX += colWidth;
    }

    if (currentY + rowHeight > 280) {
      doc.addPage();
      currentX = margin;
      currentY = margin + 10;
    }
  }

  return doc.output('blob');
};

import { GoogleGenAI, Type } from "@google/genai";
import { InvoiceData } from "../types";

export const extractInvoiceWithGemini = async (
  file: File,
  ocrFull: string,
  ocrUpc: string
): Promise<InvoiceData> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const base64 = await new Promise<string>((resolve) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => resolve((reader.result as string).split(',')[1]);
  });

  const systemInstruction = `
    You are an expert EDI and retail data extraction agent.

    STRICT JSON OUTPUT ONLY. NO MARKDOWN.

    INPUT SOURCES:
    1. Invoice Image (Multi-modal)
    2. OCR Full Page Text
    3. OCR UPC Column Region Text

    TASK:
    Extract invoice facts into the specified JSON schema.

    RULES:
    - Seller: Usually at the top header.
    - Buyer: Customer/Account block.
    - UPC Extraction: Match line items to UPCs found in the OCR UPC text.
    - If a value is missing, use "" or null.
    - Do not invent/hallucinate.
  `;

  const prompt = `
    Invoice Data Extraction:
    OCR Full: ${ocrFull}
    OCR UPC Column: ${ocrUpc}

    Return JSON structure only.
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { inlineData: { mimeType: file.type, data: base64 } },
        { text: prompt }
      ]
    },
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          invoice: {
            type: Type.OBJECT,
            properties: {
              invoice_number: { type: Type.STRING },
              invoice_date: { type: Type.STRING },
              seller: {
                type: Type.OBJECT,
                properties: {
                  name: { type: Type.STRING },
                  address: { type: Type.STRING },
                  city: { type: Type.STRING },
                  state: { type: Type.STRING },
                  zip: { type: Type.STRING }
                }
              },
              buyer: {
                type: Type.OBJECT,
                properties: {
                  name: { type: Type.STRING },
                  address: { type: Type.STRING },
                  city: { type: Type.STRING },
                  state: { type: Type.STRING },
                  zip: { type: Type.STRING },
                  account_id: { type: Type.STRING }
                }
              },
              po_number: { type: Type.STRING },
              currency: { type: Type.STRING },
              totals: {
                type: Type.OBJECT,
                properties: {
                  subtotal: { type: Type.NUMBER },
                  tax: { type: Type.NUMBER },
                  discount: { type: Type.NUMBER },
                  total: { type: Type.NUMBER }
                }
              },
              line_items: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    line_no: { type: Type.NUMBER },
                    description: { type: Type.STRING },
                    qty: { type: Type.NUMBER },
                    uom: { type: Type.STRING },
                    unit_price: { type: Type.NUMBER },
                    line_total: { type: Type.NUMBER },
                    code_type: { type: Type.STRING },
                    code_value: { type: Type.STRING }
                  }
                }
              }
            }
          },
          missing_fields: { type: Type.ARRAY, items: { type: Type.STRING } },
          warnings: { type: Type.ARRAY, items: { type: Type.STRING } },
          needs_review: { type: Type.BOOLEAN }
        }
      }
    }
  });

  const parsed = JSON.parse(response.text);
  return parsed.invoice;
};

