  // --- Actions ---

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!e.target.files) return;
    const newFiles = Array.from(e.target.files).slice(0, 4 - batch.invoices.length);
    const newInvoices: InvoiceState[] = newFiles.map(file => ({
      id: Math.random().toString(36).substring(7),
      file,
      previewUrl: URL.createObjectURL(file),
      status: 'QUEUED',
      progress: 0,
      currentTask: 'Ready to process',
      sellerName: 'Pending...',
      ocrFullText: '',
      ocrUpcText: '',
      data: null,
      missing_fields: [],
      warnings: [],
      ediText: '',
      pdfBlobUrl: null
    }));
    setBatch(prev => ({ ...prev, invoices: [...prev.invoices, ...newInvoices] }));
  };

  const removeInvoice = (id: string) => {
    setBatch(prev => ({ 
      ...prev, 
      invoices: prev.invoices.filter(inv => inv.id !== id) 
    }));
  };

  const startProcessing = async () => {
    setStep('PROCESSING');

    // Process sequentially for demo reliability
    for (let inv of batch.invoices) {
      if (inv.status === 'DONE') continue;

      updateInvoice(inv.id, { status: 'RUNNING', progress: 10 });

      try {
        // 1. OCR Passes
        updateInvoice(inv.id, { currentTask: 'OCR: Full Page Scan', progress: 20 });
        const fullResult = await Tesseract.recognize(inv.file, 'eng');
        const fullText = fullResult.data.text;

        updateInvoice(inv.id, { currentTask: 'OCR: Analyzing Columns', progress: 40 });
        // In a real app we'd crop. For this prototype, we'll use a regex extraction as proxy
        const upcText = fullText; 

        // 2. Gemini Extraction
        updateInvoice(inv.id, { currentTask: 'AI Invoice Analysis', progress: 60 });
        const invoiceData = await extractInvoiceWithGemini(inv.file, fullText, upcText);

        // 3. Validation
        updateInvoice(inv.id, { currentTask: 'Validating Codes', progress: 80 });
        const validatedItems = invoiceData.line_items.map(item => {
          const v = validateCode(item.code_value);
          return {
            ...item,
            code_status: v.isValid ? 'VALID' : 'INVALID'
          };
        }) as LineItem[];

        invoiceData.line_items = validatedItems;

        // 4. EDI & PDF
        updateInvoice(inv.id, { currentTask: 'Generating EDI & PDF', progress: 90 });
        const edi = generateEDI810(invoiceData, batch.strictMode);
        const pdfBlob = await generateLabelPDF(invoiceData, batch.strictMode, batch.allowCode128Fallback);
        const pdfUrl = URL.createObjectURL(pdfBlob);

        updateInvoice(inv.id, { 
          status: invoiceData.line_items.some(i => i.code_status === 'INVALID') ? 'NEEDS_REVIEW' : 'DONE',
          progress: 100,
          currentTask: 'Finished',
