export const preprocessForOCR = async (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.src = URL.createObjectURL(file);
    img.onload = () => {
      const canvas = document.createElement('canvas');
      const ctx = canvas.getContext('2d');
      if (!ctx) return reject('Canvas context error');

      // 2x Upscale
      const scale = 2;
      canvas.width = img.width * scale;
      canvas.height = img.height * scale;

      // Draw and apply simple filters
      ctx.imageSmoothingEnabled = false;
      ctx.drawImage(img, 0, 0, canvas.width, canvas.height);

      // Grayscale + Contrast Heuristic
      const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
      const data = imageData.data;
      for (let i = 0; i < data.length; i += 4) {
        const avg = (data[i] + data[i + 1] + data[i + 2]) / 3;
        // Simple thresholding/contrast boost
        const val = avg > 128 ? Math.min(255, avg * 1.2) : Math.max(0, avg * 0.8);
        data[i] = data[i+1] = data[i+2] = val;
      }
      ctx.putImageData(imageData, 0, 0);

      resolve(canvas.toDataURL('image/jpeg', 0.9));
      URL.revokeObjectURL(img.src);
    };
    img.onerror = reject;
  });
};

import Tesseract from 'tesseract.js';

export const performFullOCR = async (dataUrl: string): Promise<string> => {
  const { data: { text } } = await Tesseract.recognize(dataUrl, 'eng');
  return text;
};

export const performRegionOCR = async (dataUrl: string): Promise<string> => {
  // Prototype heuristic: In retail receipts, UPC is often in the right 40% of the page
  // We simulate a crop by creating a canvas from the dataUrl
  return new Promise((resolve) => {
    const img = new Image();
    img.src = dataUrl;
    img.onload = async () => {
      const canvas = document.createElement('canvas');
      const ctx = canvas.getContext('2d');
      if (!ctx) return resolve("");

      const width = img.width;
      const height = img.height;
      const cropWidth = width * 0.45;
      const cropX = width * 0.55; // Right side

      canvas.width = cropWidth;
      canvas.height = height;
      ctx.drawImage(img, cropX, 0, cropWidth, height, 0, 0, cropWidth, height);

      const croppedUrl = canvas.toDataURL();
      const { data: { text } } = await Tesseract.recognize(croppedUrl, 'eng');
      resolve(text);
    };
  });
};

import { GoogleGenAI, Type } from "@google/genai";
import { InvoiceData } from "../types";

export const extractInvoiceWithGemini = async (
  file: File,
  ocrFull: string,
  ocrUpc: string
): Promise<InvoiceData> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const base64 = await new Promise<string>((resolve) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => resolve((reader.result as string).split(',')[1]);
  });

  const systemInstruction = `
    You are a high-precision EDI architect. Extract invoice data into valid JSON.

    STRICT RULES:
    1. Extract Seller (top header), Buyer (bill-to), and Items.
    2. Link each line item to a UPC/EAN if present in the OCR texts.
    3. Use ONLY visible facts. Do not invent PO numbers or dates.
    4. X12 810 specific: ensure qty, uom (e.g. EA, CA, LB), and unit_price are accurate.

    JSON SCHEMA ONLY. NO MARKDOWN.
  `;

  const prompt = `
    Analyze this invoice image.
    Full Page OCR: ${ocrFull}
    UPC Column OCR Heuristic: ${ocrUpc}

    Return JSON structured precisely like this:
    {
      "invoice": {
        "invoice_number": "string",
        "invoice_date": "YYYY-MM-DD",
        "seller": {"name": "string", "address": "string", "city": "string", "state": "string", "zip": "string"},
        "buyer": {"name": "string", "address": "string", "city": "string", "state": "string", "zip": "string", "account_id": "string"},
        "po_number": "string",
        "currency": "USD",
        "totals": {"subtotal": number, "tax": number, "discount": number, "total": number},
        "line_items": [
          {"line_no": number, "description": "string", "qty": number, "uom": "string", "unit_price": number, "line_total": number, "code_type": "UPC", "code_value": "string"}
        ]
      },
      "missing_fields": ["field_name"],
      "warnings": ["warning_text"],
      "needs_review": boolean
    }
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { inlineData: { mimeType: file.type, data: base64 } },
        { text: prompt }
      ]
    },
    config: {
      systemInstruction,
      responseMimeType: "application/json"
    }
  });

  const parsed = JSON.parse(response.text);
  return parsed.invoice;
};

