      try {
        // 1. Preprocess
        const preprocessedUrl = await preprocessForOCR(inv.file);

        // 2. OCR Passes
        updateInvoice(inv.id, { currentTask: 'OCR: Full Page Scan', progress: 20 });
        const fullText = await performFullOCR(preprocessedUrl);

        updateInvoice(inv.id, { currentTask: 'OCR: Analyzing UPC Column', progress: 40 });
        const upcText = await performRegionOCR(preprocessedUrl);

        // 3. Gemini Extraction
        updateInvoice(inv.id, { currentTask: 'AI Understanding Invoice...', progress: 65 });
        const invoiceData = await extractInvoiceWithGemini(inv.file, fullText, upcText);

        // 4. Validation & EDI/PDF
        updateInvoice(inv.id, { currentTask: 'Building EDI & Label Sheet...', progress: 85 });

        const validatedItems = invoiceData.line_items.map(item => {
          const v = validateCode(item.code_value);
          return { ...item, code_status: v.isValid ? 'VALID' : 'INVALID' };
        }) as LineItem[];

        invoiceData.line_items = validatedItems;
        const edi = generateEDI810(invoiceData, batch.strictMode);
        const pdfBlob = await generateLabelPDF(invoiceData, batch.strictMode, batch.allowCode128Fallback);
        const pdfUrl = URL.createObjectURL(pdfBlob);

        const hasInvalid = invoiceData.line_items.some(i => i.code_status === 'INVALID');
        updateInvoice(inv.id, { 
          status: hasInvalid ? 'NEEDS_REVIEW' : 'DONE',
          progress: 100,
          currentTask: 'Processing complete',
          sellerName: invoiceData.seller.name || 'Unknown Vendor',
          ocrFullText: fullText,
          ocrUpcText: upcText,
          data: invoiceData,
          ediText: edi,
          pdfBlobUrl: pdfUrl
        });

      } catch (err: any) {
        updateInvoice(inv.id, { status: 'ERROR', error: err.message, currentTask: 'Failed' });
      }
    }
  };

  const updateInvoice = (id: string, updates: Partial<InvoiceState>) => {
    setBatch(prev => ({
      ...prev,
      invoices: prev.invoices.map(inv => inv.id === id ? { ...inv, ...updates } : inv)
    }));
  };

  const handleEditItem = (invId: string, lineIndex: number, field: keyof LineItem, value: any) => {
    setBatch(prev => {
      const inv = prev.invoices.find(i => i.id === invId);
      if (!inv || !inv.data) return prev;
      const newItems = [...inv.data.line_items];
      newItems[lineIndex] = { ...newItems[lineIndex], [field]: value };
      if (field === 'code_value') {
        const v = validateCode(value);
        newItems[lineIndex].code_status = v.isValid ? 'VALID' : 'INVALID';
      }
      const newData = { ...inv.data, line_items: newItems };
      return {
        ...prev,
        invoices: prev.invoices.map(i => i.id === invId ? { ...i, data: newData } : i)
      };
    });
  };

  const regenerate = async (invId: string) => {
    const inv = batch.invoices.find(i => i.id === invId);
    if (!inv || !inv.data) return;
    const edi = generateEDI810(inv.data, batch.strictMode);
    const pdfBlob = await generateLabelPDF(inv.data, batch.strictMode, batch.allowCode128Fallback);
    const pdfUrl = URL.createObjectURL(pdfBlob);
    updateInvoice(invId, {
      ediText: edi,
      pdfBlobUrl: pdfUrl,
      status: inv.data.line_items.some(i => i.code_status === 'INVALID') ? 'NEEDS_REVIEW' : 'DONE'
    });
  };

  const sellers = Array.from(new Set(batch.invoices.map(inv => inv.sellerName).filter(s => s !== 'Pending...')));
  const filteredInvoices = batch.invoices.filter(inv => !filterSeller || inv.sellerName === filterSeller);

  // --- Step 1: Upload ---
  if (step === 'UPLOAD') {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-8">
        <div className="max-w-4xl w-full">
          <header className="mb-12 text-center">
            <div className="inline-flex items-center space-x-2 bg-indigo-600 text-white px-4 py-1.5 rounded-full text-xs font-bold mb-6 shadow-lg shadow-indigo-100 uppercase tracking-widest">
              <FileDigit className="w-4 h-4" />
              <span>Version 2.0 Enterprise</span>
            </div>
            <h1 className="text-5xl font-black text-slate-900 mb-4 tracking-tight">Invoice Batch Processor</h1>
            <p className="text-slate-500 text-lg max-w-2xl mx-auto font-medium leading-relaxed">
              Automated X12 810 EDI conversion and retail label generation for logistics teams.
            </p>
          </header>

          <div className="bg-white rounded-[40px] shadow-2xl border border-slate-200 p-12 overflow-hidden relative">
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-16 relative z-10">
              <div className="space-y-8">
                <div className="space-y-4">
                  <label className="text-sm font-bold text-slate-900 block ml-1 uppercase tracking-wider">Batch Identity</label>
                  <input 
                    type="text" 
                    value={batch.name} 
                    onChange={e => setBatch(prev => ({...prev, name: e.target.value}))}
                    className="w-full bg-slate-100 border-none rounded-2xl px-6 py-4 font-bold text-slate-700 focus:ring-2 focus:ring-indigo-500 transition-all shadow-inner"
                  />
                </div>

                <div className="space-y-4">
                  <label className="text-sm font-bold text-slate-900 block ml-1 uppercase tracking-wider">Add Documents</label>
                  <div className="relative group cursor-pointer border-2 border-dashed border-slate-200 rounded-[32px] p-12 hover:border-indigo-400 hover:bg-indigo-50/30 transition-all text-center">
                    <input type="file" multiple accept="image/*" onChange={handleFileChange} className="absolute inset-0 opacity-0 cursor-pointer z-20" />
                    <Upload className="w-12 h-12 text-indigo-500 mx-auto mb-4 group-hover:-translate-y-1 transition-transform" />
                    <p className="text-slate-900 font-bold text-lg mb-1">Click to Upload</p>
                    <p className="text-slate-400 text-sm">Select up to 4 invoice images (JPG/PNG)</p>
                  </div>
                </div>

                <div className="bg-slate-50 rounded-3xl p-6 border border-slate-100">
                  <div className="flex items-center space-x-2 mb-4 text-slate-900">
                    <Settings2 className="w-4 h-4" />
                    <span className="text-xs font-black uppercase tracking-widest">Global Options</span>
                  </div>
                  <div className="space-y-5">
                    <Toggle 
                      label="Strict Validation" 
                      sub="Block invalid codes in EDI/PDF"
                      active={batch.strictMode} 
                      onClick={() => setBatch(prev => ({...prev, strictMode: !prev.strictMode}))} 
                    />
                    <Toggle 
                      label="Fallback Labels" 
                      sub="Use Code128 for unverified tags"
                      active={batch.allowCode128Fallback} 
                      onClick={() => setBatch(prev => ({...prev, allowCode128Fallback: !prev.allowCode128Fallback}))} 
                    />
                  </div>
                </div>
              </div>

              <div className="flex flex-col">
                <div className="flex items-center justify-between mb-6">
                  <h3 className="text-sm font-black text-slate-400 uppercase tracking-widest">Selected Batch ({batch.invoices.length}/4)</h3>
                </div>
                {batch.invoices.length === 0 ? (
                  <div className="flex-1 flex flex-col items-center justify-center bg-slate-50 border border-slate-100 rounded-[32px] p-12 text-slate-300">
                    <LayoutGrid className="w-16 h-16 mb-4 opacity-20" />
                    <p className="font-bold text-slate-400">Queue is currently empty</p>
                  </div>
                ) : (
                  <div className="flex-1 space-y-4 overflow-y-auto max-h-[450px] pr-2 scrollbar-thin">
                    {batch.invoices.map(inv => (
                      <div key={inv.id} className="flex items-center justify-between p-4 bg-white border border-slate-200 rounded-2xl shadow-sm hover:shadow-md transition-shadow group">
                        <div className="flex items-center space-x-4">
                          <img src={inv.previewUrl} className="w-14 h-14 rounded-xl object-cover border border-slate-100" />
                          <div className="min-w-0">
                            <p className="text-sm font-bold text-slate-900 truncate max-w-[150px]">{inv.file.name}</p>
                            <p className="text-[10px] font-black text-slate-400 uppercase">{(inv.file.size / 1024).toFixed(1)} KB</p>
                          </div>
                        </div>
                        <button onClick={() => removeInvoice(inv.id)} className="p-2 text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-xl transition-all">
                          <Trash2 className="w-5 h-5" />
                        </button>
                      </div>
                    ))}
                    <button 
                      onClick={startProcessing}
                      className="w-full mt-6 bg-slate-900 hover:bg-black text-white font-black py-5 rounded-[24px] shadow-2xl shadow-slate-200 flex items-center justify-center group active:scale-[0.98] transition-all"
                    >
                      Process Entire Batch
                      <ChevronRight className="ml-2 w-5 h-5 group-hover:translate-x-1 transition-transform" />
                    </button>
                  </div>
                )}
              </div>
            </div>
            {/* Background Accent */}
            <div className="absolute top-0 right-0 w-64 h-64 bg-indigo-50/50 rounded-full blur-[100px] -mr-32 -mt-32 pointer-events-none" />
          </div>
        </div>
      </div>
    );
  }

  // --- Step 2: Processing ---
  if (step === 'PROCESSING') {
    const isDone = batch.invoices.every(inv => ['DONE', 'NEEDS_REVIEW', 'ERROR'].includes(inv.status));
    const processedCount = batch.invoices.filter(i => ['DONE', 'NEEDS_REVIEW'].includes(i.status)).length;

    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-8">
        <div className="max-w-3xl w-full bg-white rounded-[40px] shadow-2xl border border-slate-200 p-12">
          <div className="flex items-center justify-between mb-12">
            <div>
              <h2 className="text-3xl font-black text-slate-900">Batch Pipeline</h2>
              <p className="text-slate-400 font-bold mt-1">Executing multi-stage extraction</p>
            </div>
            <div className="bg-slate-50 px-6 py-2 rounded-2xl border border-slate-100 flex items-center space-x-3">
              <Loader2 className={`w-5 h-5 text-indigo-600 ${!isDone && 'animate-spin'}`} />
              <span className="text-sm font-black text-slate-700">{processedCount} / {batch.invoices.length} Complete</span>
            </div>
          </div>

          <div className="space-y-6 mb-12">
            {batch.invoices.map(inv => (
              <div key={inv.id} className="p-6 border border-slate-100 rounded-3xl bg-slate-50/50 hover:bg-white hover:shadow-xl transition-all border border-transparent hover:border-slate-100">
                <div className="flex items-center justify-between mb-4">
                  <div className="flex items-center space-x-4">
                    <img src={inv.previewUrl} className="w-16 h-16 rounded-2xl object-cover border border-slate-200 shadow-sm" />
                    <div>
                      <h4 className="text-sm font-black text-slate-900 uppercase tracking-tight">{inv.file.name}</h4>
                      <p className="text-xs font-bold text-slate-400 mt-1">{inv.currentTask}</p>
                    </div>
                  </div>
                  <div className={`px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-wider shadow-sm border ${
                    inv.status === 'DONE' ? 'bg-emerald-50 text-emerald-700 border-emerald-100' :
                    inv.status === 'RUNNING' ? 'bg-indigo-50 text-indigo-700 border-indigo-100' :
                    inv.status === 'NEEDS_REVIEW' ? 'bg-amber-50 text-amber-700 border-amber-100' :
                    inv.status === 'ERROR' ? 'bg-red-50 text-red-700 border-red-100' : 'bg-slate-100 text-slate-400 border-slate-200'
                  }`}>
                    {inv.status.replace('_', ' ')}
                  </div>
                </div>
                <div className="h-3 bg-slate-200 rounded-full overflow-hidden shadow-inner">
                  <div 
                    className="h-full bg-gradient-to-r from-indigo-600 to-violet-600 transition-all duration-700" 
                    style={{ width: `${inv.progress}%` }} 
                  />
                </div>
              </div>
            ))}
          </div>

          <div className="flex space-x-6">
            <button onClick={() => setStep('UPLOAD')} className="flex-1 border-2 border-slate-200 text-slate-600 font-black py-5 rounded-3xl hover:bg-slate-50 active:scale-[0.98] transition-all">
              Cancel Batch
            </button>
            <button 
              disabled={!isDone}
              onClick={() => setStep('RESULTS')}
              className={`flex-1 font-black py-5 rounded-3xl shadow-2xl transition-all active:scale-[0.98] ${
                isDone ? 'bg-indigo-600 hover:bg-indigo-700 text-white shadow-indigo-200' : 'bg-slate-200 text-slate-400 cursor-not-allowed shadow-none'
              }`}
            >
              Analyze Results
            </button>
          </div>
        </div>
      </div>
    );
  }

  // --- Step 3: Results ---
  return (
    <div className="min-h-screen flex bg-slate-50">
      {/* Dynamic Filter Sidebar */}
      <aside className="w-80 bg-white border-r border-slate-200 sticky top-0 h-screen p-8 flex flex-col shadow-lg z-10">
        <div className="flex items-center space-x-4 mb-12">
          <div className="bg-slate-900 p-3 rounded-2xl text-white shadow-xl">
            <Package className="w-6 h-6" />
          </div>
          <span className="font-black text-xl text-slate-900 tracking-tight">Summary</span>
        </div>

        <div className="flex-1 space-y-12 overflow-y-auto pr-2 scrollbar-thin">
          <div className="space-y-4">
            <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-4">Supplier Segments</h4>
            <div className="space-y-2">
              <SidebarItem 
                label="All Transmissions" 
                count={batch.invoices.length} 
                active={!filterSeller} 
                onClick={() => setFilterSeller(null)} 
              />
              {sellers.map(s => (
                <SidebarItem 
                  key={s} 
                  label={s} 
                  count={batch.invoices.filter(i => i.sellerName === s).length} 
                  active={filterSeller === s} 
                  onClick={() => setFilterSeller(s)} 
                />
              ))}
            </div>
          </div>

          <div className="space-y-4">
            <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-4">Export Utilities</h4>
            <div className="space-y-2">
              <button className="w-full flex items-center p-4 text-sm text-slate-700 font-bold hover:bg-slate-50 rounded-2xl transition-all border border-transparent hover:border-slate-100 group">
                <Download className="w-4 h-4 mr-4 text-slate-400 group-hover:text-indigo-600" />
                Download Batch EDI
              </button>
              <button className="w-full flex items-center p-4 text-sm text-slate-700 font-bold hover:bg-slate-50 rounded-2xl transition-all border border-transparent hover:border-slate-100 group">
                <FileCheck className="w-4 h-4 mr-4 text-slate-400 group-hover:text-indigo-600" />
                Download All PDFs
              </button>
            </div>
          </div>
        </div>

        <button 
          onClick={() => setStep('UPLOAD')}
          className="mt-8 flex items-center justify-center p-5 bg-slate-900 text-white rounded-[24px] font-black text-sm shadow-2xl shadow-slate-200 hover:bg-black active:scale-[0.98] transition-all"
        >
          New Batch Run
        </button>
      </aside>

      {/* Results Viewport */}
      <main className="flex-1 p-16 max-w-6xl mx-auto">
        <div className="flex items-center justify-between mb-12">
          <div>
            <h2 className="text-4xl font-black text-slate-900 tracking-tight">
              {filterSeller || 'Batch Inventory'}
            </h2>
            <p className="text-slate-400 font-bold mt-1">Reviewing verified extraction results</p>
          </div>
          <div className="flex items-center space-x-4">
             <div className="flex items-center space-x-2 text-[10px] font-black text-slate-500 bg-white px-5 py-2.5 rounded-full border border-slate-200 shadow-sm uppercase tracking-widest">
                <Search className="w-3.5 h-3.5" />
                <span>Total Matches: {filteredInvoices.length}</span>
             </div>
          </div>
        </div>

        <div className="space-y-8">
          {filteredInvoices.map(inv => (
            <div key={inv.id} className="bg-white rounded-[40px] border border-slate-200 shadow-sm overflow-hidden hover:shadow-xl transition-all duration-300">
              <div 
                className="p-8 flex items-center justify-between cursor-pointer hover:bg-slate-50/50 transition-colors"
                onClick={() => setExpandedInvoice(expandedInvoice === inv.id ? null : inv.id)}
              >
                <div className="flex items-center space-x-6">
                  <div className="relative">
                    <img src={inv.previewUrl} className="w-20 h-20 rounded-[24px] object-cover shadow-inner border border-slate-100 group-hover:scale-105 transition-transform" />
                    {inv.status === 'NEEDS_REVIEW' && (
                      <div className="absolute -top-1 -right-1 bg-amber-500 text-white p-1 rounded-full shadow-lg">
                        <AlertCircle className="w-3.5 h-3.5" />
                      </div>
                    )}
                  </div>
                  <div>
                    <h3 className="text-lg font-black text-slate-900 tracking-tight leading-none mb-2">{inv.data?.invoice_number || 'UNKNOWN INVOICE'}</h3>
                    <p className="text-xs font-bold text-slate-400 uppercase tracking-wider">{inv.sellerName} &bull; {inv.data?.invoice_date || 'N/A'}</p>
                  </div>
                </div>

                <div className="flex items-center space-x-12">
                  <div className="text-right">
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Settlement</p>
                    <p className="text-lg font-black text-slate-900">${inv.data?.totals.total?.toLocaleString() || '0.00'}</p>
                  </div>
                  <div className={`px-5 py-2 rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-sm border ${
                    inv.status === 'DONE' ? 'bg-emerald-50 text-emerald-700 border-emerald-100' :
                    inv.status === 'NEEDS_REVIEW' ? 'bg-amber-50 text-amber-700 border-amber-100' : 'bg-red-50 text-red-700 border-red-100'
                  }`}>
                    {inv.status.replace('_', ' ')}
                  </div>
                  <div className="bg-slate-100 p-2 rounded-full text-slate-400">
                    {expandedInvoice === inv.id ? <ChevronUp className="w-5 h-5" /> : <ChevronDown className="w-5 h-5" />}
                  </div>
                </div>
              </div>

              {expandedInvoice === inv.id && (
                <div className="border-t border-slate-100 animate-in fade-in slide-in-from-top-4 duration-500 bg-white">
                  <InvoiceTabs 
                    inv={inv} 
                    onEditItem={handleEditItem}
                    onRegenerate={regenerate}
                    strictMode={batch.strictMode}
                  />
                </div>
              )}
            </div>
          ))}
        </div>
      </main>
    </div>
  );
};

// --- Helper Components ---

const SidebarItem: React.FC<{ label: string, count: number, active: boolean, onClick: () => void }> = ({ label, count, active, onClick }) => (
  <button 
    onClick={onClick}
    className={`w-full flex items-center justify-between p-4 rounded-2xl text-xs font-black uppercase tracking-widest transition-all ${active ? 'bg-slate-900 text-white shadow-xl' : 'text-slate-500 hover:bg-slate-50'}`}
  >
    <span className="truncate pr-4">{label}</span>
    <span className={`px-2.5 py-1 rounded-lg border ${active ? 'bg-white/10 border-white/20 text-white' : 'bg-slate-50 border-slate-200 text-slate-400'}`}>
      {count}
    </span>
  </button>
);

const Toggle: React.FC<{ label: string, sub: string, active: boolean, onClick: () => void }> = ({ label, sub, active, onClick }) => (
  <div className="flex items-center justify-between group">
    <div className="cursor-pointer" onClick={onClick}>
      <p className="text-sm font-black text-slate-900 tracking-tight group-hover:text-indigo-600 transition-colors">{label}</p>
      <p className="text-[10px] font-bold text-slate-400">{sub}</p>
    </div>
    <button 
      onClick={onClick}
      className={`w-12 h-6 rounded-full transition-all duration-300 relative ${active ? 'bg-indigo-600 shadow-lg shadow-indigo-100' : 'bg-slate-200 shadow-inner'}`}
    >
      <div className={`absolute top-1 w-4 h-4 bg-white rounded-full transition-transform duration-300 shadow-sm ${active ? 'translate-x-7' : 'translate-x-1'}`} />
    </button>
  </div>
);

const InvoiceTabs: React.FC<{ 
  inv: InvoiceState, 
  onEditItem: (id: string, idx: number, f: keyof LineItem, v: any) => void,
  onRegenerate: (id: string) => void,
  strictMode: boolean
}> = ({ inv, onEditItem, onRegenerate, strictMode }) => {
  const [tab, setTab] = useState<'EDI' | 'BARCODE' | 'EDIT'>('EDIT');

  return (
    <div>
      <div className="flex border-b border-slate-100 px-8 bg-slate-50/50">
        {[
          { id: 'EDIT', label: 'Quality Audit' },
          { id: 'EDI', label: '810 Transaction' },
          { id: 'BARCODE', label: 'Logistic Tags' }
        ].map(t => (
          <button 
            key={t.id}
            onClick={() => setTab(t.id as any)}
            className={`px-8 py-5 text-[10px] font-black uppercase tracking-[0.2em] transition-all relative ${tab === t.id ? 'text-indigo-600' : 'text-slate-400 hover:text-slate-900'}`}
          >
            {t.label}
            {tab === t.id && <div className="absolute bottom-0 left-8 right-8 h-1 bg-indigo-600 rounded-t-full shadow-lg shadow-indigo-100" />}
          </button>
        ))}
      </div>

      <div className="p-12">
        {tab === 'EDIT' && (
          <div className="space-y-10">
            <div className="flex items-center justify-between">
               <div>
                 <h4 className="text-sm font-black text-slate-900 uppercase tracking-widest">Line Item Verification</h4>
                 <p className="text-xs text-slate-400 mt-1">Review extracted codes and settlement amounts.</p>
               </div>
               <button 
                onClick={() => onRegenerate(inv.id)}
                className="flex items-center px-6 py-3 bg-indigo-600 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-indigo-700 shadow-xl shadow-indigo-100 active:scale-[0.98] transition-all"
               >
                 <RefreshCw className="w-3.5 h-3.5 mr-3" />
                 Re-sync Documents
               </button>
            </div>
            <div className="border border-slate-200 rounded-[32px] overflow-hidden shadow-sm">
              <table className="w-full text-left text-xs">
                <thead className="bg-slate-50 border-b border-slate-200">
                  <tr>
                    <th className="px-6 py-4 font-black text-slate-400 uppercase tracking-widest">Ln</th>
                    <th className="px-6 py-4 font-black text-slate-400 uppercase tracking-widest">Description</th>
                    <th className="px-6 py-4 font-black text-slate-400 uppercase tracking-widest">Qty</th>
                    <th className="px-6 py-4 font-black text-slate-400 uppercase tracking-widest">Unit Price</th>
                    <th className="px-6 py-4 font-black text-slate-400 uppercase tracking-widest">UPC/EAN Code</th>
                    <th className="px-6 py-4 font-black text-slate-400 uppercase tracking-widest">Integrity</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {inv.data?.line_items.map((item, idx) => (
                    <tr key={idx} className="hover:bg-slate-50/50 transition-colors">
                      <td className="px-6 py-5 text-slate-400 font-bold">{item.line_no}</td>
                      <td className="px-6 py-5">
                        <input 
                          value={item.description} 
                          onChange={(e) => onEditItem(inv.id, idx, 'description', e.target.value)}
                          className="bg-transparent border-none focus:ring-0 rounded p-0 w-full text-slate-900 font-bold"
                        />
                      </td>
                      <td className="px-6 py-5 w-24">
                        <input 
                          type="number"
                          value={item.qty || 0} 
                          onChange={(e) => onEditItem(inv.id, idx, 'qty', parseFloat(e.target.value))}
                          className="bg-slate-50 border border-slate-100 rounded-lg px-2 py-1 w-full font-bold"
                        />
                      </td>
                      <td className="px-6 py-5 w-28 font-mono">
