export type AppStep = 'UPLOAD' | 'PROCESSING' | 'RESULTS';

export interface Party {
  name: string;
  address: string;
  city: string;
  state: string;
  zip: string;
  account_id?: string;
}

export interface LineItem {
  line_no: number;
  description: string;
  qty: number | null;
  uom: string;
  unit_price: number | null;
  line_total: number | null;
  code_type: string;
  code_value: string;
  code_status?: 'VALID' | 'INVALID' | 'UNVERIFIED';
}

export interface InvoiceData {
  invoice_number: string;
  invoice_date: string;
  seller: Party;
  buyer: Party;
  po_number: string;
  currency: string;
  totals: {
    subtotal: number | null;
    tax: number | null;
    discount: number | null;
    total: number | null;
  };
  line_items: LineItem[];
}

export interface InvoiceState {
  id: string;
  file: File;
  previewUrl: string;
  status: 'QUEUED' | 'RUNNING' | 'DONE' | 'NEEDS_REVIEW' | 'ERROR';
  progress: number;
  currentTask: string;
  sellerName: string;
  ocrFullText: string;
  ocrUpcText: string;
  data: InvoiceData | null;
  missing_fields: string[];
  warnings: string[];
  ediText: string;
  pdfBlobUrl: string | null;
  error?: string;
}

export interface BatchState {
  name: string;
  strictMode: boolean;
  allowCode128Fallback: boolean;
  invoices: InvoiceState[];
}

export interface CodeValidationResult {
  value: string;
  type: 'UPC-A' | 'EAN-13' | 'UCI' | 'QR' | 'UNKNOWN';
  isValid: boolean;
}

/**
 * Represents a barcode or identifier detected during document scanning.
 * Used in barcodeScanner and pdfGenerator.
 */
export interface DetectedCode {
  type: 'UPC-A' | 'EAN-13' | 'UCI' | 'QR' | 'UNKNOWN';
  value: string;
  dateLeft?: string;
  dateRight?: string;
  price?: number;
  unit?: string;
  description?: string;
}

/**
 * Enumerates the possible stages of the invoice processing pipeline.
 * Used in the StepProgress component.
 */
export enum ProcessingStep {
  RUNNING_OCR = 'RUNNING_OCR',
  UNDERSTANDING_INVOICE = 'UNDERSTANDING_INVOICE',
  GENERATING_EDI = 'GENERATING_EDI',
  GENERATING_PDF = 'GENERATING_PDF',
  COMPLETED = 'COMPLETED'
}

/**
 * Represents the final aggregated results of an invoice processing run.
 * Used in the ResultsPanel component.
 */
export interface ProcessingResult {
  invoice: InvoiceData;
  edi_810: string;
  detected_codes: DetectedCode[];
  missing_fields: string[];
  warnings: string[];
}

import React, { useState, useEffect } from 'react';
import { 
  Upload, 
  Layers, 
  FileCheck, 
  Loader2, 
  ChevronRight, 
  AlertCircle, 
  CheckCircle, 
  Trash2,
  Filter,
  Download,
  Edit2,
  RefreshCw,
  ChevronDown,
  ChevronUp,
  Search,
  ExternalLink,
  Package,
  Settings2,
  FileDigit,
  LayoutGrid,
  Copy,
  Check
} from 'lucide-react';
import { 
  AppStep, 
  BatchState, 
  InvoiceState, 
  InvoiceData, 
  LineItem 
} from './types';
import { validateCode } from './services/validationService';
import { extractInvoiceWithGemini } from './services/geminiService';
import { generateEDI810 } from './services/ediService';
import { generateLabelPDF } from './services/pdfService';
import { preprocessForOCR } from './services/imagePreprocessor';
import { performFullOCR, performRegionOCR } from './services/ocrService';

const App: React.FC = () => {
  const [step, setStep] = useState<AppStep>('UPLOAD');
  const [batch, setBatch] = useState<BatchState>({
    name: 'Batch_' + new Date().toISOString().slice(0, 10),
    strictMode: true,
    allowCode128Fallback: false,
    invoices: []
  });

  const [filterSeller, setFilterSeller] = useState<string | null>(null);
  const [expandedInvoice, setExpandedInvoice] = useState<string | null>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!e.target.files) return;
    const newFiles = Array.from(e.target.files).slice(0, 4 - batch.invoices.length);
    const newInvoices: InvoiceState[] = newFiles.map(file => ({
      id: Math.random().toString(36).substring(7),
      file,
      previewUrl: URL.createObjectURL(file),
      status: 'QUEUED',
      progress: 0,
      currentTask: 'Waiting...',
      sellerName: 'Pending...',
      ocrFullText: '',
      ocrUpcText: '',
      data: null,
      missing_fields: [],
      warnings: [],
      ediText: '',
      pdfBlobUrl: null
    }));
    setBatch(prev => ({ ...prev, invoices: [...prev.invoices, ...newInvoices] }));
  };

  const removeInvoice = (id: string) => {
    setBatch(prev => ({ 
      ...prev, 
      invoices: prev.invoices.filter(inv => inv.id !== id) 
    }));
  };

  const startProcessing = async () => {
    setStep('PROCESSING');

    for (let inv of batch.invoices) {
      if (inv.status === 'DONE' || inv.status === 'NEEDS_REVIEW') continue;

      updateInvoice(inv.id, { status: 'RUNNING', progress: 5, currentTask: 'Preprocessing image...' });

      try {
        const preprocessedUrl = await preprocessForOCR(inv.file);

        updateInvoice(inv.id, { currentTask: 'OCR: Full Page Scan', progress: 20 });
        const fullText = await performFullOCR(preprocessedUrl);

        updateInvoice(inv.id, { currentTask: 'OCR: Analyzing UPC Column', progress: 40 });
        const upcText = await performRegionOCR(preprocessedUrl);

        updateInvoice(inv.id, { currentTask: 'AI Understanding Invoice...', progress: 65 });
        const invoiceData = await extractInvoiceWithGemini(inv.file, fullText, upcText);

        updateInvoice(inv.id, { currentTask: 'Building EDI & Label Sheet...', progress: 85 });

        const validatedItems = invoiceData.line_items.map(item => {
          const v = validateCode(item.code_value);
          return { ...item, code_status: v.isValid ? 'VALID' : 'INVALID' };
        }) as LineItem[];

        invoiceData.line_items = validatedItems;
        const edi = generateEDI810(invoiceData, batch.strictMode);
        const pdfBlob = await generateLabelPDF(invoiceData, batch.strictMode, batch.allowCode128Fallback);
        const pdfUrl = URL.createObjectURL(pdfBlob);

        const hasInvalid = invoiceData.line_items.some(i => i.code_status === 'INVALID');
        updateInvoice(inv.id, { 
          status: hasInvalid ? 'NEEDS_REVIEW' : 'DONE',
          progress: 100,
          currentTask: 'Processing complete',
          sellerName: invoiceData.seller.name || 'Unknown Vendor',
          ocrFullText: fullText,
          ocrUpcText: upcText,
          data: invoiceData,
          ediText: edi,
          pdfBlobUrl: pdfUrl
        });

      } catch (err: any) {
        updateInvoice(inv.id, { status: 'ERROR', error: err.message, currentTask: 'Failed' });
      }
    }

    // Auto-transition to results page after processing is finished
    setTimeout(() => {
      setStep('RESULTS');
    }, 1200);
  };

  const updateInvoice = (id: string, updates: Partial<InvoiceState>) => {
    setBatch(prev => ({
      ...prev,
      invoices: prev.invoices.map(inv => inv.id === id ? { ...inv, ...updates } : inv)
    }));
  };

  const handleEditItem = (invId: string, lineIndex: number, field: keyof LineItem, value: any) => {
    setBatch(prev => {
      const inv = prev.invoices.find(i => i.id === invId);
      if (!inv || !inv.data) return prev;
      const newItems = [...inv.data.line_items];
      newItems[lineIndex] = { ...newItems[lineIndex], [field]: value };
      if (field === 'code_value') {
        const v = validateCode(value);
        newItems[lineIndex].code_status = v.isValid ? 'VALID' : 'INVALID';
      }
      const newData = { ...inv.data, line_items: newItems };
      return {
        ...prev,
        invoices: prev.invoices.map(i => i.id === invId ? { ...i, data: newData } : i)
      };
    });
  };

  const regenerate = async (invId: string) => {
    const inv = batch.invoices.find(i => i.id === invId);
    if (!inv || !inv.data) return;
    const edi = generateEDI810(inv.data, batch.strictMode);
    const pdfBlob = await generateLabelPDF(inv.data, batch.strictMode, batch.allowCode128Fallback);
    const pdfUrl = URL.createObjectURL(pdfBlob);
    updateInvoice(invId, {
      ediText: edi,
      pdfBlobUrl: pdfUrl,
      status: inv.data.line_items.some(i => i.code_status === 'INVALID') ? 'NEEDS_REVIEW' : 'DONE'
    });
  };

  // --- Download Utilities ---

  const downloadAllEDI = () => {
    batch.invoices.forEach(inv => {
      if (inv.ediText) {
        const blob = new Blob([inv.ediText], { type: 'text/plain' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `EDI_${inv.id}_${inv.data?.invoice_number || 'export'}.edi`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
      }
    });
  };

  const downloadAllPDFs = () => {
    batch.invoices.forEach(inv => {
      if (inv.pdfBlobUrl) {
        const a = document.createElement('a');
        a.href = inv.pdfBlobUrl;
        a.download = `Labels_${inv.id}_${inv.data?.invoice_number || 'export'}.pdf`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
      }
    });
  };

  const sellers = Array.from(new Set(batch.invoices.map(inv => inv.sellerName).filter(s => s !== 'Pending...')));
  const filteredInvoices = batch.invoices.filter(inv => !filterSeller || inv.sellerName === filterSeller);

  if (step === 'UPLOAD') {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-8">
        <div className="max-w-4xl w-full">
