              <FileDigit className="w-4 h-4" />
              <span>Version 2.0 Enterprise</span>
            </div>
            <h1 className="text-5xl font-black text-slate-900 mb-4 tracking-tight">Invoice Batch Processor</h1>
            <p className="text-slate-500 text-lg max-w-2xl mx-auto font-medium leading-relaxed">
              Automated EDI document generation and retail label creation for logistics teams.
            </p>
          </header>

          <div className="bg-white rounded-[40px] shadow-2xl border border-slate-200 p-12 overflow-hidden relative">
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-16 relative z-10">
              <div className="space-y-8">
                <div className="space-y-4">
                  <label className="text-sm font-bold text-slate-900 block ml-1 uppercase tracking-wider">Batch Identity</label>
                  <input 
                    type="text" 
                    value={batch.name} 
                    onChange={e => setBatch(prev => ({...prev, name: e.target.value}))}
                    className="w-full bg-slate-100 border-none rounded-2xl px-6 py-4 font-bold text-slate-700 focus:ring-2 focus:ring-indigo-500 transition-all shadow-inner"
                  />
                </div>

                <div className="space-y-4">
                  <label className="text-sm font-bold text-slate-900 block ml-1 uppercase tracking-wider">Add Documents</label>
                  <div className="relative group cursor-pointer border-2 border-dashed border-slate-200 rounded-[32px] p-12 hover:border-indigo-400 hover:bg-indigo-50/30 transition-all text-center">
                    <input type="file" multiple accept="image/*" onChange={handleFileChange} className="absolute inset-0 opacity-0 cursor-pointer z-20" />
                    <Upload className="w-12 h-12 text-indigo-500 mx-auto mb-4 group-hover:-translate-y-1 transition-transform" />
                    <p className="text-slate-900 font-bold text-lg mb-1">Click to Upload</p>
                    <p className="text-slate-400 text-sm">Select up to 4 invoice images (JPG/PNG)</p>
                  </div>
                </div>

                <div className="bg-slate-50 rounded-3xl p-6 border border-slate-100">
                  <div className="flex items-center space-x-2 mb-4 text-slate-900">
                    <Settings2 className="w-4 h-4" />
                    <span className="text-xs font-black uppercase tracking-widest">Global Options</span>
                  </div>
                  <div className="space-y-5">
                    <Toggle 
                      label="Strict Validation" 
                      sub="Block invalid codes in EDI/PDF"
                      active={batch.strictMode} 
                      onClick={() => setBatch(prev => ({...prev, strictMode: !prev.strictMode}))} 
                    />
                    <Toggle 
                      label="Fallback Labels" 
                      sub="Use Code128 for unverified tags"
                      active={batch.allowCode128Fallback} 
                      onClick={() => setBatch(prev => ({...prev, allowCode128Fallback: !prev.allowCode128Fallback}))} 
                    />
                  </div>
                </div>
              </div>

              <div className="flex flex-col">
                <div className="flex items-center justify-between mb-6">
                  <h3 className="text-sm font-black text-slate-400 uppercase tracking-widest">Selected Batch ({batch.invoices.length}/4)</h3>
                </div>
                {batch.invoices.length === 0 ? (
                  <div className="flex-1 flex flex-col items-center justify-center bg-slate-50 border border-slate-100 rounded-[32px] p-12 text-slate-300">
                    <LayoutGrid className="w-16 h-16 mb-4 opacity-20" />
                    <p className="font-bold text-slate-400">Queue is currently empty</p>
