                ) : (
                  <div className="flex-1 space-y-4 overflow-y-auto max-h-[450px] pr-2 scrollbar-thin">
                    {batch.invoices.map(inv => (
                      <div key={inv.id} className="flex items-center justify-between p-4 bg-white border border-slate-200 rounded-2xl shadow-sm hover:shadow-md transition-shadow group">
                        <div className="flex items-center space-x-4">
                          <img src={inv.previewUrl} className="w-14 h-14 rounded-xl object-cover border border-slate-100" />
                          <div className="min-w-0">
                            <p className="text-sm font-bold text-slate-900 truncate max-w-[150px]">{inv.file.name}</p>
                            <p className="text-[10px] font-black text-slate-400 uppercase">{(inv.file.size / 1024).toFixed(1)} KB</p>
