                        </button>
                      </div>
                    ))}
                    <button 
                      onClick={startProcessing}
                      className="w-full mt-6 bg-slate-900 hover:bg-black text-white font-black py-5 rounded-[24px] shadow-2xl shadow-slate-200 flex items-center justify-center group active:scale-[0.98] transition-all"
