            <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-4">Supplier Segments</h4>
            <div className="space-y-2">
              <SidebarItem 
                label="All Transmissions" 
                count={batch.invoices.length} 
                active={!filterSeller} 
                onClick={() => setFilterSeller(null)} 
              />
              {sellers.map(s => (
                <SidebarItem 
                  key={s} 
                  label={s} 
                  count={batch.invoices.filter(i => i.sellerName === s).length} 
