              <button 
                onClick={downloadAllPDFs}
                className="w-full flex items-center p-4 text-sm text-slate-700 font-bold hover:bg-slate-50 rounded-2xl transition-all border border-transparent hover:border-slate-100 group"
              >
                <FileCheck className="w-4 h-4 mr-4 text-slate-400 group-hover:text-indigo-600" />
                Download All PDFs
              </button>
            </div>
          </div>
        </div>

        <button 
          onClick={() => setStep('UPLOAD')}
          className="mt-8 flex items-center justify-center p-5 bg-slate-900 text-white rounded-[24px] font-black text-sm shadow-2xl shadow-slate-200 hover:bg-black active:scale-[0.98] transition-all"
        >
          New Batch Run
        </button>
      </aside>

      <main className="flex-1 p-16 max-w-6xl mx-auto">
        <div className="flex items-center justify-between mb-12">
          <div>
            <h2 className="text-4xl font-black text-slate-900 tracking-tight">
              {filterSeller || 'Batch Inventory'}
            </h2>
            <p className="text-slate-400 font-bold mt-1">Reviewing verified extraction results</p>
          </div>
          <div className="flex items-center space-x-4">
             <div className="flex items-center space-x-2 text-[10px] font-black text-slate-500 bg-white px-5 py-2.5 rounded-full border border-slate-200 shadow-sm uppercase tracking-widest">
                <Search className="w-3.5 h-3.5" />
                <span>Total Matches: {filteredInvoices.length}</span>
             </div>
          </div>
        </div>

        <div className="space-y-8">
          {filteredInvoices.map(inv => (
            <div key={inv.id} className="bg-white rounded-[40px] border border-slate-200 shadow-sm overflow-hidden hover:shadow-xl transition-all duration-300">
              <div 
                className="p-8 flex items-center justify-between cursor-pointer hover:bg-slate-50/50 transition-colors"
                onClick={() => setExpandedInvoice(expandedInvoice === inv.id ? null : inv.id)}
              >
                <div className="flex items-center space-x-6">
                  <div className="relative">
                    <img src={inv.previewUrl} className="w-20 h-20 rounded-[24px] object-cover shadow-inner border border-slate-100 group-hover:scale-105 transition-transform" />
                    {inv.status === 'NEEDS_REVIEW' && (
                      <div className="absolute -top-1 -right-1 bg-amber-500 text-white p-1 rounded-full shadow-lg">
                        <AlertCircle className="w-3.5 h-3.5" />
                      </div>
                    )}
                  </div>
                  <div>
                    <h3 className="text-lg font-black text-slate-900 tracking-tight leading-none mb-2">{inv.data?.invoice_number || 'UNKNOWN INVOICE'}</h3>
                    <p className="text-xs font-bold text-slate-400 uppercase tracking-wider">{inv.sellerName} &bull; {inv.data?.invoice_date || 'N/A'}</p>
                  </div>
                </div>

                <div className="flex items-center space-x-12">
                  <div className="text-right">
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Settlement</p>
                    <p className="text-lg font-black text-slate-900">${inv.data?.totals.total?.toLocaleString() || '0.00'}</p>
                  </div>
                  <div className={`px-5 py-2 rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-sm border ${
                    inv.status === 'DONE' ? 'bg-emerald-50 text-emerald-700 border-emerald-100' :
                    inv.status === 'NEEDS_REVIEW' ? 'bg-amber-50 text-amber-700 border-amber-100' : 'bg-red-50 text-red-700 border-red-100'
                  }`}>
                    {inv.status.replace('_', ' ')}
                  </div>
                  <div className="bg-slate-100 p-2 rounded-full text-slate-400">
                    {expandedInvoice === inv.id ? <ChevronUp className="w-5 h-5" /> : <ChevronDown className="w-5 h-5" />}
                  </div>
                </div>
              </div>

              {expandedInvoice === inv.id && (
                <div className="border-t border-slate-100 animate-in fade-in slide-in-from-top-4 duration-500 bg-white">
                  <InvoiceTabs 
                    inv={inv} 
                    onEditItem={handleEditItem}
                    onRegenerate={regenerate}
                    strictMode={batch.strictMode}
                  />
                </div>
              )}
            </div>
          ))}
        </div>
      </main>
    </div>
  );
};

const SidebarItem: React.FC<{ label: string, count: number, active: boolean, onClick: () => void }> = ({ label, count, active, onClick }) => (
  <button 
    onClick={onClick}
    className={`w-full flex items-center justify-between p-4 rounded-2xl text-xs font-black uppercase tracking-widest transition-all ${active ? 'bg-slate-900 text-white shadow-xl' : 'text-slate-500 hover:bg-slate-50'}`}
  >
    <span className="truncate pr-4">{label}</span>
    <span className={`px-2.5 py-1 rounded-lg border ${active ? 'bg-white/10 border-white/20 text-white' : 'bg-slate-50 border-slate-200 text-slate-400'}`}>
      {count}
    </span>
  </button>
);

const Toggle: React.FC<{ label: string, sub: string, active: boolean, onClick: () => void }> = ({ label, sub, active, onClick }) => (
  <div className="flex items-center justify-between group">
    <div className="cursor-pointer" onClick={onClick}>
      <p className="text-sm font-black text-slate-900 tracking-tight group-hover:text-indigo-600 transition-colors">{label}</p>
      <p className="text-[10px] font-bold text-slate-400">{sub}</p>
    </div>
    <button 
      onClick={onClick}
      className={`w-12 h-6 rounded-full transition-all duration-300 relative ${active ? 'bg-indigo-600 shadow-lg shadow-indigo-100' : 'bg-slate-200 shadow-inner'}`}
    >
      <div className={`absolute top-1 w-4 h-4 bg-white rounded-full transition-transform duration-300 shadow-sm ${active ? 'translate-x-7' : 'translate-x-1'}`} />
    </button>
  </div>
);

const InvoiceTabs: React.FC<{ 
  inv: InvoiceState, 
  onEditItem: (id: string, idx: number, f: keyof LineItem, v: any) => void,
  onRegenerate: (id: string) => void,
  strictMode: boolean
}> = ({ inv, onEditItem, onRegenerate, strictMode }) => {
  const [tab, setTab] = useState<'EDI' | 'BARCODE' | 'EDIT'>('EDIT');
  const [copied, setCopied] = useState(false);

  const handleCopy = () => {
    navigator.clipboard.writeText(inv.ediText);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleDownloadEDI = () => {
    const blob = new Blob([inv.ediText], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `EDI_${inv.id}_${inv.data?.invoice_number || 'export'}.edi`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleDownloadPDF = () => {
    if (inv.pdfBlobUrl) {
      const a = document.createElement('a');
      a.href = inv.pdfBlobUrl;
      a.download = `Labels_${inv.id}_${inv.data?.invoice_number || 'export'}.pdf`;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
    }
  };

  return (
    <div>
      <div className="flex border-b border-slate-100 px-8 bg-slate-50/50">
        {[
          { id: 'EDIT', label: 'Quality Audit' },
          { id: 'EDI', label: 'EDI Document' },
          { id: 'BARCODE', label: 'Logistic Tags' }
        ].map(t => (
          <button 
            key={t.id}
            onClick={() => setTab(t.id as any)}
            className={`px-8 py-5 text-[10px] font-black uppercase tracking-[0.2em] transition-all relative ${tab === t.id ? 'text-indigo-600' : 'text-slate-400 hover:text-slate-900'}`}
          >
            {t.label}
            {tab === t.id && <div className="absolute bottom-0 left-8 right-8 h-1 bg-indigo-600 rounded-t-full shadow-lg shadow-indigo-100" />}
          </button>
        ))}
      </div>

      <div className="p-12">
        {tab === 'EDIT' && (
          <div className="space-y-10">
            <div className="flex items-center justify-between">
               <div>
                 <h4 className="text-sm font-black text-slate-900 uppercase tracking-widest">Line Item Verification</h4>
                 <p className="text-xs text-slate-400 mt-1">Review extracted codes and settlement amounts.</p>
               </div>
               <button 
                onClick={() => onRegenerate(inv.id)}
                className="flex items-center px-6 py-3 bg-indigo-600 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-indigo-700 shadow-xl shadow-indigo-100 active:scale-[0.98] transition-all"
               >
                 <RefreshCw className="w-3.5 h-3.5 mr-3" />
                 Re-sync Documents
               </button>
            </div>
            <div className="border border-slate-200 rounded-[32px] overflow-hidden shadow-sm">
              <table className="w-full text-left text-xs">
                <thead className="bg-slate-50 border-b border-slate-200">
                  <tr>
                    <th className="px-6 py-4 font-black text-slate-400 uppercase tracking-widest">Ln</th>
                    <th className="px-6 py-4 font-black text-slate-400 uppercase tracking-widest">Description</th>
                    <th className="px-6 py-4 font-black text-slate-400 uppercase tracking-widest">Qty</th>
                    <th className="px-6 py-4 font-black text-slate-400 uppercase tracking-widest">Unit Price</th>
                    <th className="px-6 py-4 font-black text-slate-400 uppercase tracking-widest">UPC/EAN Code</th>
                    <th className="px-6 py-4 font-black text-slate-400 uppercase tracking-widest">Integrity</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {inv.data?.line_items.map((item, idx) => (
                    <tr key={idx} className="hover:bg-slate-50/50 transition-colors">
                      <td className="px-6 py-5 text-slate-400 font-bold">{item.line_no}</td>
                      <td className="px-6 py-5">
                        <input 
                          value={item.description} 
                          onChange={(e) => onEditItem(inv.id, idx, 'description', e.target.value)}
                          className="bg-transparent border-none focus:ring-0 rounded p-0 w-full text-slate-900 font-bold"
                        />
                      </td>
                      <td className="px-6 py-5 w-24">
                        <input 
                          type="number"
                          value={item.qty || 0} 
                          onChange={(e) => onEditItem(inv.id, idx, 'qty', parseFloat(e.target.value))}
                          className="bg-slate-50 border border-slate-100 rounded-lg px-2 py-1 w-full font-bold"
                        />
                      </td>
                      <td className="px-6 py-5 w-28 font-mono">
                        <input 
                          type="number"
                          value={item.unit_price || 0} 
                          onChange={(e) => onEditItem(inv.id, idx, 'unit_price', parseFloat(e.target.value))}
                          className="bg-slate-50 border border-slate-100 rounded-lg px-2 py-1 w-full font-bold"
                        />
                      </td>
                      <td className="px-6 py-5">
                        <input 
                          value={item.code_value} 
                          onChange={(e) => onEditItem(inv.id, idx, 'code_value', e.target.value)}
                          className={`font-mono font-black bg-white border border-slate-200 rounded-lg px-3 py-1.5 w-full shadow-sm focus:ring-2 focus:ring-indigo-500 transition-all ${item.code_status === 'INVALID' ? 'text-red-600 border-red-200' : 'text-indigo-600 border-indigo-200'}`}
                        />
                      </td>
                      <td className="px-6 py-5">
                        <span className={`px-3 py-1.5 rounded-xl text-[9px] font-black uppercase tracking-[0.1em] border shadow-sm ${
                          item.code_status === 'VALID' ? 'bg-emerald-50 text-emerald-600 border-emerald-100' : 'bg-red-50 text-red-600 border-red-100'
                        }`}>
                          {item.code_status}
                        </span>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {tab === 'EDI' && (
          <div className="space-y-6">
            <div className="flex items-center justify-between">
               <div>
                 <h4 className="text-sm font-black text-slate-900 uppercase tracking-widest">EDI Content</h4>
                 <p className="text-xs text-slate-400 mt-1">X12 standard document ready for transmission.</p>
               </div>
               <div className="flex items-center space-x-3">
                 <button 
                  onClick={handleCopy}
                  className="flex items-center px-5 py-2.5 bg-slate-100 text-slate-700 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-slate-200 shadow-sm border border-slate-200 transition-all"
                 >
                   {copied ? <Check className="w-3.5 h-3.5 mr-2 text-emerald-600" /> : <Copy className="w-3.5 h-3.5 mr-2" />}
                   {copied ? 'Copied' : 'Copy Text'}
                 </button>
                 <button 
                  onClick={handleDownloadEDI}
                  className="flex items-center px-5 py-2.5 bg-indigo-600 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-indigo-700 shadow-xl shadow-indigo-100 active:scale-[0.98] transition-all"
                 >
                   <Download className="w-3.5 h-3.5 mr-2" />
                   Download .edi
                 </button>
               </div>
            </div>
            <div className="bg-slate-950 rounded-[32px] p-10 font-mono text-xs text-emerald-400 leading-relaxed overflow-auto max-h-[500px] shadow-2xl border border-slate-800">
              {inv.ediText.split('~').map((seg, i) => (
                <div key={i} className="mb-2 hover:bg-white/5 p-1 rounded transition-colors group">
                  <span className="text-emerald-800 select-none mr-4">{(i+1).toString().padStart(3, '0')}</span>
                  {seg}<span className="text-emerald-700 opacity-50">~</span>
                </div>
              ))}
            </div>
          </div>
        )}

        {tab === 'BARCODE' && (
          <div className="space-y-8">
            <div className="flex items-center justify-between">
               <div>
                 <h4 className="text-sm font-black text-slate-900 uppercase tracking-widest">Retail Label Grid</h4>
                 <p className="text-xs text-slate-400 mt-1">Validated logistics stickers.</p>
               </div>
               <div className="flex items-center space-x-3">
                 <button 
                  onClick={handleDownloadPDF}
                  className="flex items-center px-5 py-2.5 bg-indigo-600 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-indigo-700 shadow-xl shadow-indigo-100 active:scale-[0.98] transition-all"
                 >
                   <Download className="w-3.5 h-3.5 mr-3" />
                   Download PDF
                 </button>
                 {inv.pdfBlobUrl && (
                   <a 
                    href={inv.pdfBlobUrl}
                    target="_blank"
                    className="text-xs font-black text-indigo-600 hover:text-indigo-800 flex items-center bg-indigo-50 px-5 py-2.5 rounded-2xl shadow-sm border border-indigo-100 transition-all"
                   >
                     <ExternalLink className="w-4 h-4 mr-3" />
                     Full View
                   </a>
                 )}
               </div>
            </div>
            {inv.pdfBlobUrl ? (
              <div className="aspect-[1/1.41] bg-slate-900 rounded-[40px] border-8 border-slate-900 overflow-hidden shadow-2xl flex items-center justify-center relative group">
                <iframe src={`${inv.pdfBlobUrl}#toolbar=0`} className="w-full h-full border-none" />
                <div className="absolute inset-0 pointer-events-none border-[32px] border-white/5 rounded-[32px]" />
              </div>
            ) : (
              <div className="h-96 bg-slate-50 border-4 border-dashed border-slate-100 rounded-[40px] flex flex-col items-center justify-center text-slate-400">
                <AlertCircle className="w-16 h-16 mb-6 opacity-20" />
                <p className="text-lg font-black tracking-tight text-slate-300">No label sheet available</p>
                <p className="text-xs font-bold mt-2">Check data integrity tab for code validation.</p>
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { ProcessingResult } from '../types';
import { 
  FileText, 
  Grid, 
  Clipboard, 
  Download, 
  AlertTriangle, 
  CheckCircle2, 
  ExternalLink,
  XCircle,
  Hash,
  ShoppingBag
} from 'lucide-react';

interface ResultsPanelProps {
  result: ProcessingResult;
  pdfBlob: Blob | null;
}

export const ResultsPanel: React.FC<ResultsPanelProps> = ({ result, pdfBlob }) => {
  const [activeTab, setActiveTab] = useState<'edi' | 'barcodes' | 'quality'>('edi');

  const formattedEdi = result.edi_810.replace(/~/g, '~\n');

  const copyToClipboard = () => {
    navigator.clipboard.writeText(result.edi_810);
    alert('Raw EDI text copied to clipboard!');
  };

  const downloadEdi = () => {
    const blob = new Blob([result.edi_810], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `invoice_${result.invoice.invoice_number || 'export'}.edi`;
    a.click();
  };

  const downloadPdf = () => {
    if (!pdfBlob) return;
    const url = URL.createObjectURL(pdfBlob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `labels_${result.invoice.invoice_number || 'export'}.pdf`;
    a.click();
