                      <XCircle className="w-4 h-4 mr-3 shrink-0" />
                      Missing: {f}
                    </div>
                  ))}
                  {result.warnings.map((w, i) => (
                    <div key={i} className="flex items-center p-3 bg-amber-50 text-amber-700 rounded-xl text-xs font-medium border border-amber-100">
                      <AlertTriangle className="w-4 h-4 mr-3 shrink-0" />
                      {w}
                    </div>
                  ))}
                  {result.missing_fields.length === 0 && result.warnings.length === 0 && (
                    <div className="flex items-center p-3 bg-emerald-50 text-emerald-700 rounded-xl text-xs font-medium border border-emerald-100">
                      <CheckCircle2 className="w-4 h-4 mr-3 shrink-0" />
                      Validation successful. No issues found.
                    </div>
                  )}
                </div>
              </div>

              {/* Core Details */}
              <div className="space-y-4">
                <h4 className="text-xs font-bold text-slate-400 uppercase tracking-widest">Entity Facts</h4>
                <div className="bg-slate-50 p-6 rounded-2xl border border-slate-200 space-y-4">
                  <div className="flex justify-between items-start">
                    <div className="text-[10px] font-bold text-slate-400 uppercase">Seller</div>
                    <div className="text-right text-sm font-bold text-slate-900">{result.invoice.seller.name || 'Unknown'}</div>
                  </div>
                  <div className="flex justify-between items-start border-t border-slate-200 pt-3">
                    <div className="text-[10px] font-bold text-slate-400 uppercase">Buyer</div>
                    <div className="text-right text-sm font-bold text-slate-900">{result.invoice.buyer.name || 'Unknown'}</div>
                  </div>
                  <div className="flex justify-between items-start border-t border-slate-200 pt-3">
                    <div className="text-[10px] font-bold text-slate-400 uppercase">Invoice #</div>
                    <div className="text-right text-sm font-bold text-indigo-600 font-mono">{result.invoice.invoice_number || 'N/A'}</div>
                  </div>
                  <div className="flex justify-between items-start border-t border-slate-200 pt-3">
                    <div className="text-[10px] font-bold text-slate-400 uppercase">Total Amount</div>
                    <div className="text-right text-lg font-black text-slate-900">
                      {result.invoice.currency} {result.invoice.totals.total?.toFixed(2) || '0.00'}
                    </div>
                  </div>
                </div>
              </div>
            </div>

            {/* Line Items Table */}
            <div className="mt-8">
              <h4 className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-4">Transaction Lines ({result.invoice.line_items.length})</h4>
              <div className="bg-white border border-slate-200 rounded-2xl overflow-hidden overflow-x-auto">
                <table className="w-full text-left text-xs border-collapse">
                  <thead className="bg-slate-50 border-b border-slate-200">
                    <tr>
                      <th className="px-4 py-3 font-bold text-slate-500">Ln</th>
                      <th className="px-4 py-3 font-bold text-slate-500">Description</th>
                      <th className="px-4 py-3 font-bold text-slate-500">Qty</th>
                      <th className="px-4 py-3 font-bold text-slate-500">Price</th>
                      <th className="px-4 py-3 font-bold text-slate-500">UPC</th>
                      <th className="px-4 py-3 font-bold text-slate-500 text-right">Ext</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-100">
                    {result.invoice.line_items.map((item, i) => (
                      <tr key={i} className="hover:bg-slate-50 transition-colors">
                        <td className="px-4 py-3 font-medium text-slate-400">{item.line_no}</td>
                        <td className="px-4 py-3 text-slate-900">{item.description}</td>
                        <td className="px-4 py-3 text-slate-600">{item.qty} {item.uom}</td>
                        <td className="px-4 py-3 font-mono text-slate-500">${item.unit_price?.toFixed(2)}</td>
                        {/* Fix: Property 'upc' does not exist on type 'LineItem'. Using 'code_value' instead. */}
                        <td className="px-4 py-3 font-mono text-indigo-500 font-bold">{item.code_value || '-'}</td>
                        <td className="px-4 py-3 font-bold text-slate-900 text-right">${item.line_total?.toFixed(2)}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { 
  Upload, 
  Layers, 
  FileCheck, 
  Loader2, 
  ChevronRight, 
  AlertCircle, 
  CheckCircle, 
  Trash2,
  Filter,
  Download,
  Edit2,
  RefreshCw,
  ChevronDown,
  ChevronUp,
  Search,
  ExternalLink,
  Package,
  Settings2,
  FileDigit,
  LayoutGrid,
  Copy,
  Check
} from 'lucide-react';
import { 
  AppStep, 
  BatchState, 
  InvoiceState, 
  InvoiceData, 
  LineItem 
} from './types';
import { validateCode } from './services/validationService';
import { extractInvoiceWithGemini } from './services/geminiService';
import { generateEDI810 } from './services/ediService';
import { generateLabelPDF } from './services/pdfService';
import { preprocessForOCR } from './services/imagePreprocessor';
import { performFullOCR, performRegionOCR } from './services/ocrService';

const App: React.FC = () => {
  const [step, setStep] = useState<AppStep>('UPLOAD');
  const [batch, setBatch] = useState<BatchState>({
    name: 'Batch_' + new Date().toISOString().slice(0, 10),
    strictMode: true,
    allowCode128Fallback: false,
    invoices: []
  });

  const [filterSeller, setFilterSeller] = useState<string | null>(null);
  const [expandedInvoice, setExpandedInvoice] = useState<string | null>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!e.target.files) return;
    const newFiles = Array.from(e.target.files).slice(0, 4 - batch.invoices.length);
    const newInvoices: InvoiceState[] = newFiles.map(file => ({
      id: Math.random().toString(36).substring(7),
      file,
      previewUrl: URL.createObjectURL(file),
      status: 'QUEUED',
      progress: 0,
      currentTask: 'Waiting...',
      sellerName: 'Pending...',
      ocrFullText: '',
      ocrUpcText: '',
      data: null,
      missing_fields: [],
      warnings: [],
      ediText: '',
      pdfBlobUrl: null
    }));
    setBatch(prev => ({ ...prev, invoices: [...prev.invoices, ...newInvoices] }));
  };

  const removeInvoice = (id: string) => {
    setBatch(prev => ({ 
      ...prev, 
      invoices: prev.invoices.filter(inv => inv.id !== id) 
    }));
  };

  const startProcessing = async () => {
    setStep('PROCESSING');

    const updatedInvoices = [...batch.invoices];

    for (let i = 0; i < updatedInvoices.length; i++) {
      let inv = updatedInvoices[i];
      if (inv.status === 'DONE' || inv.status === 'NEEDS_REVIEW') continue;

      updateInvoice(inv.id, { status: 'RUNNING', progress: 5, currentTask: 'Preprocessing image...' });

      try {
        const preprocessedUrl = await preprocessForOCR(inv.file);

        updateInvoice(inv.id, { currentTask: 'OCR: Full Page Scan', progress: 20 });
        const fullText = await performFullOCR(preprocessedUrl);

        updateInvoice(inv.id, { currentTask: 'OCR: Analyzing UPC Column', progress: 40 });
        const upcText = await performRegionOCR(preprocessedUrl);

        updateInvoice(inv.id, { currentTask: 'AI Understanding Invoice...', progress: 65 });
        const invoiceData = await extractInvoiceWithGemini(inv.file, fullText, upcText);

        updateInvoice(inv.id, { currentTask: 'Building EDI & Label Sheet...', progress: 85 });

        const validatedItems = invoiceData.line_items.map(item => {
          const v = validateCode(item.code_value);
          return { ...item, code_status: v.isValid ? 'VALID' : 'INVALID' };
        }) as LineItem[];

        invoiceData.line_items = validatedItems;
        const edi = generateEDI810(invoiceData, batch.strictMode);
        const pdfBlob = await generateLabelPDF(invoiceData, batch.strictMode, batch.allowCode128Fallback);
        const pdfUrl = URL.createObjectURL(pdfBlob);

        const hasInvalid = invoiceData.line_items.some(it => it.code_status === 'INVALID');
        const needsReview = hasInvalid || invoiceData.invoice_number === '' || !invoiceData.totals.total;

        updateInvoice(inv.id, { 
          status: needsReview ? 'NEEDS_REVIEW' : 'DONE',
          progress: 100,
          currentTask: 'Processing complete',
          sellerName: invoiceData.seller.name || 'Unknown Vendor',
          ocrFullText: fullText,
          ocrUpcText: upcText,
          data: invoiceData,
          ediText: edi,
          pdfBlobUrl: pdfUrl
        });

      } catch (err: any) {
        updateInvoice(inv.id, { status: 'ERROR', error: err.message, currentTask: 'Failed' });
      }
    }

    // AUTOMATIC TRANSITION TO RESULTS
    setTimeout(() => {
      setStep('RESULTS');
    }, 1500);
  };

  const updateInvoice = (id: string, updates: Partial<InvoiceState>) => {
    setBatch(prev => ({
      ...prev,
      invoices: prev.invoices.map(inv => inv.id === id ? { ...inv, ...updates } : inv)
    }));
  };

  const handleEditItem = (invId: string, lineIndex: number, field: keyof LineItem, value: any) => {
    setBatch(prev => {
      const inv = prev.invoices.find(i => i.id === invId);
      if (!inv || !inv.data) return prev;
      const newItems = [...inv.data.line_items];
      newItems[lineIndex] = { ...newItems[lineIndex], [field]: value };
      if (field === 'code_value') {
        const v = validateCode(value);
        newItems[lineIndex].code_status = v.isValid ? 'VALID' : 'INVALID';
      }
      const newData = { ...inv.data, line_items: newItems };
      return {
        ...prev,
        invoices: prev.invoices.map(i => i.id === invId ? { ...i, data: newData } : i)
      };
    });
  };

  const regenerate = async (invId: string) => {
    const inv = batch.invoices.find(i => i.id === invId);
    if (!inv || !inv.data) return;

    const validatedItems = inv.data.line_items.map(item => {
      const v = validateCode(item.code_value);
      return { ...item, code_status: v.isValid ? 'VALID' : 'INVALID' };
    }) as LineItem[];

    const newData = { ...inv.data, line_items: validatedItems };
    const edi = generateEDI810(newData, batch.strictMode);
    const pdfBlob = await generateLabelPDF(newData, batch.strictMode, batch.allowCode128Fallback);
    const pdfUrl = URL.createObjectURL(pdfBlob);

    updateInvoice(invId, {
      data: newData,
      ediText: edi,
      pdfBlobUrl: pdfUrl,
      status: newData.line_items.some(it => it.code_status === 'INVALID') ? 'NEEDS_REVIEW' : 'DONE'
    });
  };

  const downloadAllEDI = () => {
    batch.invoices.forEach(inv => {
      if (inv.ediText) {
        const blob = new Blob([inv.ediText], { type: 'text/plain' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `EDI_${inv.data?.invoice_number || inv.id}.edi`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
      }
    });
  };

  const downloadAllPDFs = () => {
    batch.invoices.forEach(inv => {
      if (inv.pdfBlobUrl) {
        const a = document.createElement('a');
        a.href = inv.pdfBlobUrl;
        a.download = `Labels_${inv.data?.invoice_number || inv.id}.pdf`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
      }
    });
  };

  const sellers = Array.from(new Set(batch.invoices.map(inv => inv.sellerName).filter(s => s !== 'Pending...')));
  const filteredInvoices = batch.invoices.filter(inv => !filterSeller || inv.sellerName === filterSeller);

  if (step === 'UPLOAD') {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-8">
        <div className="max-w-4xl w-full">
          <header className="mb-12 text-center">
            <div className="inline-flex items-center space-x-2 bg-indigo-600 text-white px-4 py-1.5 rounded-full text-xs font-bold mb-6 shadow-lg shadow-indigo-100 uppercase tracking-widest">
              <FileDigit className="w-4 h-4" />
              <span>Version 2.0 Enterprise</span>
            </div>
            <h1 className="text-5xl font-black text-slate-900 mb-4 tracking-tight">Invoice Batch Processor</h1>
            <p className="text-slate-500 text-lg max-w-2xl mx-auto font-medium leading-relaxed">
              Automated EDI document generation and retail label creation for logistics teams.
            </p>
          </header>

          <div className="bg-white rounded-[40px] shadow-2xl border border-slate-200 p-12 overflow-hidden relative">
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-16 relative z-10">
              <div className="space-y-8">
                <div className="space-y-4">
                  <label className="text-sm font-bold text-slate-900 block ml-1 uppercase tracking-wider">Batch Identity</label>
                  <input 
                    type="text" 
                    value={batch.name} 
                    onChange={e => setBatch(prev => ({...prev, name: e.target.value}))}
                    className="w-full bg-slate-100 border-none rounded-2xl px-6 py-4 font-bold text-slate-700 focus:ring-2 focus:ring-indigo-500 transition-all shadow-inner"
                  />
                </div>

                <div className="space-y-4">
                  <label className="text-sm font-bold text-slate-900 block ml-1 uppercase tracking-wider">Add Documents</label>
                  <div className="relative group cursor-pointer border-2 border-dashed border-slate-200 rounded-[32px] p-12 hover:border-indigo-400 hover:bg-indigo-50/30 transition-all text-center">
                    <input type="file" multiple accept="image/*" onChange={handleFileChange} className="absolute inset-0 opacity-0 cursor-pointer z-20" />
                    <Upload className="w-12 h-12 text-indigo-500 mx-auto mb-4 group-hover:-translate-y-1 transition-transform" />
                    <p className="text-slate-900 font-bold text-lg mb-1">Click to Upload</p>
                    <p className="text-slate-400 text-sm">Select up to 4 invoice images (JPG/PNG)</p>
                  </div>
                </div>

                <div className="bg-slate-50 rounded-3xl p-6 border border-slate-100">
                  <div className="flex items-center space-x-2 mb-4 text-slate-900">
                    <Settings2 className="w-4 h-4" />
                    <span className="text-xs font-black uppercase tracking-widest">Global Options</span>
                  </div>
                  <div className="space-y-5">
                    <Toggle 
                      label="Strict Validation" 
                      sub="Block invalid codes in EDI/PDF"
                      active={batch.strictMode} 
                      onClick={() => setBatch(prev => ({...prev, strictMode: !prev.strictMode}))} 
                    />
                    <Toggle 
                      label="Fallback Labels" 
                      sub="Use Code128 for unverified tags"
                      active={batch.allowCode128Fallback} 
                      onClick={() => setBatch(prev => ({...prev, allowCode128Fallback: !prev.allowCode128Fallback}))} 
                    />
                  </div>
                </div>
              </div>

              <div className="flex flex-col">
                <div className="flex items-center justify-between mb-6">
                  <h3 className="text-sm font-black text-slate-400 uppercase tracking-widest">Selected Batch ({batch.invoices.length}/4)</h3>
                </div>
                {batch.invoices.length === 0 ? (
                  <div className="flex-1 flex flex-col items-center justify-center bg-slate-50 border border-slate-100 rounded-[32px] p-12 text-slate-300">
                    <LayoutGrid className="w-16 h-16 mb-4 opacity-20" />
                    <p className="font-bold text-slate-400">Queue is currently empty</p>
                  </div>
                ) : (
                  <div className="flex-1 space-y-4 overflow-y-auto max-h-[450px] pr-2 scrollbar-thin">
                    {batch.invoices.map(inv => (
                      <div key={inv.id} className="flex items-center justify-between p-4 bg-white border border-slate-200 rounded-2xl shadow-sm hover:shadow-md transition-shadow group">
                        <div className="flex items-center space-x-4">
                          <img src={inv.previewUrl} className="w-14 h-14 rounded-xl object-cover border border-slate-100" />
                          <div className="min-w-0">
                            <p className="text-sm font-bold text-slate-900 truncate max-w-[150px]">{inv.file.name}</p>
                            <p className="text-[10px] font-black text-slate-400 uppercase">{(inv.file.size / 1024).toFixed(1)} KB</p>
                          </div>
                        </div>
                        <button onClick={() => removeInvoice(inv.id)} className="p-2 text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-xl transition-all">
                          <Trash2 className="w-5 h-5" />
                        </button>
                      </div>
                    ))}
                    <button 
                      onClick={startProcessing}
                      className="w-full mt-6 bg-slate-900 hover:bg-black text-white font-black py-5 rounded-[24px] shadow-2xl shadow-slate-200 flex items-center justify-center group active:scale-[0.98] transition-all"
                    >
                      Process Entire Batch
                      <ChevronRight className="ml-2 w-5 h-5 group-hover:translate-x-1 transition-transform" />
                    </button>
                  </div>
                )}
              </div>
            </div>
            <div className="absolute top-0 right-0 w-64 h-64 bg-indigo-50/50 rounded-full blur-[100px] -mr-32 -mt-32 pointer-events-none" />
          </div>
        </div>
      </div>
    );
  }

  if (step === 'PROCESSING') {
    const isDone = batch.invoices.every(inv => ['DONE', 'NEEDS_REVIEW', 'ERROR'].includes(inv.status));
    const processedCount = batch.invoices.filter(i => ['DONE', 'NEEDS_REVIEW'].includes(i.status)).length;

    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-8">
        <div className="max-w-3xl w-full bg-white rounded-[40px] shadow-2xl border border-slate-200 p-12 text-center">
          <div className="flex items-center justify-center mb-8">
            <div className="bg-indigo-50 p-6 rounded-full animate-pulse">
              <Loader2 className="w-12 h-12 text-indigo-600 animate-spin" />
            </div>
          </div>
          <h2 className="text-3xl font-black text-slate-900 mb-2">Processing Batch</h2>
          <p className="text-slate-500 font-bold mb-12 uppercase tracking-widest text-xs">Pipeline: OCR &rarr; AI Extraction &rarr; EDI Build</p>

          <div className="space-y-6 text-left">
            {batch.invoices.map(inv => (
              <div key={inv.id} className="p-6 border border-slate-100 rounded-3xl bg-slate-50/50">
                <div className="flex items-center justify-between mb-4">
                  <div className="flex items-center space-x-4">
                    <img src={inv.previewUrl} className="w-12 h-12 rounded-xl object-cover border border-slate-200 shadow-sm" />
                    <div>
                      <h4 className="text-xs font-black text-slate-900 uppercase tracking-tight truncate max-w-[200px]">{inv.file.name}</h4>
                      <p className="text-[10px] font-bold text-slate-400 mt-1">{inv.currentTask}</p>
                    </div>
                  </div>
                  <div className={`px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-wider border shadow-sm ${
                    inv.status === 'DONE' ? 'bg-emerald-50 text-emerald-700 border-emerald-100' :
                    inv.status === 'RUNNING' ? 'bg-indigo-50 text-indigo-700 border-indigo-100' :
                    inv.status === 'NEEDS_REVIEW' ? 'bg-amber-50 text-amber-700 border-amber-100' :
                    inv.status === 'ERROR' ? 'bg-red-50 text-red-700 border-red-100' : 'bg-slate-100 text-slate-400 border-slate-200'
                  }`}>
                    {inv.status.replace('_', ' ')}
                  </div>
                </div>
                <div className="h-2.5 bg-slate-200 rounded-full overflow-hidden shadow-inner">
                  <div 
                    className="h-full bg-gradient-to-r from-indigo-600 to-violet-600 transition-all duration-700" 
                    style={{ width: `${inv.progress}%` }} 
                  />
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex bg-slate-50">
      {/* Sidebar */}
      <aside className="w-80 bg-white border-r border-slate-200 sticky top-0 h-screen p-8 flex flex-col shadow-lg z-10">
        <div className="flex items-center space-x-4 mb-12">
          <div className="bg-slate-900 p-3 rounded-2xl text-white shadow-xl">
            <Package className="w-6 h-6" />
          </div>
          <span className="font-black text-xl text-slate-900 tracking-tight">Summary</span>
        </div>

        <div className="flex-1 space-y-12 overflow-y-auto pr-2 scrollbar-thin">
          <div className="space-y-4">
            <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-4">Supplier Segments</h4>
            <div className="space-y-2">
              <SidebarItem label="All Documents" count={batch.invoices.length} active={!filterSeller} onClick={() => setFilterSeller(null)} />
              {sellers.map(s => (
                <SidebarItem key={s} label={s} count={batch.invoices.filter(i => i.sellerName === s).length} active={filterSeller === s} onClick={() => setFilterSeller(s)} />
              ))}
            </div>
          </div>

          <div className="space-y-4">
            <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-4">Quick Batch Actions</h4>
            <div className="space-y-2">
              <button onClick={downloadAllEDI} className="w-full flex items-center p-4 text-xs text-slate-700 font-black uppercase tracking-widest hover:bg-slate-50 rounded-2xl transition-all border border-transparent hover:border-slate-100 group">
                <Download className="w-4 h-4 mr-4 text-slate-400 group-hover:text-indigo-600" />
                Batch .EDI Download
              </button>
              <button onClick={downloadAllPDFs} className="w-full flex items-center p-4 text-xs text-slate-700 font-black uppercase tracking-widest hover:bg-slate-50 rounded-2xl transition-all border border-transparent hover:border-slate-100 group">
                <FileCheck className="w-4 h-4 mr-4 text-slate-400 group-hover:text-indigo-600" />
                Batch PDF Download
              </button>
            </div>
          </div>
        </div>

        <button onClick={() => setStep('UPLOAD')} className="mt-8 flex items-center justify-center p-5 bg-slate-900 text-white rounded-[24px] font-black text-sm shadow-2xl shadow-slate-200 hover:bg-black active:scale-[0.98] transition-all">
          New Processing Run
        </button>
      </aside>

      {/* Main Results */}
      <main className="flex-1 p-16 max-w-6xl mx-auto">
        <header className="mb-12">
          <h2 className="text-4xl font-black text-slate-900 tracking-tight">{filterSeller || 'Batch Inventory'}</h2>
          <p className="text-slate-400 font-bold mt-1">Reviewing verified extraction results</p>
        </header>

        <div className="space-y-8">
          {filteredInvoices.map(inv => (
            <div key={inv.id} className="bg-white rounded-[40px] border border-slate-200 shadow-sm overflow-hidden hover:shadow-xl transition-all duration-300">
              <div 
                className="p-8 flex items-center justify-between cursor-pointer hover:bg-slate-50/50 transition-colors"
                onClick={() => setExpandedInvoice(expandedInvoice === inv.id ? null : inv.id)}
              >
                <div className="flex items-center space-x-6">
                  <div className="relative group">
                    <img src={inv.previewUrl} className="w-20 h-20 rounded-[24px] object-cover shadow-inner border border-slate-100 group-hover:scale-105 transition-transform" />
                    {inv.status === 'NEEDS_REVIEW' && (
                      <div className="absolute -top-1 -right-1 bg-amber-500 text-white p-1 rounded-full shadow-lg border-2 border-white">
                        <AlertCircle className="w-3.5 h-3.5" />
                      </div>
                    )}
                  </div>
                  <div>
                    <h3 className="text-lg font-black text-slate-900 tracking-tight leading-none mb-2">{inv.data?.invoice_number || 'PENDING IDENTITY'}</h3>
                    <p className="text-xs font-bold text-slate-400 uppercase tracking-wider">{inv.sellerName} &bull; {inv.data?.invoice_date || 'N/A'}</p>
                  </div>
                </div>

