import { preprocessForOCR } from './services/imagePreprocessor';
import { performFullOCR, performRegionOCR } from './services/ocrService';

const App: React.FC = () => {
  const [step, setStep] = useState<AppStep>('UPLOAD');
  const [batch, setBatch] = useState<BatchState>({
    name: 'Batch_' + new Date().toISOString().slice(0, 10),
    strictMode: true,
    allowCode128Fallback: false,
    invoices: []
  });

  const [filterSeller, setFilterSeller] = useState<string | null>(null);
  const [expandedInvoice, setExpandedInvoice] = useState<string | null>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!e.target.files) return;
    const newFiles = Array.from(e.target.files).slice(0, 4 - batch.invoices.length);
    const newInvoices: InvoiceState[] = newFiles.map(file => ({
      id: Math.random().toString(36).substring(7),
      file,
      previewUrl: URL.createObjectURL(file),
      status: 'QUEUED',
      progress: 0,
      currentTask: 'Waiting...',
      sellerName: 'Pending...',
      ocrFullText: '',
      ocrUpcText: '',
      data: null,
      missing_fields: [],
      warnings: [],
      ediText: '',
      pdfBlobUrl: null
    }));
    setBatch(prev => ({ ...prev, invoices: [...prev.invoices, ...newInvoices] }));
  };

  const removeInvoice = (id: string) => {
    setBatch(prev => ({ 
      ...prev, 
      invoices: prev.invoices.filter(inv => inv.id !== id) 
    }));
  };

  const startProcessing = async () => {
    setStep('PROCESSING');

    for (let i = 0; i < batch.invoices.length; i++) {
      let inv = batch.invoices[i];
      if (inv.status === 'DONE' || inv.status === 'NEEDS_REVIEW') continue;

      updateInvoice(inv.id, { status: 'RUNNING', progress: 5, currentTask: 'Analyzing Document...' });

      try {
        const preprocessedUrl = await preprocessForOCR(inv.file);

        updateInvoice(inv.id, { currentTask: 'OCR Processing...', progress: 30 });
        const fullText = await performFullOCR(preprocessedUrl);
        const upcText = await performRegionOCR(preprocessedUrl);

        updateInvoice(inv.id, { currentTask: 'AI Extraction...', progress: 60 });
        const invoiceData = await extractInvoiceWithGemini(inv.file, fullText, upcText);

        // Initial Validation
        const validatedItems = invoiceData.line_items.map(item => {
          const v = validateCode(item.code_value);
          return { ...item, code_status: v.isValid ? 'VALID' : 'INVALID' };
        }) as LineItem[];

        invoiceData.line_items = validatedItems;
        const edi = generateEDI810(invoiceData, batch.strictMode);
        const pdfBlob = await generateLabelPDF(invoiceData, batch.strictMode, batch.allowCode128Fallback);
        const pdfUrl = URL.createObjectURL(pdfBlob);

        const hasInvalid = invoiceData.line_items.some(it => it.code_status === 'INVALID');
        const needsReview = hasInvalid || !invoiceData.invoice_number || !invoiceData.totals.total;

        updateInvoice(inv.id, { 
          status: needsReview ? 'NEEDS_REVIEW' : 'DONE',
          progress: 100,
          currentTask: 'Complete',
          sellerName: invoiceData.seller.name || 'Unknown Vendor',
          ocrFullText: fullText,
          ocrUpcText: upcText,
          data: invoiceData,
          ediText: edi,
          pdfBlobUrl: pdfUrl
        });

      } catch (err: any) {
        updateInvoice(inv.id, { status: 'ERROR', error: err.message, currentTask: 'Failed' });
      }
    }

    // AUTOMATIC REDIRECT
    setTimeout(() => {
      setStep('RESULTS');
    }, 1200);
  };

  const updateInvoice = (id: string, updates: Partial<InvoiceState>) => {
    setBatch(prev => ({
      ...prev,
      invoices: prev.invoices.map(inv => inv.id === id ? { ...inv, ...updates } : inv)
    }));
  };

