import { GoogleGenAI, Type } from "@google/genai";
import { InvoiceData } from "../types";

export const extractInvoiceWithGemini = async (
  file: File,
  ocrFull: string,
  ocrUpc: string
): Promise<InvoiceData> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const base64 = await new Promise<string>((resolve) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => resolve((reader.result as string).split(',')[1]);
  });

  const systemInstruction = `
    You are a logistics-grade EDI architect. Extract invoice data into valid JSON with 100% spelling precision.

    STRICT DATA RULES:
    1. SELLER vs BUYER: Seller is the main provider. Buyer is the Bill-To/Ship-To customer.
    2. CITY NAMES: Ensure absolute accuracy for N4 segments. (Example: 'NORTH RIDGEVILLE', not 'NORTH RIDGEVILL'). 
    3. PRODUCT CODES: Link items to the UPC/EAN column precisely. 
    4. UOM: Default to 'CA' (Case) for bulk beverage/food invoices unless 'EA' is explicit.
    5. TOTALS: Subtotal + Tax + Shipping - Discount = Total. 

    Return ONLY VALID JSON. DO NOT INCLUDE MARKDOWN BLOCKS.
  `;

  const prompt = `
    Analyze this invoice image. Use the OCR text as context but rely on visual evidence.
    Full OCR context: ${ocrFull}
    Heuristic UPC context: ${ocrUpc}

    Structure:
    {
      "invoice": {
        "invoice_number": "string",
        "invoice_date": "YYYY-MM-DD",
        "seller": {"name": "string", "address": "string", "city": "string", "state": "string", "zip": "string"},
        "buyer": {"name": "string", "address": "string", "city": "string", "state": "string", "zip": "string"},
        "po_number": "string",
        "currency": "USD",
        "totals": {"subtotal": number, "tax": number, "discount": number, "total": number},
        "line_items": [
          {"line_no": number, "description": "string", "qty": number, "uom": "string", "unit_price": number, "line_total": number, "code_value": "string"}
        ]
      },
      "needs_review": boolean
    }
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { inlineData: { mimeType: file.type, data: base64 } },
        { text: prompt }
      ]
    },
    config: {
      systemInstruction,
      responseMimeType: "application/json"
    }
  });

  const parsed = JSON.parse(response.text);
  return parsed.invoice;
};

import React, { useState, useEffect } from 'react';
import { 
  Upload, 
  Layers, 
  FileCheck, 
  Loader2, 
  ChevronRight, 
  AlertCircle, 
  CheckCircle, 
  Trash2,
  Filter,
  Download,
  Edit2,
  RefreshCw,
  ChevronDown,
  ChevronUp,
  Search,
  ExternalLink,
  Package,
  Settings2,
  FileDigit,
  LayoutGrid,
  Copy,
  Check,
  RotateCcw
} from 'lucide-react';
import { 
  AppStep, 
  BatchState, 
  InvoiceState, 
  InvoiceData, 
  LineItem 
} from './types';
import { validateCode } from './services/validationService';
import { extractInvoiceWithGemini } from './services/geminiService';
import { generateEDI810 } from './services/ediService';
import { generateLabelPDF } from './services/pdfService';
import { preprocessForOCR } from './services/imagePreprocessor';
import { performFullOCR, performRegionOCR } from './services/ocrService';

const App: React.FC = () => {
  const [step, setStep] = useState<AppStep>('UPLOAD');
  const [batch, setBatch] = useState<BatchState>({
    name: 'Batch_' + new Date().toISOString().slice(0, 10),
    strictMode: true,
    allowCode128Fallback: false,
    invoices: []
  });

  const [filterSeller, setFilterSeller] = useState<string | null>(null);
  const [expandedInvoice, setExpandedInvoice] = useState<string | null>(null);

  const startOver = () => {
    // Cleanup memory
    batch.invoices.forEach(inv => {
      URL.revokeObjectURL(inv.previewUrl);
      if (inv.pdfBlobUrl) URL.revokeObjectURL(inv.pdfBlobUrl);
    });

    // Reset state
    setBatch({
      name: 'Batch_' + new Date().toISOString().slice(0, 10),
      strictMode: true,
      allowCode128Fallback: false,
      invoices: []
    });
    setFilterSeller(null);
    setExpandedInvoice(null);
    setStep('UPLOAD');
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!e.target.files) return;
    const newFiles = Array.from(e.target.files).slice(0, 4 - batch.invoices.length);
    const newInvoices: InvoiceState[] = newFiles.map(file => ({
      id: Math.random().toString(36).substring(7),
      file,
      previewUrl: URL.createObjectURL(file),
      status: 'QUEUED',
      progress: 0,
      currentTask: 'Waiting...',
      sellerName: 'Pending...',
      ocrFullText: '',
      ocrUpcText: '',
      data: null,
      missing_fields: [],
      warnings: [],
      ediText: '',
      pdfBlobUrl: null
    }));
    setBatch(prev => ({ ...prev, invoices: [...prev.invoices, ...newInvoices] }));
  };

  const removeInvoice = (id: string) => {
    setBatch(prev => {
      const inv = prev.invoices.find(i => i.id === id);
      if (inv) URL.revokeObjectURL(inv.previewUrl);
      return { 
        ...prev, 
        invoices: prev.invoices.filter(i => i.id !== id) 
      };
    });
  };

  const startProcessing = async () => {
    setStep('PROCESSING');

    for (let i = 0; i < batch.invoices.length; i++) {
      let inv = batch.invoices[i];
      if (inv.status === 'DONE' || inv.status === 'NEEDS_REVIEW') continue;

      updateInvoice(inv.id, { status: 'RUNNING', progress: 5, currentTask: 'Analyzing Document...' });

      try {
        const preprocessedUrl = await preprocessForOCR(inv.file);

        updateInvoice(inv.id, { currentTask: 'OCR Processing...', progress: 30 });
        const fullText = await performFullOCR(preprocessedUrl);
        const upcText = await performRegionOCR(preprocessedUrl);

        updateInvoice(inv.id, { currentTask: 'AI Extraction...', progress: 60 });
        const invoiceData = await extractInvoiceWithGemini(inv.file, fullText, upcText);

        // Initial Validation
        const validatedItems = invoiceData.line_items.map(item => {
          const v = validateCode(item.code_value);
          return { ...item, code_status: v.isValid ? 'VALID' : 'INVALID' };
        }) as LineItem[];

        invoiceData.line_items = validatedItems;
        const edi = generateEDI810(invoiceData, batch.strictMode);
        const pdfBlob = await generateLabelPDF(invoiceData, batch.strictMode, batch.allowCode128Fallback);
        const pdfUrl = URL.createObjectURL(pdfBlob);

        const hasInvalid = invoiceData.line_items.some(it => it.code_status === 'INVALID');
        const needsReview = hasInvalid || !invoiceData.invoice_number || !invoiceData.totals.total;

        updateInvoice(inv.id, { 
          status: needsReview ? 'NEEDS_REVIEW' : 'DONE',
          progress: 100,
          currentTask: 'Complete',
          sellerName: invoiceData.seller.name || 'Unknown Vendor',
          ocrFullText: fullText,
          ocrUpcText: upcText,
          data: invoiceData,
          ediText: edi,
          pdfBlobUrl: pdfUrl
        });

      } catch (err: any) {
        updateInvoice(inv.id, { status: 'ERROR', error: err.message, currentTask: 'Failed' });
      }
    }

    // AUTOMATIC REDIRECT
    setTimeout(() => {
      setStep('RESULTS');
    }, 1200);
  };

  const updateInvoice = (id: string, updates: Partial<InvoiceState>) => {
    setBatch(prev => ({
      ...prev,
      invoices: prev.invoices.map(inv => inv.id === id ? { ...inv, ...updates } : inv)
    }));
  };

  const handleEditItem = (invId: string, lineIndex: number, field: keyof LineItem, value: any) => {
    setBatch(prev => {
      const inv = prev.invoices.find(i => i.id === invId);
      if (!inv || !inv.data) return prev;
      const newItems = [...inv.data.line_items];
      newItems[lineIndex] = { ...newItems[lineIndex], [field]: value };

      if (field === 'code_value') {
        const v = validateCode(value);
        newItems[lineIndex].code_status = v.isValid ? 'VALID' : 'INVALID';
      }

      const newData = { ...inv.data, line_items: newItems };
      return {
        ...prev,
        invoices: prev.invoices.map(i => i.id === invId ? { ...i, data: newData } : i)
      };
    });
  };

  const regenerate = async (invId: string) => {
    const inv = batch.invoices.find(i => i.id === invId);
    if (!inv || !inv.data) return;

    const validatedItems = inv.data.line_items.map(item => {
      const v = validateCode(item.code_value);
      return { ...item, code_status: v.isValid ? 'VALID' : 'INVALID' };
    }) as LineItem[];

    const newData = { ...inv.data, line_items: validatedItems };
    const edi = generateEDI810(newData, batch.strictMode);
    const pdfBlob = await generateLabelPDF(newData, batch.strictMode, batch.allowCode128Fallback);
    const pdfUrl = URL.createObjectURL(pdfBlob);

    updateInvoice(invId, {
      data: newData,
      ediText: edi,
      pdfBlobUrl: pdfUrl,
      status: newData.line_items.some(it => it.code_status === 'INVALID') ? 'NEEDS_REVIEW' : 'DONE'
    });
  };

  const downloadAllEDI = () => {
    batch.invoices.forEach(inv => {
      if (inv.ediText) {
        const blob = new Blob([inv.ediText], { type: 'text/plain' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `EDI_${inv.data?.invoice_number || inv.id}.edi`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
      }
    });
  };

  const downloadAllPDFs = () => {
    batch.invoices.forEach(inv => {
      if (inv.pdfBlobUrl) {
        const a = document.createElement('a');
        a.href = inv.pdfBlobUrl;
        a.download = `Labels_${inv.data?.invoice_number || inv.id}.pdf`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
      }
    });
  };

  const sellers = Array.from(new Set(batch.invoices.map(inv => inv.sellerName).filter(s => s !== 'Pending...')));
  const filteredInvoices = batch.invoices.filter(inv => !filterSeller || inv.sellerName === filterSeller);

  if (step === 'UPLOAD') {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-8">
        <div className="max-w-4xl w-full">
          <header className="mb-12 text-center">
            <div className="inline-flex items-center space-x-2 bg-indigo-600 text-white px-4 py-1.5 rounded-full text-xs font-bold mb-6 shadow-lg uppercase tracking-widest">
              <FileDigit className="w-4 h-4" />
              <span>Version 2.2 Final</span>
            </div>
            <h1 className="text-5xl font-black text-slate-900 mb-4 tracking-tight">Invoice Batch Processor</h1>
            <p className="text-slate-500 text-lg max-w-2xl mx-auto font-medium">
              Automated EDI generation and logistic labeling for retail distribution.
            </p>
          </header>

          <div className="bg-white rounded-[40px] shadow-2xl border border-slate-200 p-12 overflow-hidden relative">
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-16 relative z-10">
              <div className="space-y-8">
                <div className="space-y-4">
                  <label className="text-sm font-bold text-slate-900 block ml-1 uppercase tracking-wider">Batch Identity</label>
                  <input 
                    type="text" 
                    value={batch.name} 
                    onChange={e => setBatch(prev => ({...prev, name: e.target.value}))}
                    className="w-full bg-slate-100 border-none rounded-2xl px-6 py-4 font-bold text-slate-700 focus:ring-2 focus:ring-indigo-500"
                  />
                </div>

                <div className="space-y-4">
                  <label className="text-sm font-bold text-slate-900 block ml-1 uppercase tracking-wider">Add Documents</label>
                  <div className="relative group cursor-pointer border-2 border-dashed border-slate-300 rounded-[32px] p-12 hover:border-indigo-400 hover:bg-indigo-50 transition-all text-center">
                    <input type="file" multiple accept="image/*" onChange={handleFileChange} className="absolute inset-0 opacity-0 cursor-pointer z-20" />
