}

import { CodeValidationResult } from '../types';

export const validateUPC = (code: string): boolean => {
  const clean = code.replace(/\s+/g, '');
  if (clean.length !== 12) return false;
  if (!/^\d{12}$/.test(clean)) return false;
  if (/^(.)\1+$/.test(clean)) return false; // Reject repeated digits

  let sum = 0;
  for (let i = 0; i < 11; i++) {
    sum += parseInt(clean[i]) * (i % 2 === 0 ? 3 : 1);
  }
  const checkDigit = (10 - (sum % 10)) % 10;
  return checkDigit === parseInt(clean[11]);
};

export const validateEAN = (code: string): boolean => {
  const clean = code.replace(/\s+/g, '');
  if (clean.length !== 13) return false;
  if (!/^\d{13}$/.test(clean)) return false;
  if (/^(.)\1+$/.test(clean)) return false;

  let sum = 0;
  for (let i = 0; i < 12; i++) {
    sum += parseInt(clean[i]) * (i % 2 === 0 ? 1 : 3);
  }
  const checkDigit = (10 - (sum % 10)) % 10;
  return checkDigit === parseInt(clean[12]);
};

export const validateSSCC = (code: string): boolean => {
  const clean = code.replace(/\s+/g, '');
  if (clean.length !== 18) return false;
  if (!/^\d{18}$/.test(clean)) return false;

  let sum = 0;
  for (let i = 0; i < 17; i++) {
    sum += parseInt(clean[i]) * (i % 2 === 0 ? 3 : 1);
  }
  const checkDigit = (10 - (sum % 10)) % 10;
  return checkDigit === parseInt(clean[17]);
};

export const validateCode = (value: string): CodeValidationResult => {
  if (!value) return { value: '', type: 'UNKNOWN', isValid: false };
  const clean = value.replace(/\s+/g, '');

  if (clean.length === 12) {
    return { value: clean, type: 'UPC-A', isValid: validateUPC(clean) };
  }
  if (clean.length === 11) {
    const padded = '0' + clean;
    return { value: padded, type: 'UPC-A', isValid: validateUPC(padded) };
  }
  if (clean.length === 13) {
    return { value: clean, type: 'EAN-13', isValid: validateEAN(clean) };
  }
  if (clean.length === 18) {
    return { value: clean, type: 'SSCC-18', isValid: validateSSCC(clean) };
  }
  if (clean.length >= 10 && clean.length <= 25 && /^[A-Z0-9]+$/i.test(clean)) {
    return { value: clean, type: 'UCI', isValid: true };
  }

  return { value: clean, type: 'UNKNOWN', isValid: false };
};

import { InvoiceData } from '../types';

export const generateEDI810 = (data: InvoiceData | null): string => {
  if (!data) return '';
  const segments: string[] = [];

  // Transaction Header
  segments.push(`ST*810*0001`);

  // BIG Segment: BIG*<YYYYMMDD>*<InvoiceNumber>***
  const dateStr = data.invoice_date.replace(/[-/]/g, '');
  const invNo = data.invoice_number || '';
  const poNo = data.po_number || '';

  // Per instructions: BIG*YYYYMMDD*InvoiceNumber***
  // If PO exists, we use common practice: BIG*Date*InvNo*PODate*PONumber
  if (poNo) {
    segments.push(`BIG*${dateStr}*${invNo}**${poNo}*`);
  } else {
    segments.push(`BIG*${dateStr}*${invNo}***`);
  }

  // N1 Loop (Seller)
  if (data.seller.name) {
    segments.push(`N1*SU*${data.seller.name.toUpperCase().substring(0, 35)}`);
    if (data.seller.address) segments.push(`N3*${data.seller.address.toUpperCase().substring(0, 35)}`);
    if (data.seller.city) {
      const city = data.seller.city.toUpperCase();
      const state = (data.seller.state || '').toUpperCase();
      const zip = (data.seller.zip || '').replace(/[^\d]/g, '');
      segments.push(`N4*${city}*${state}*${zip}`);
    }
  }

  // N1 Loop (Buyer)
  if (data.buyer.name) {
    segments.push(`N1*BY*${data.buyer.name.toUpperCase().substring(0, 35)}`);
    if (data.buyer.address) segments.push(`N3*${data.buyer.address.toUpperCase().substring(0, 35)}`);
    if (data.buyer.city) {
      const city = data.buyer.city.toUpperCase();
      const state = (data.buyer.state || '').toUpperCase();
      const zip = (data.buyer.zip || '').replace(/[^\d]/g, '');
      segments.push(`N4*${city}*${state}*${zip}`);
    }
  }

  // IT1 Loops
  data.line_items.forEach((item) => {
    const qty = item.qty || 0;
    const price = item.unit_price || 0;
    const uom = item.uom || 'CA';

    // Include UP only for valid codes
    const upPart = item.code_status === 'VALID' ? `**UP*${item.code_value}` : '';
    segments.push(`IT1*${item.line_no}*${qty}*${uom}*${price}${upPart}`);

    if (item.description) {
      segments.push(`PID*F****${item.description.toUpperCase().substring(0, 80)}`);
    }
  });

  // TDS - Amount
  if (data.totals.total !== null) {
    const cents = Math.round(data.totals.total * 100);
    segments.push(`TDS*${cents}`);
  }

  // CTT - Transaction Totals
  segments.push(`CTT*${data.line_items.length}`);

  // SE - Trailer
  const segCount = segments.length + 1;
  segments.push(`SE*${segCount}*0001`);

  return segments.join('~') + '~';
};

import { jsPDF } from 'jspdf';
import JsBarcode from 'jsbarcode';
import { InvoiceData } from '../types';

export const generateLabelPDF = async (data: InvoiceData): Promise<Blob | null> => {
  const validCodes = data.line_items.filter(it => it.code_status === 'VALID' || it.code_value);
  if (validCodes.length === 0) return null;

  const doc = new jsPDF({ orientation: 'p', unit: 'mm', format: 'a4' });
  const margin = 10;
  const colWidth = 63;
  const rowHeight = 45;
  const cols = 3;

  doc.setFont('helvetica', 'bold');
  doc.setFontSize(10);
  doc.text(`Logistic Tags: ${data.invoice_number || 'Batch'}`, margin, margin);
  doc.line(margin, margin + 2, 200, margin + 2);

  let currentX = margin;
  let currentY = margin + 10;

  for (let i = 0; i < data.line_items.length; i++) {
    const item = data.line_items[i];
    if (!item.code_value) continue;

    // Label Frame
    doc.setDrawColor(240);
    doc.rect(currentX, currentY, colWidth - 2, rowHeight - 2);

    // Header Meta
    doc.setFontSize(5);
    doc.setTextColor(150);
    doc.text(new Date().toLocaleDateString(), currentX + 3, currentY + 4);

    // Price
    doc.setFontSize(16);
    doc.setTextColor(0);
    doc.setFont('helvetica', 'bold');
    const price = item.unit_price ? `$${item.unit_price.toFixed(2)}` : '$---';
    doc.text(price, currentX + colWidth / 2, currentY + 10, { align: 'center' });

    // Desc
    doc.setFontSize(6);
    const desc = item.description.toUpperCase().substring(0, 30);
    doc.text(desc, currentX + colWidth / 2, currentY + 15, { align: 'center' });

    // Barcode Rendering
    if (item.code_status !== 'VALID') {
      doc.setDrawColor(255, 230, 230);
      doc.setFillColor(255, 245, 245);
      doc.roundedRect(currentX + 8, currentY + 18, colWidth - 18, 16, 2, 2, 'FD');
      doc.setFontSize(6);
      doc.setTextColor(200, 0, 0);
      doc.text('INVALID — EDIT REQUIRED', currentX + colWidth / 2, currentY + 25, { align: 'center' });
      doc.setFontSize(5);
      doc.text(item.code_value, currentX + colWidth / 2, currentY + 28, { align: 'center' });
    } else {
      try {
        const canvas = document.createElement('canvas');
        let format = 'CODE128';
        if (item.code_type === 'UPC-A') format = 'UPC';
        if (item.code_type === 'EAN-13') format = 'EAN13';

        JsBarcode(canvas, item.code_value, {
          format,
          displayValue: false,
          margin: 0,
          width: 4,
          height: 50,
          background: "#ffffff"
        });

        const imgData = canvas.toDataURL('image/png');
        doc.addImage(imgData, 'PNG', currentX + 8, currentY + 18, colWidth - 18, 16);
      } catch (err) {
        doc.setFontSize(6);
        doc.setTextColor(200, 0, 0);
        doc.text('RENDER ERROR', currentX + colWidth / 2, currentY + 26, { align: 'center' });
      }
    }

    // Human Readable
    doc.setFontSize(8);
    doc.setTextColor(0);
    doc.setFont('helvetica', 'normal');
    doc.text(item.code_value, currentX + colWidth / 2, currentY + rowHeight - 6, { align: 'center' });

    // Placement
    if ((i + 1) % cols === 0) {
      currentX = margin;
      currentY += rowHeight;
    } else {
      currentX += colWidth;
    }

    if (currentY + rowHeight > 280) {
      doc.addPage();
      currentX = margin;
      currentY = margin + 10;
    }
  }

  return doc.output('blob');
};

import Tesseract from 'tesseract.js';

export const runOCRPipeline = async (dataUrl: string): Promise<{ fullText: string; upcText: string }> => {
  const worker = await Tesseract.createWorker('eng');

  // Pass 1: Full Page
  const { data: { text: fullText } } = await worker.recognize(dataUrl);

  // Pass 2: Right-hand region heuristic for UPC column
  // We simulate a crop by creating a temporary canvas
  const upcText = await new Promise<string>((resolve) => {
    const img = new Image();
    img.src = dataUrl;
    img.onload = async () => {
      const canvas = document.createElement('canvas');
      const ctx = canvas.getContext('2d');
      if (!ctx) return resolve("");

      const width = img.width;
      const height = img.height;
      const cropW = width * 0.45;
      const cropX = width * 0.55;

      canvas.width = cropW;
      canvas.height = height;
      ctx.drawImage(img, cropX, 0, cropW, height, 0, 0, cropW, height);

      const { data: { text } } = await worker.recognize(canvas.toDataURL());
      resolve(text);
    };
  });

  await worker.terminate();
  return { fullText, upcText };
};

import { GoogleGenAI } from "@google/genai";
import { InvoiceData } from "../types";

export const extractWithGeminiFallback = async (
  file: File,
  ocrContext: string
): Promise<InvoiceData> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const base64 = await new Promise<string>((resolve) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => resolve((reader.result as string).split(',')[1]);
  });

  const prompt = `
    Act as a high-precision EDI data extractor. 
    Analyze the attached invoice image and OCR context: ${ocrContext}

    1. Correct any OCR spelling errors (e.g., 'NORTH RIDGEVILL' -> 'NORTH RIDGEVILLE').
    2. Extract line items meticulously. Default UOM to 'CA' (Case) if it's a bulk/wholesale distributor invoice.
    3. Identify identifiers (UPC, EAN, UCI). 
    4. Classify DocType: INVOICE_WITH_UPC, LONG_RECEIPT, TABLE_GRID, PAYMENT_RECEIPT, STATEMENT, or UNKNOWN.

    Return VALID JSON ONLY. NO MARKDOWN.
    {
      "invoice_number": "string",
      "invoice_date": "YYYY-MM-DD",
      "seller": {"name": "string", "address": "string", "city": "string", "state": "string", "zip": "string"},
      "buyer": {"name": "string", "address": "string", "city": "string", "state": "string", "zip": "string"},
      "po_number": "string",
      "currency": "USD",
      "doc_type": "string",
      "totals": {"subtotal": number, "tax": number, "discount": number, "total": number},
      "line_items": [
        {"line_no": number, "description": "string", "qty": number, "uom": "string", "unit_price": number, "line_total": number, "code_value": "string"}
      ]
    }
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { inlineData: { mimeType: file.type, data: base64 } },
        { text: prompt }
      ]
    },
    config: {
      responseMimeType: "application/json"
    }
  });

  return JSON.parse(response.text);
};

import React, { useState } from 'react';
import { 
  Upload, 
  ChevronRight, 
  RotateCcw, 
  FileDigit, 
  Trash2, 
  Loader2, 
  AlertCircle, 
  CheckCircle,
  Download,
  Copy,
  LayoutGrid,
  Filter,
  FileCheck,
  ChevronDown,
  ChevronUp,
  RefreshCw,
  ExternalLink,
  Settings2,
  Package
} from 'lucide-react';
import { 
  AppStep, 
  BatchState, 
  InvoiceState, 
  InvoiceData, 
  LineItem 
} from './types';
import { runOCRPipeline } from './services/ocrService';
import { preprocessForOCR } from './services/imagePreprocessor';
import { extractWithGeminiFallback } from './services/geminiService';
import { validateCode } from './services/validationService';
import { generateEDI810 } from './services/ediService';
import { generateLabelPDF } from './services/pdfService';

const App: React.FC = () => {
  const [step, setStep] = useState<AppStep>('UPLOAD');
  const [batch, setBatch] = useState<BatchState>({
    name: 'Batch_' + new Date().toISOString().slice(0, 10),
    strictMode: true,
    allowCode128Fallback: false,
    invoices: []
  });

  const [expandedDoc, setExpandedDoc] = useState<string | null>(null);
  const [filterType, setFilterType] = useState<string | null>(null);

  const startOver = () => {
    batch.invoices.forEach(inv => {
      URL.revokeObjectURL(inv.previewUrl);
      if (inv.pdfBlobUrl) URL.revokeObjectURL(inv.pdfBlobUrl);
    });
    setBatch({ name: 'Batch_' + new Date().toISOString().slice(0, 10), strictMode: true, allowCode128Fallback: false, invoices: [] });
    setStep('UPLOAD');
  };

  const handleFiles = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!e.target.files) return;
    const newFiles = Array.from(e.target.files);
    const newInvoices: InvoiceState[] = newFiles.map(file => ({
      id: Math.random().toString(36).substring(7),
      file,
      previewUrl: URL.createObjectURL(file),
      status: 'QUEUED',
      progress: 0,
      currentTask: 'Ready',
      qualityScore: 0.95, // Baseline
      sellerName: 'Pending...',
      data: null,
      ediText: '',
      pdfBlobUrl: null,
      warnings: [],
      missingFields: []
    }));
    setBatch(prev => ({ ...prev, invoices: [...prev.invoices, ...newInvoices] }));
  };

  const processBatch = async () => {
    setStep('PROCESSING');

    for (let inv of batch.invoices) {
      if (inv.status === 'DONE') continue;

      updateInv(inv.id, { status: 'RUNNING', progress: 5, currentTask: 'Enhancing Image...' });

      try {
        const enhancedUrl = await preprocessForOCR(inv.file);

        updateInv(inv.id, { progress: 20, currentTask: 'OCR Scan (Multi-pass)...' });
        const ocr = await runOCRPipeline(enhancedUrl);

        updateInv(inv.id, { progress: 50, currentTask: 'AI Extraction...' });
        const data = await extractWithGeminiFallback(inv.file, ocr.fullText);

        updateInv(inv.id, { progress: 85, currentTask: 'Finalizing Docs...' });

        // Validation & Sync
        const validatedItems = data.line_items.map(it => {
          const v = validateCode(it.code_value);
          return { ...it, code_value: v.value, code_type: v.type, code_status: v.isValid ? 'VALID' : 'INVALID' };
        }) as LineItem[];

        data.line_items = validatedItems;
        const edi = generateEDI810(data);
        const pdf = await generateLabelPDF(data);
        const pdfUrl = pdf ? URL.createObjectURL(pdf) : null;

        const needsReview = !data.invoice_number || data.line_items.some(it => it.code_status === 'INVALID');

        updateInv(inv.id, {
          status: needsReview ? 'NEEDS_REVIEW' : 'DONE',
          progress: 100,
          currentTask: 'Complete',
          sellerName: data.seller.name || 'Unknown Supplier',
          data,
          ediText: edi,
          pdfBlobUrl: pdfUrl
        });

      } catch (err: any) {
        updateInv(inv.id, { status: 'ERROR', error: err.message, currentTask: 'Failed' });
      }
    }

    setTimeout(() => setStep('RESULTS'), 1500);
  };

  const updateInv = (id: string, updates: Partial<InvoiceState>) => {
    setBatch(prev => ({
      ...prev,
      invoices: prev.invoices.map(i => i.id === id ? { ...i, ...updates } : i)
    }));
  };

  const handleEdit = (invId: string, idx: number, field: keyof LineItem, val: any) => {
    setBatch(prev => {
      const inv = prev.invoices.find(i => i.id === invId);
      if (!inv || !inv.data) return prev;
      const newItems = [...inv.data.line_items];
      newItems[idx] = { ...newItems[idx], [field]: val };

      if (field === 'code_value') {
        const v = validateCode(val);
        newItems[idx].code_status = v.isValid ? 'VALID' : 'INVALID';
        newItems[idx].code_type = v.type;
      }

      const newData = { ...inv.data, line_items: newItems };
      return { ...prev, invoices: prev.invoices.map(i => i.id === invId ? { ...i, data: newData } : i) };
    });
  };

  const syncChanges = async (invId: string) => {
    const inv = batch.invoices.find(i => i.id === invId);
    if (!inv || !inv.data) return;
    const edi = generateEDI810(inv.data);
    const pdf = await generateLabelPDF(inv.data);
    updateInv(invId, { ediText: edi, pdfBlobUrl: pdf ? URL.createObjectURL(pdf) : null });
  };

  if (step === 'UPLOAD') {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-8">
        <div className="max-w-4xl w-full">
          <header className="text-center mb-12">
            <h1 className="text-4xl font-black text-slate-900 tracking-tight flex items-center justify-center">
              <Package className="w-10 h-10 mr-4 text-indigo-600" />
              Universal Batch Processor
            </h1>
            <p className="text-slate-500 font-medium mt-2">Logistics-grade invoice extraction & label generation.</p>
          </header>

          <div className="bg-white rounded-[40px] shadow-2xl border border-slate-200 p-12 overflow-hidden relative">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-12">
              <div className="space-y-6">
                <div className="relative group border-2 border-dashed border-slate-300 rounded-[32px] p-12 text-center hover:bg-indigo-50 transition-all cursor-pointer">
                  <input type="file" multiple accept="image/*" onChange={handleFiles} className="absolute inset-0 opacity-0 cursor-pointer" />
                  <Upload className="w-12 h-12 text-indigo-500 mx-auto mb-4" />
                  <p className="font-black text-slate-900">Upload Invoices</p>
                  <p className="text-xs text-slate-400 mt-1 uppercase font-bold tracking-widest">Supports multiple suppliers</p>
                </div>
                <div className="bg-slate-50 p-6 rounded-[24px] border border-slate-100">
                  <div className="flex items-center space-x-2 mb-4">
                    <Settings2 className="w-4 h-4 text-slate-400" />
                    <span className="text-[10px] font-black uppercase text-slate-500 tracking-widest">Processing Logic</span>
                  </div>
                  <div className="flex items-center justify-between">
                    <div>
                      <p className="text-sm font-bold text-slate-900">Strict Validation</p>
                      <p className="text-[10px] text-slate-400">Force valid check-digits for labels</p>
                    </div>
                    <button onClick={() => setBatch(p => ({...p, strictMode: !p.strictMode}))} className={`w-10 h-5 rounded-full relative transition-all ${batch.strictMode ? 'bg-indigo-600' : 'bg-slate-200'}`}>
                      <div className={`absolute top-1 w-3 h-3 bg-white rounded-full transition-transform ${batch.strictMode ? 'translate-x-6' : 'translate-x-1'}`} />
                    </button>
                  </div>
                </div>
              </div>

              <div className="flex flex-col">
                <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Batch Queue ({batch.invoices.length}/8)</h3>
                {batch.invoices.length === 0 ? (
                  <div className="flex-1 flex flex-col items-center justify-center bg-slate-50 rounded-[32px] border border-slate-100 p-12 text-slate-300">
                    <LayoutGrid className="w-16 h-16 mb-4 opacity-10" />
                    <p className="font-bold text-xs">Waiting for files...</p>
                  </div>
                ) : (
                  <div className="flex-1 space-y-3 overflow-y-auto max-h-[300px] pr-2 scrollbar-thin">
                    {batch.invoices.map(inv => (
                      <div key={inv.id} className="flex items-center p-3 bg-white border border-slate-200 rounded-2xl shadow-sm hover:shadow-md transition-shadow">
                        <img src={inv.previewUrl} className="w-10 h-10 rounded-lg object-cover mr-4" />
                        <span className="text-xs font-bold text-slate-600 truncate flex-1">{inv.file.name}</span>
                        <button onClick={() => setBatch(p => ({...p, invoices: p.invoices.filter(i => i.id !== inv.id)}))} className="p-2 text-slate-300 hover:text-red-500">
                          <Trash2 className="w-4 h-4" />
                        </button>
                      </div>
                    ))}
                  </div>
                )}
                {batch.invoices.length > 0 && (
                  <button onClick={processBatch} className="mt-6 w-full py-5 bg-slate-900 text-white rounded-[24px] font-black uppercase text-xs tracking-widest shadow-xl flex items-center justify-center group active:scale-[0.98] transition-all">
                    Generate Batch Run
                    <ChevronRight className="w-4 h-4 ml-2 group-hover:translate-x-1 transition-transform" />
                  </button>
                )}
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  }

  if (step === 'PROCESSING') {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-8">
        <div className="max-w-2xl w-full bg-white rounded-[40px] shadow-2xl p-16 text-center border border-slate-200">
          <div className="inline-flex p-8 bg-indigo-50 rounded-full mb-8 animate-pulse">
            <Loader2 className="w-12 h-12 text-indigo-600 animate-spin" />
          </div>
          <h2 className="text-3xl font-black text-slate-900 mb-2">Processing Pipeline</h2>
          <p className="text-slate-400 font-bold uppercase text-[10px] tracking-[0.2em] mb-12">Extracting Intelligence &rarr; Building EDI</p>

          <div className="space-y-4 text-left">
            {batch.invoices.map(inv => (
              <div key={inv.id} className="p-6 bg-slate-50 rounded-[24px] border border-slate-100">
                <div className="flex items-center justify-between mb-4">
                  <div className="flex items-center space-x-3">
                    <img src={inv.previewUrl} className="w-8 h-8 rounded-lg object-cover" />
                    <span className="text-[10px] font-black uppercase text-slate-900 truncate max-w-[150px]">{inv.file.name}</span>
                  </div>
                  <span className="text-[9px] font-black text-indigo-600 uppercase tracking-widest">{inv.currentTask}</span>
                </div>
                <div className="h-1.5 bg-slate-200 rounded-full overflow-hidden">
                  <div className="h-full bg-indigo-600 transition-all duration-700" style={{ width: `${inv.progress}%` }} />
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 flex">
      {/* Sidebar Filter */}
      <aside className="w-80 bg-white border-r border-slate-200 h-screen sticky top-0 p-8 flex flex-col shadow-lg z-10">
        <div className="flex items-center space-x-4 mb-12">
          <div className="bg-slate-900 p-3 rounded-2xl text-white shadow-xl">
            <FileDigit className="w-6 h-6" />
          </div>
          <span className="font-black text-xl text-slate-900">Output</span>
        </div>

        <div className="flex-1 space-y-10 overflow-y-auto pr-2 scrollbar-thin">
          <div className="space-y-4">
            <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Supplier Segments</h4>
            <SidebarItem label="All Documents" count={batch.invoices.length} active={!filterType} onClick={() => setFilterType(null)} />
            {Array.from(new Set(batch.invoices.map(i => i.sellerName))).map(s => (
              <SidebarItem key={s} label={s} count={batch.invoices.filter(i => i.sellerName === s).length} active={filterType === s} onClick={() => setFilterType(s)} />
            ))}
          </div>
        </div>

        <button onClick={startOver} className="mt-8 py-5 bg-slate-900 text-white rounded-[24px] font-black uppercase text-[10px] tracking-[0.2em] shadow-2xl flex items-center justify-center">
          <RotateCcw className="w-4 h-4 mr-3" />
          New Start Over
        </button>
      </aside>

      {/* Main Content */}
      <main className="flex-1 p-16 max-w-6xl mx-auto">
        <header className="mb-12 flex items-center justify-between">
          <div>
            <h2 className="text-4xl font-black text-slate-900 tracking-tight">{filterType || 'Batch Inventory'}</h2>
            <p className="text-slate-400 font-bold mt-2">Verified EDI Streams & Logistic Tags</p>
          </div>
        </header>

        <div className="space-y-8">
          {batch.invoices.filter(i => !filterType || i.sellerName === filterType).map(inv => (
            <DocCard key={inv.id} inv={inv} expanded={expandedDoc === inv.id} onToggle={() => setExpandedDoc(expandedDoc === inv.id ? null : inv.id)} onEdit={handleEdit} onSync={syncChanges} />
          ))}
        </div>
      </main>
    </div>
  );
};

const SidebarItem: React.FC<{ label: string; count: number; active: boolean; onClick: () => void }> = ({ label, count, active, onClick }) => (
  <button onClick={onClick} className={`w-full flex items-center justify-between p-4 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${active ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}>
    <span className="truncate pr-4">{label}</span>
    <span className={`px-2 py-0.5 rounded-lg border ${active ? 'bg-white/10 border-white/20' : 'bg-slate-50 border-slate-200'}`}>{count}</span>
  </button>
);

const DocCard: React.FC<{ inv: InvoiceState; expanded: boolean; onToggle: () => void; onEdit: any; onSync: any }> = ({ inv, expanded, onToggle, onEdit, onSync }) => {
  const [tab, setTab] = useState<'EDI' | 'TAGS' | 'EDIT'>('EDIT');
  const hasTags = inv.data?.line_items.some(it => it.code_value);

  return (
