const BarcodePreview: React.FC<{ code: string; type: string }> = ({ code, type }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    if (canvasRef.current && code) {
      try {
        let format = 'CODE128';
        if (type === 'UPC-A') format = 'UPC';
        if (type === 'EAN-13') format = 'EAN13';

        JsBarcode(canvasRef.current, code, {
          format,
          displayValue: true,
          fontSize: 14,
          height: 50,
          width: 2,
          margin: 10,
          background: "#ffffff"
        });
      } catch (err) {
        console.error("Barcode render error", err);
      }
    }
  }, [code, type]);

  return (
    <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm flex flex-col items-center">
      <canvas ref={canvasRef} className="max-w-full h-auto" />
    </div>
  );
};

const ZoomableImage: React.FC<{ src: string; onClose: () => void }> = ({ src, onClose }) => {
  const [zoom, setZoom] = useState(1);
  const [position, setPosition] = useState({ x: 0, y: 0 });
  const [isDragging, setIsDragging] = useState(false);
  const [dragStart, setDragStart] = useState({ x: 0, y: 0 });
  const containerRef = useRef<HTMLDivElement>(null);

  const handleZoomIn = () => setZoom(prev => Math.min(prev + 0.5, 5));
  const handleZoomOut = () => setZoom(prev => Math.max(prev - 0.5, 1));
  const handleReset = () => {
    setZoom(1);
    setPosition({ x: 0, y: 0 });
  };

  const handleMouseDown = (e: React.MouseEvent) => {
    if (zoom > 1) {
      setIsDragging(true);
      setDragStart({ x: e.clientX - position.x, y: e.clientY - position.y });
    }
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    if (isDragging) {
      setPosition({
        x: e.clientX - dragStart.x,
        y: e.clientY - dragStart.y
      });
    }
  };

  const handleMouseUp = () => setIsDragging(false);

  return (
    <div className="flex flex-col h-full bg-slate-900 rounded-3xl overflow-hidden border border-slate-700 shadow-2xl">
      <div className="p-4 border-b border-slate-800 flex items-center justify-between bg-slate-900/50 backdrop-blur-md sticky top-0 z-10">
        <div className="flex items-center space-x-2">
          <button onClick={handleZoomOut} className="p-2 text-slate-400 hover:text-white hover:bg-slate-800 rounded-xl transition-all">
            <ZoomOut className="w-5 h-5" />
          </button>
          <span className="text-[10px] font-black text-slate-500 w-12 text-center uppercase tracking-widest">
            {Math.round(zoom * 100)}%
          </span>
          <button onClick={handleZoomIn} className="p-2 text-slate-400 hover:text-white hover:bg-slate-800 rounded-xl transition-all">
            <ZoomIn className="w-5 h-5" />
          </button>
          <button onClick={handleReset} className="p-2 text-slate-400 hover:text-white hover:bg-slate-800 rounded-xl transition-all">
            <Maximize2 className="w-5 h-5" />
          </button>
        </div>
        <button onClick={onClose} className="p-2 text-slate-400 hover:text-red-500 hover:bg-red-500/10 rounded-xl transition-all">
          <X className="w-5 h-5" />
        </button>
      </div>

      <div 
        ref={containerRef}
        className="flex-1 overflow-hidden cursor-grab active:cursor-grabbing relative"
        onMouseDown={handleMouseDown}
        onMouseMove={handleMouseMove}
        onMouseUp={handleMouseUp}
        onMouseLeave={handleMouseUp}
      >
        <div 
          className="w-full h-full flex items-center justify-center transition-transform duration-200 ease-out"
          style={{ 
            transform: `translate(${position.x}px, ${position.y}px) scale(${zoom})`,
            transformOrigin: 'center'
          }}
        >
          <img 
            src={src} 
            alt="Receipt Preview" 
            className="max-w-full max-h-full object-contain pointer-events-none shadow-2xl"
          />
        </div>
      </div>
      <div className="p-4 bg-slate-800/50 text-center">
        <p className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em]">
          Hold & Drag to Pan when zoomed
        </p>
      </div>
    </div>
  );
};

const App: React.FC = () => {
  const [step, setStep] = useState<AppStep>('UPLOAD');
  const [batch, setBatch] = useState<BatchState>({
    name: 'Batch_' + new Date().toISOString().slice(0, 10),
    strictMode: true,
    allowCode128Fallback: false,
    invoices: []
  });

  const [expandedDoc, setExpandedDoc] = useState<string | null>(null);
  const [filterType, setFilterType] = useState<string | null>(null);
  const [previewingDocId, setPreviewingDocId] = useState<string | null>(null);

  const startOver = () => {
    batch.invoices.forEach(inv => {
      URL.revokeObjectURL(inv.previewUrl);
      if (inv.pdfBlobUrl) URL.revokeObjectURL(inv.pdfBlobUrl);
    });
    setBatch({ name: 'Batch_' + new Date().toISOString().slice(0, 10), strictMode: true, allowCode128Fallback: false, invoices: [] });
    setStep('UPLOAD');
    setPreviewingDocId(null);
  };

  const handleFiles = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!e.target.files) return;
    const newFiles = Array.from(e.target.files);
    const newInvoices: InvoiceState[] = newFiles.map(file => ({
      id: Math.random().toString(36).substring(7),
      file,
      previewUrl: URL.createObjectURL(file),
      status: 'QUEUED',
      progress: 0,
      currentTask: 'Ready',
      qualityScore: 0.95, // Baseline
      sellerName: 'Pending...',
      data: null,
      ediText: '',
      pdfBlobUrl: null,
      warnings: [],
      missingFields: []
    }));
    setBatch(prev => ({ ...prev, invoices: [...prev.invoices, ...newInvoices] }));
  };

  const processBatch = async () => {
    setStep('PROCESSING');

    for (let inv of batch.invoices) {
      if (inv.status === 'DONE') continue;

      updateInv(inv.id, { status: 'RUNNING', progress: 5, currentTask: 'Enhancing Image...' });

      try {
        const enhancedUrl = await preprocessForOCR(inv.file);

        updateInv(inv.id, { progress: 20, currentTask: 'OCR Scan (Multi-pass)...' });
        const ocr = await runOCRPipeline(enhancedUrl);

        updateInv(inv.id, { progress: 50, currentTask: 'AI Extraction...' });
        const data = await extractWithGeminiFallback(inv.file, ocr.fullText);

        updateInv(inv.id, { progress: 85, currentTask: 'Finalizing Docs...' });

        // Validation & Sync
        const validatedItems = data.line_items.map(it => {
          const v = validateCode(it.code_value);
          return { ...it, code_value: v.value, code_type: v.type, code_status: v.isValid ? 'VALID' : 'INVALID' };
        }) as LineItem[];

        data.line_items = validatedItems;
        const edi = generateEDI810(data);
        const pdf = await generateLabelPDF(data);
        const pdfUrl = pdf ? URL.createObjectURL(pdf) : null;

        const needsReview = !data.invoice_number || data.line_items.some(it => it.code_status === 'INVALID');

        updateInv(inv.id, {
          status: needsReview ? 'NEEDS_REVIEW' : 'DONE',
          progress: 100,
          currentTask: 'Complete',
          sellerName: data.seller.name || 'Unknown Supplier',
          data,
          ediText: edi,
          pdfBlobUrl: pdfUrl
        });

      } catch (err: any) {
        updateInv(inv.id, { status: 'ERROR', error: err.message, currentTask: 'Failed' });
      }
    }

    setTimeout(() => setStep('RESULTS'), 1500);
  };

  const updateInv = (id: string, updates: Partial<InvoiceState>) => {
    setBatch(prev => ({
      ...prev,
      invoices: prev.invoices.map(i => i.id === id ? { ...i, ...updates } : i)
    }));
  };

  const handleEdit = (invId: string, idx: number, field: keyof LineItem, val: any) => {
    setBatch(prev => {
      const inv = prev.invoices.find(i => i.id === invId);
      if (!inv || !inv.data) return prev;
      const newItems = [...inv.data.line_items];
      newItems[idx] = { ...newItems[idx], [field]: val };

      if (field === 'code_value') {
        const v = validateCode(val);
        newItems[idx].code_status = v.isValid ? 'VALID' : 'INVALID';
        newItems[idx].code_type = v.type;
      }

      const newData = { ...inv.data, line_items: newItems };
      return { ...prev, invoices: prev.invoices.map(i => i.id === invId ? { ...i, data: newData } : i) };
    });
  };

  const syncChanges = async (invId: string) => {
    const inv = batch.invoices.find(i => i.id === invId);
    if (!inv || !inv.data) return;
    const edi = generateEDI810(inv.data);
    const pdf = await generateLabelPDF(inv.data);
    updateInv(invId, { ediText: edi, pdfBlobUrl: pdf ? URL.createObjectURL(pdf) : null });
  };

  const togglePreview = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    setPreviewingDocId(prev => prev === id ? null : id);
    if (expandedDoc !== id) {
      setExpandedDoc(id);
    }
  };

  const getEdiDownloadName = (inv: InvoiceState) => {
    const seller = inv.sellerName || inv.data?.seller.name;
    if (seller && seller !== 'Pending...' && seller !== 'Unknown Supplier') {
      return `EDI_${seller.replace(/[^a-z0-9]/gi, '_')}.edi`;
    }
    const unique = Math.floor(10000 + Math.random() * 90000);
    return `EDI_${unique}.edi`;
  };

  if (step === 'UPLOAD') {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-8">
        <div className="max-w-4xl w-full">
          <header className="text-center mb-12">
            <h1 className="text-4xl font-black text-slate-900 tracking-tight flex items-center justify-center">
              <Package className="w-10 h-10 mr-4 text-indigo-600" />
              Universal Batch Processor
            </h1>
            <p className="text-slate-500 font-medium mt-2">Logistics-grade invoice extraction & label generation.</p>
          </header>

          <div className="bg-white rounded-[40px] shadow-2xl border border-slate-200 p-12 overflow-hidden relative">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-12">
              <div className="space-y-6">
                <div className="relative group border-2 border-dashed border-slate-300 rounded-[32px] p-12 text-center hover:bg-indigo-50 transition-all cursor-pointer">
                  <input type="file" multiple accept="image/*" onChange={handleFiles} className="absolute inset-0 opacity-0 cursor-pointer" />
                  <Upload className="w-12 h-12 text-indigo-500 mx-auto mb-4" />
                  <p className="font-black text-slate-900">Upload Invoices</p>
                  <p className="text-xs text-slate-400 mt-1 uppercase font-bold tracking-widest">Supports multiple suppliers</p>
                </div>
                <div className="bg-slate-50 p-6 rounded-[24px] border border-slate-100">
                  <div className="flex items-center space-x-2 mb-4">
                    <Settings2 className="w-4 h-4 text-slate-400" />
                    <span className="text-[10px] font-black uppercase text-slate-500 tracking-widest">Processing Logic</span>
                  </div>
                  <div className="flex items-center justify-between">
                    <div>
                      <p className="text-sm font-bold text-slate-900">Strict Validation</p>
                      <p className="text-[10px] text-slate-400">Force valid check-digits for labels</p>
                    </div>
                    <button onClick={() => setBatch(p => ({...p, strictMode: !p.strictMode}))} className={`w-10 h-5 rounded-full relative transition-all ${batch.strictMode ? 'bg-indigo-600' : 'bg-slate-200'}`}>
                      <div className={`absolute top-1 w-3 h-3 bg-white rounded-full transition-transform ${batch.strictMode ? 'translate-x-6' : 'translate-x-1'}`} />
                    </button>
                  </div>
                </div>
              </div>

              <div className="flex flex-col">
                <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Batch Queue ({batch.invoices.length}/8)</h3>
                {batch.invoices.length === 0 ? (
                  <div className="flex-1 flex flex-col items-center justify-center bg-slate-50 rounded-[32px] border border-slate-100 p-12 text-slate-300">
                    <LayoutGrid className="w-16 h-16 mb-4 opacity-10" />
                    <p className="font-bold text-xs">Waiting for files...</p>
                  </div>
                ) : (
                  <div className="flex-1 space-y-3 overflow-y-auto max-h-[300px] pr-2 scrollbar-thin">
                    {batch.invoices.map(inv => (
                      <div key={inv.id} className="flex items-center p-3 bg-white border border-slate-200 rounded-2xl shadow-sm hover:shadow-md transition-shadow">
                        <img src={inv.previewUrl} className="w-10 h-10 rounded-lg object-cover mr-4" />
                        <span className="text-xs font-bold text-slate-600 truncate flex-1">{inv.file.name}</span>
                        <button onClick={() => setBatch(p => ({...p, invoices: p.invoices.filter(i => i.id !== inv.id)}))} className="p-2 text-slate-300 hover:text-red-500">
                          <Trash2 className="w-4 h-4" />
                        </button>
                      </div>
                    ))}
                  </div>
                )}
                {batch.invoices.length > 0 && (
                  <button onClick={processBatch} className="mt-6 w-full py-5 bg-slate-900 text-white rounded-[24px] font-black uppercase text-xs tracking-widest shadow-xl flex items-center justify-center group active:scale-[0.98] transition-all">
                    Generate Batch Run
                    <ChevronRight className="w-4 h-4 ml-2 group-hover:translate-x-1 transition-transform" />
                  </button>
                )}
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  }

  if (step === 'PROCESSING') {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-8">
        <div className="max-w-2xl w-full bg-white rounded-[40px] shadow-2xl p-16 text-center border border-slate-200">
          <div className="inline-flex p-8 bg-indigo-50 rounded-full mb-8 animate-pulse">
            <Loader2 className="w-12 h-12 text-indigo-600 animate-spin" />
          </div>
          <h2 className="text-3xl font-black text-slate-900 mb-4 tracking-tight">Processing Pipeline</h2>
          <p className="text-slate-400 font-bold uppercase text-[10px] tracking-[0.2em] mb-12">Extracting Intelligence &rarr; Building EDI</p>

          <div className="space-y-4 text-left">
            {batch.invoices.map(inv => (
              <div key={inv.id} className="p-6 bg-slate-50 rounded-[24px] border border-slate-100">
                <div className="flex items-center justify-between mb-4">
                  <div className="flex items-center space-x-3">
                    <img src={inv.previewUrl} className="w-8 h-8 rounded-lg object-cover" />
                    <span className="text-[10px] font-black uppercase text-slate-900 truncate max-w-[150px]">{inv.file.name}</span>
                  </div>
                  <span className="text-[9px] font-black text-indigo-600 uppercase tracking-widest">{inv.currentTask}</span>
                </div>
                <div className="h-1.5 bg-slate-200 rounded-full overflow-hidden">
                  <div className="h-full bg-indigo-600 transition-all duration-700" style={{ width: `${inv.progress}%` }} />
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 flex">
      <aside className="w-80 bg-white border-r border-slate-200 h-screen sticky top-0 p-8 flex flex-col shadow-lg z-10">
        <div className="flex items-center space-x-4 mb-12">
          <div className="bg-slate-900 p-3 rounded-2xl text-white shadow-xl">
            <FileDigit className="w-6 h-6" />
          </div>
          <span className="font-black text-xl text-slate-900">Output</span>
        </div>

        <div className="flex-1 space-y-10 overflow-y-auto pr-2 scrollbar-thin">
          <div className="space-y-4">
            <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Supplier Segments</h4>
            <SidebarItem label="All Documents" count={batch.invoices.length} active={!filterType} onClick={() => setFilterType(null)} />
            {Array.from(new Set(batch.invoices.map(i => i.sellerName))).map(s => (
              <SidebarItem key={s} label={s} count={batch.invoices.filter(i => i.sellerName === s).length} active={filterType === s} onClick={() => setFilterType(s)} />
            ))}
          </div>
        </div>

        <button onClick={startOver} className="mt-8 py-5 bg-slate-900 text-white rounded-[24px] font-black uppercase text-[10px] tracking-[0.2em] shadow-2xl flex items-center justify-center">
          <RotateCcw className="w-4 h-4 mr-3" />
          New Start Over
        </button>
      </aside>

      <main className="flex-1 p-16 max-w-7xl mx-auto">
        <header className="mb-12 flex items-center justify-between">
          <div>
            <h2 className="text-4xl font-black text-slate-900 tracking-tight">{filterType || 'Batch Inventory'}</h2>
            <p className="text-slate-400 font-bold mt-2">Verified EDI Streams & Logistic Tags</p>
          </div>
        </header>

        <div className="space-y-8">
          {batch.invoices.filter(i => !filterType || i.sellerName === filterType).map(inv => (
            <DocCard 
              key={inv.id} 
              inv={inv} 
              expanded={expandedDoc === inv.id} 
              isPreviewing={previewingDocId === inv.id}
              onToggle={() => setExpandedDoc(expandedDoc === inv.id ? null : inv.id)} 
              onTogglePreview={(e) => togglePreview(e, inv.id)}
              onEdit={handleEdit} 
              onSync={syncChanges} 
              onClosePreview={() => setPreviewingDocId(null)}
              ediDownloadName={getEdiDownloadName(inv)}
            />
          ))}
        </div>
      </main>
    </div>
  );
};

