import Tesseract from 'tesseract.js';

interface OCRResult {
  text: string;
  score: number;
  variant: string;
}

export const calculateOCRScore = (text: string): number => {
  if (!text) return 0;

  const words = text.split(/\s+/).filter(w => w.length > 1).length;
  const currencyPatterns = (text.match(/\$\s?\d+[.,]\d{2}/g) || []).length;
  const datePatterns = (text.match(/\d{1,2}[\/-]\d{1,2}[\/-]\d{2,4}/g) || []).length;
  const lines = text.split('\n').filter(l => l.trim().length > 5).length;

  // Weights based on logical extraction value
  return words + (currencyPatterns * 20) + (datePatterns * 15) + (lines * 5);
};

export const runOCRPipeline = async (variants: { label: string, url: string }[]): Promise<{ fullText: string; bestVariant: string; score: number }> => {
  const worker = await Tesseract.createWorker('eng');
  const results: OCRResult[] = [];

  for (const variant of variants) {
    const { data: { text } } = await worker.recognize(variant.url);
    results.push({
      text,
      score: calculateOCRScore(text),
      variant: variant.label
    });
  }

  await worker.terminate();

  // Pick best
  const best = results.reduce((prev, current) => (prev.score > current.score) ? prev : current);

  return {
    fullText: best.text,
    bestVariant: best.variant,
    score: best.score
  };
};

import { GoogleGenAI } from "@google/genai";
import { InvoiceData } from "../types";

const getBase64 = (file: File): Promise<string> => {
  return new Promise((resolve) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => resolve((reader.result as string).split(',')[1]);
  });
};

export const transcribeOnly = async (file: File): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const base64 = await getBase64(file);

  const prompt = `Transcribe only clearly visible text from this document. Do not guess or hallucinate. Return plain text transcription.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { inlineData: { mimeType: file.type, data: base64 } },
        { text: prompt }
      ]
    }
  });

  return response.text || "";
};

export const extractWithGeminiFallback = async (
  file: File,
  ocrContext: string,
  isFullFallback: boolean = false
): Promise<InvoiceData> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const base64 = await getBase64(file);

  const prompt = `
    Act as a high-precision logistics data extractor. 
    Analyze the attached image.
    ${!isFullFallback ? `OCR Context for hint: ${ocrContext}` : 'Perform direct visual extraction as local OCR failed.'}

    RULES:
    1. Extract line items meticulously.
    2. Correct OCR typos.
    3. Default UOM to 'CA' if wholesale.
    4. Find "Delivered By" and "Brought By".
    5. Generate a 2-sentence "info_summary".
    6. If a field is missing, set to null or "".

    Return VALID JSON ONLY:
    {
      "invoice_number": "string",
      "invoice_date": "YYYY-MM-DD",
      "seller": {"name": "string", "address": "string", "city": "string", "state": "string", "zip": "string"},
      "buyer": {"name": "string", "address": "string", "city": "string", "state": "string", "zip": "string"},
      "po_number": "string",
      "currency": "USD",
      "doc_type": "string",
      "delivered_by": "string",
      "brought_by": "string",
      "info_summary": "string",
      "totals": {"subtotal": number, "tax": number, "discount": number, "total": number},
      "line_items": [
        {"line_no": number, "description": "string", "qty": number, "uom": "string", "unit_price": number, "line_total": number, "code_value": "string"}
      ]
    }
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { inlineData: { mimeType: file.type, data: base64 } },
        { text: prompt }
      ]
    },
    config: {
      responseMimeType: "application/json"
    }
  });

  try {
    const data = JSON.parse(response.text);
    return { ...data, raw_text: ocrContext };
  } catch (e) {
    // If JSON fails, we still want a partial object
    return {
      invoice_number: "",
      invoice_date: "",
      seller: { name: "", address: "", city: "", state: "", zip: "" },
      buyer: { name: "", address: "", city: "", state: "", zip: "" },
      po_number: "",
      currency: "USD",
      doc_type: "UNKNOWN",
      delivered_by: "",
      brought_by: "",
      info_summary: "Manual review required: AI parse failed.",
      raw_text: ocrContext,
      totals: { subtotal: null, tax: null, discount: null, total: null },
      line_items: []
    };
  }
};

