      if (mode === 'GEMINI_ONLY') {
        const geminiTranscription = await transcribeOnly(inv.file);
        finalData = await extractWithGeminiFallback(inv.file, "", true);
        finalData.gemini_transcription = geminiTranscription;
        method = 'GEMINI';
      } else {
        const variants = [
          { label: 'Standard', url: await preprocessForOCR(inv.file) }
        ];
        const ocr = await runOCRPipeline(variants);
        const ocrScoreThreshold = 50;

        if (ocr.score < ocrScoreThreshold) {
          finalData = await extractWithGeminiFallback(inv.file, ocr.fullText, true);
          method = 'HYBRID';
        } else {
          finalData = await extractWithGeminiFallback(inv.file, ocr.fullText, false);
          method = 'OCR';
        }
        finalData.raw_text = ocr.fullText;
      }

      const validatedItems = (finalData.line_items || []).map(it => {
        const v = validateCode(it.code_value);
        return { ...it, code_value: v.value, code_type: v.type, code_status: v.isValid ? 'VALID' : 'INVALID' };
      }) as LineItem[];

      finalData.line_items = validatedItems;
      const edi = generateEDI810(finalData);
      const pdf = await generateLabelPDF(finalData);
      const pdfUrl = pdf ? URL.createObjectURL(pdf) : null;

      const needsReview = !finalData.invoice_number || !finalData.totals.total || finalData.line_items.some(it => it.code_status === 'INVALID');

      updateInv(inv.id, {
        status: needsReview ? 'NEEDS_REVIEW' : 'DONE',
        progress: 100, currentTask: 'Complete',
        sellerName: finalData.seller.name || 'Unknown Supplier',
        data: finalData, ediText: edi, pdfBlobUrl: pdfUrl, extractionMethod: method
      });

    } catch (err: any) {
      // Never crash, always needs review
      updateInv(inv.id, { 
        status: 'NEEDS_REVIEW', 
        currentTask: 'Extraction Weak', 
        warnings: [err.message || 'System error during extraction'] 
      });
    }
  };

  const processBatch = async () => {
    setStep('PROCESSING');
    for (let inv of batch.invoices) {
      if (inv.status === 'DONE') continue;
      await processInvoice(inv);
    }
    setTimeout(() => setStep('RESULTS'), 1000);
  };

  const updateInv = (id: string, updates: Partial<InvoiceState>) => {
    setBatch(prev => ({
      ...prev, invoices: prev.invoices.map(i => i.id === id ? { ...i, ...updates } : i)
    }));
  };

  const handleEdit = (invId: string, idx: number, field: keyof LineItem, val: any) => {
    setBatch(prev => {
      const inv = prev.invoices.find(i => i.id === invId);
      if (!inv || !inv.data) return prev;
      const newItems = [...inv.data.line_items];
      newItems[idx] = { ...newItems[idx], [field]: val };
      if (field === 'code_value') {
        const v = validateCode(val);
        newItems[idx].code_status = v.isValid ? 'VALID' : 'INVALID';
        newItems[idx].code_type = v.type;
      }
      const newData = { ...inv.data, line_items: newItems };
      return { ...prev, invoices: prev.invoices.map(i => i.id === invId ? { ...i, data: newData } : i) };
    });
  };

  const addLine = (invId: string) => {
    setBatch(prev => {
      const inv = prev.invoices.find(i => i.id === invId);
      if (!inv || !inv.data) return prev;
      const newLine: LineItem = {
        line_no: inv.data.line_items.length + 1,
        description: "New Item",
        qty: 1, uom: 'CA', unit_price: 0, line_total: 0,
        code_type: 'UNKNOWN', code_value: '', code_status: 'UNVERIFIED'
      };
      const newData = { ...inv.data, line_items: [...inv.data.line_items, newLine] };
      return { ...prev, invoices: prev.invoices.map(i => i.id === invId ? { ...i, data: newData } : i) };
    });
  };

  const syncChanges = async (invId: string) => {
    const inv = batch.invoices.find(i => i.id === invId);
    if (!inv || !inv.data) return;
    const edi = generateEDI810(inv.data);
    const pdf = await generateLabelPDF(inv.data);
    updateInv(invId, { ediText: edi, pdfBlobUrl: pdf ? URL.createObjectURL(pdf) : null });
  };

  const togglePreview = (e: React.MouseEvent, id: string) => {
    e.stopPropagation(); setPreviewingDocId(prev => prev === id ? null : id);
    if (expandedDoc !== id) setExpandedDoc(id);
  };

  const getEdiDownloadName = (inv: InvoiceState) => {
    const seller = inv.sellerName || inv.data?.seller.name;
    if (seller && seller !== 'Pending...' && seller !== 'Unknown Supplier') return `EDI_${seller.replace(/[^a-z0-9]/gi, '_')}.edi`;
    return `EDI_${inv.id.substring(0,5)}.edi`;
  };

  if (step === 'UPLOAD') {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-8">
        <div className="max-w-4xl w-full">
          <header className="text-center mb-12">
            <h1 className="text-4xl font-black text-slate-900 tracking-tight flex items-center justify-center"><Package className="w-10 h-10 mr-4 text-indigo-600" />Universal Batch Processor</h1>
            <p className="text-slate-500 font-medium mt-2">Logistics-grade invoice extraction & label generation.</p>
          </header>
          <div className="bg-white rounded-[40px] shadow-2xl border border-slate-200 p-12 overflow-hidden relative">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-12">
              <div className="space-y-6">
                <div className="relative group border-2 border-dashed border-slate-300 rounded-[32px] p-12 text-center hover:bg-indigo-50 transition-all cursor-pointer">
                  <input type="file" multiple accept="image/*" onChange={handleFiles} className="absolute inset-0 opacity-0 cursor-pointer" />
                  <Upload className="w-12 h-12 text-indigo-500 mx-auto mb-4" />
                  <p className="font-black text-slate-900">Upload Invoices</p>
                  <p className="text-xs text-slate-400 mt-1 uppercase font-bold tracking-widest">Supports multiple suppliers</p>
                </div>
              </div>
              <div className="flex flex-col">
                <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Batch Queue ({batch.invoices.length}/8)</h3>
                {batch.invoices.length === 0 ? (
                  <div className="flex-1 flex flex-col items-center justify-center bg-slate-50 rounded-[32px] border border-slate-100 p-12 text-slate-300"><LayoutGrid className="w-16 h-16 mb-4 opacity-10" /><p className="font-bold text-xs">Waiting for files...</p></div>
                ) : (
                  <div className="flex-1 space-y-3 overflow-y-auto max-h-[300px] pr-2 scrollbar-thin">
                    {batch.invoices.map(inv => (
                      <div key={inv.id} className="flex items-center p-3 bg-white border border-slate-200 rounded-2xl shadow-sm hover:shadow-md transition-shadow">
                        <img src={inv.previewUrl} className="w-10 h-10 rounded-lg object-cover mr-4" />
                        <span className="text-xs font-bold text-slate-600 truncate flex-1">{inv.file.name}</span>
                        <button onClick={() => setBatch(p => ({...p, invoices: p.invoices.filter(i => i.id !== inv.id)}))} className="p-2 text-slate-300 hover:text-red-500"><Trash2 className="w-4 h-4" /></button>
                      </div>
                    ))}
                  </div>
                )}
                {batch.invoices.length > 0 && (
                  <button onClick={processBatch} className="mt-6 w-full py-5 bg-slate-900 text-white rounded-[24px] font-black uppercase text-xs tracking-widest shadow-xl flex items-center justify-center group transition-all">Generate Batch Run<ChevronRight className="w-4 h-4 ml-2 group-hover:translate-x-1 transition-transform" /></button>
                )}
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  }

  if (step === 'PROCESSING') {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-8">
        <div className="max-w-2xl w-full bg-white rounded-[40px] shadow-2xl p-16 text-center border border-slate-200">
          <div className="inline-flex p-8 bg-indigo-50 rounded-full mb-8 animate-pulse"><Loader2 className="w-12 h-12 text-indigo-600 animate-spin" /></div>
          <h2 className="text-3xl font-black text-slate-900 mb-4 tracking-tight">Processing Pipeline</h2>
          <div className="space-y-4 text-left mt-12">
            {batch.invoices.map(inv => (
              <div key={inv.id} className="p-6 bg-slate-50 rounded-[24px] border border-slate-100">
                <div className="flex items-center justify-between mb-4">
                  <div className="flex items-center space-x-3">
                    <img src={inv.previewUrl} className="w-8 h-8 rounded-lg object-cover" />
                    <span className="text-[10px] font-black uppercase text-slate-900 truncate max-w-[150px]">{inv.file.name}</span>
                  </div>
                  <span className="text-[9px] font-black text-indigo-600 uppercase tracking-widest">{inv.currentTask}</span>
                </div>
                <div className="h-1.5 bg-slate-200 rounded-full overflow-hidden">
                  <div className="h-full bg-indigo-600 transition-all duration-700" style={{ width: `${inv.progress}%` }} />
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 flex">
      <aside className="w-80 bg-white border-r border-slate-200 h-screen sticky top-0 p-8 flex flex-col shadow-lg z-10">
        <div className="flex items-center space-x-4 mb-12">
          <div className="bg-slate-900 p-3 rounded-2xl text-white shadow-xl"><FileDigit className="w-6 h-6" /></div>
          <span className="font-black text-xl text-slate-900">Output</span>
        </div>
        <div className="flex-1 space-y-10 overflow-y-auto pr-2 scrollbar-thin">
          <div className="space-y-4">
            <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Supplier Segments</h4>
            <SidebarItem label="All Documents" count={batch.invoices.length} active={!filterType} onClick={() => setFilterType(null)} />
            {Array.from(new Set(batch.invoices.map(i => i.sellerName))).map(s => (
              <SidebarItem key={s} label={s} count={batch.invoices.filter(i => i.sellerName === s).length} active={filterType === s} onClick={() => setFilterType(s)} />
            ))}
          </div>
        </div>
        <button onClick={startOver} className="mt-8 py-5 bg-slate-900 text-white rounded-[24px] font-black uppercase text-[10px] tracking-[0.2em] shadow-2xl flex items-center justify-center"><RotateCcw className="w-4 h-4 mr-3" />Start Over</button>
      </aside>

      <main className="flex-1 p-16 max-w-7xl mx-auto">
        <header className="mb-12 flex items-center justify-between">
          <div><h2 className="text-4xl font-black text-slate-900 tracking-tight">{filterType || 'Batch Inventory'}</h2><p className="text-slate-400 font-bold mt-2">Verified EDI Streams & Logistic Tags</p></div>
        </header>
        <div className="space-y-8">
          {batch.invoices.filter(i => !filterType || i.sellerName === filterType).map(inv => (
            <DocCard key={inv.id} inv={inv} expanded={expandedDoc === inv.id} isPreviewing={previewingDocId === inv.id} onToggle={() => setExpandedDoc(expandedDoc === inv.id ? null : inv.id)} onTogglePreview={(e) => togglePreview(e, inv.id)} onEdit={handleEdit} onSync={syncChanges} onClosePreview={() => setPreviewingDocId(null)} ediDownloadName={getEdiDownloadName(inv)} onRetry={(m) => processInvoice(inv, m)} onAddLine={() => addLine(inv.id)} />
          ))}
        </div>
      </main>
    </div>
  );
};

const SidebarItem: React.FC<{ label: string; count: number; active: boolean; onClick: () => void }> = ({ label, count, active, onClick }) => (
  <button onClick={onClick} className={`w-full flex items-center justify-between p-4 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${active ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}>
    <span className="truncate pr-4">{label}</span>
    <span className={`px-2 py-0.5 rounded-lg border ${active ? 'bg-white/10 border-white/20' : 'bg-slate-50 border-slate-200'}`}>{count}</span>
  </button>
);

const DocCard: React.FC<{ 
  inv: InvoiceState; expanded: boolean; isPreviewing: boolean; onToggle: () => void; onTogglePreview: (e: React.MouseEvent) => void;
  onEdit: any; onSync: any; onClosePreview: () => void; ediDownloadName: string; onRetry: (m: any) => void; onAddLine: () => void;
}> = ({ inv, expanded, isPreviewing, onToggle, onTogglePreview, onEdit, onSync, onClosePreview, ediDownloadName, onRetry, onAddLine }) => {
  const [tab, setTab] = useState<'SUMMARY' | 'EDI' | 'TAGS' | 'EDIT' | 'RAW'>('SUMMARY');
  const hasValidTags = inv.data?.line_items.some(it => it.code_status === 'VALID');

  return (
    <div className={`bg-white rounded-[40px] border border-slate-200 shadow-sm overflow-hidden transition-all ${isPreviewing ? 'ring-2 ring-indigo-500 shadow-xl' : ''}`}>
      <div className="p-8 flex items-center justify-between cursor-pointer hover:bg-slate-50/50" onClick={onToggle}>
        <div className="flex items-center space-x-6">
          <div className="relative group/thumb" onClick={onTogglePreview}>
            <img src={inv.previewUrl} className="w-16 h-16 rounded-[20px] object-cover shadow-inner border border-slate-100" />
            <div className="absolute inset-0 bg-black/40 opacity-0 group-hover/thumb:opacity-100 rounded-[20px] flex items-center justify-center transition-all"><Search className="w-6 h-6 text-white" /></div>
            {inv.status === 'NEEDS_REVIEW' && <div className="absolute -top-1 -right-1 bg-amber-500 text-white p-1 rounded-full shadow-lg border-2 border-white"><AlertCircle className="w-3.5 h-3.5" /></div>}
          </div>
          <div>
            <h3 className="text-lg font-black text-slate-900 tracking-tight leading-none mb-2">{inv.data?.invoice_number || `DOC_${inv.id.substring(0,5)}`}</h3>
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{inv.sellerName}</p>
          </div>
        </div>
        <div className="flex items-center space-x-10">
          <div className="text-right">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Total</p>
            <p className="text-lg font-black text-slate-900 leading-none">{inv.data?.totals.total ? `$${inv.data.totals.total.toLocaleString()}` : 'Not found'}</p>
          </div>
          <div className={`px-4 py-1.5 rounded-full text-[9px] font-black uppercase border ${inv.status === 'DONE' ? 'bg-emerald-50 text-emerald-700 border-emerald-100' : 'bg-amber-50 text-amber-700 border-amber-100'}`}>{inv.status.replace('_', ' ')}</div>
          <div className="text-slate-300">{expanded ? <ChevronUp className="w-5 h-5" /> : <ChevronDown className="w-5 h-5" />}</div>
        </div>
      </div>

      {expanded && (
        <div className="border-t border-slate-100 bg-white">
          <div className="flex bg-slate-50/50 border-b border-slate-100 px-8 flex-wrap">
            <TabBtn label="Summary" active={tab === 'SUMMARY'} onClick={() => setTab('SUMMARY')} />
            <TabBtn label="Inventory" active={tab === 'EDIT'} onClick={() => setTab('EDIT')} />
            <TabBtn label="EDI" active={tab === 'EDI'} onClick={() => setTab('EDI')} />
            {hasValidTags && <TabBtn label="Logistics" active={tab === 'TAGS'} onClick={() => setTab('TAGS')} />}
            <TabBtn label="Raw Text" active={tab === 'RAW'} onClick={() => setTab('RAW')} />
          </div>
          <div className="p-8">
            {tab === 'SUMMARY' && (
              <div className="space-y-8">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                  <div className="space-y-6">
                    <div className="bg-slate-50 p-6 rounded-3xl border border-slate-100">
                      <div className="flex items-center space-x-3 mb-4 text-slate-400"><FileText className="w-4 h-4" /><span className="text-[10px] font-black uppercase tracking-widest">Facts</span></div>
                      <div className="space-y-4">
                        <SummaryItem label="Date" value={inv.data?.invoice_date || 'N/A'} />
                        <SummaryItem label="Seller" value={inv.data?.seller.name || 'N/A'} />
                        <SummaryItem label="Method" value={inv.extractionMethod} />
                      </div>
                    </div>
                    <div className="flex gap-2">
                       <button onClick={() => onRetry('AGRESSIVE_OCR')} className="flex-1 py-3 bg-white border border-slate-200 rounded-2xl text-[9px] font-black uppercase text-slate-500 hover:bg-slate-50">Retry (Deep OCR)</button>
                       <button onClick={() => onRetry('GEMINI_ONLY')} className="flex-1 py-3 bg-indigo-50 border border-indigo-100 rounded-2xl text-[9px] font-black uppercase text-indigo-600 hover:bg-indigo-100">Retry (Gemini)</button>
                    </div>
                  </div>
                  <div className="bg-indigo-50/30 p-8 rounded-[40px] border border-indigo-100 flex flex-col h-full">
                    <div className="flex items-center space-x-3 mb-6 text-indigo-400"><Search className="w-5 h-5" /><span className="text-[10px] font-black uppercase tracking-widest">Extraction Intelligence</span></div>
                    <p className="text-slate-700 font-medium leading-relaxed italic">"{inv.data?.info_summary || "No summary available."}"</p>
                  </div>
                </div>
              </div>
            )}

            {tab === 'EDIT' && (
              <div className={`flex gap-8 ${isPreviewing ? 'flex-row' : 'flex-col'}`}>
                <div className={`space-y-8 ${isPreviewing ? 'w-2/3' : 'w-full'}`}>
                  <div className="flex items-center justify-between">
                    <div><h4 className="text-sm font-black text-slate-900 uppercase tracking-widest leading-none">Line Inventory</h4></div>
                    <div className="flex items-center space-x-3">
                      <button onClick={onAddLine} className="flex items-center px-6 py-3 bg-white border border-slate-200 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-slate-50"><Plus className="w-3.5 h-3.5 mr-2" /> Add Line</button>
                      <button onClick={() => onSync(inv.id)} className="px-6 py-3 bg-indigo-600 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-xl flex items-center hover:bg-indigo-700"><RefreshCw className="w-3.5 h-3.5 mr-2" /> Sync EDI</button>
                    </div>
                  </div>
                  {inv.data?.line_items.length === 0 ? (
                    <div className="p-12 text-center bg-slate-50 rounded-[32px] border-2 border-dashed border-slate-200">
                      <HelpCircle className="w-12 h-12 text-slate-300 mx-auto mb-4" />
                      <p className="text-slate-500 font-bold">No line items detected.</p>
                      <p className="text-[10px] text-slate-400 mt-1 uppercase">Review raw text or add manually.</p>
                    </div>
                  ) : (
                    <div className="border border-slate-200 rounded-[32px] overflow-hidden shadow-sm bg-white overflow-x-auto">
                      <table className="w-full text-left text-[11px] font-black min-w-[600px]">
                        <thead className="bg-slate-50 border-b border-slate-200 text-slate-400 uppercase tracking-widest">
                          <tr><th className="px-4 py-4 w-12 text-center">Ln</th><th className="px-4 py-4">Description</th><th className="px-4 py-4 w-16 text-center">Qty</th><th className="px-4 py-4 w-24 text-center">Price</th><th className="px-4 py-4">Identifier</th><th className="px-4 py-4 w-20 text-center">Status</th></tr>
                        </thead>
                        <tbody className="divide-y divide-slate-100">
                          {inv.data?.line_items.map((item, i) => (
                            <tr key={i} className="hover:bg-slate-50/30">
                              <td className="px-4 py-4 text-center">{item.line_no}</td>
                              <td className="px-4 py-4"><input value={item.description} onChange={e => onEdit(inv.id, i, 'description', e.target.value)} className="w-full bg-transparent border-none p-0 focus:ring-0 uppercase" /></td>
                              <td className="px-4 py-4"><input type="number" value={item.qty || ''} onChange={e => onEdit(inv.id, i, 'qty', parseFloat(e.target.value))} className="bg-slate-100 border-none rounded-lg px-2 py-1 w-full text-center" /></td>
                              <td className="px-4 py-4"><input type="number" value={item.unit_price || ''} onChange={e => onEdit(inv.id, i, 'unit_price', parseFloat(e.target.value))} className="bg-slate-100 border-none rounded-lg px-2 py-1 w-full text-center" /></td>
                              <td className="px-4 py-4"><input value={item.code_value} onChange={e => onEdit(inv.id, i, 'code_value', e.target.value)} className={`bg-white border rounded-lg px-3 py-1.5 w-full font-mono ${item.code_status === 'INVALID' ? 'border-red-300 text-red-600' : 'border-indigo-200 text-indigo-600'}`} /></td>
                              <td className="px-4 py-4 text-center"><span className={`px-2 py-1 rounded-full text-[9px] border ${item.code_status === 'VALID' ? 'bg-emerald-50 text-emerald-600 border-emerald-100' : 'bg-red-50 text-red-600 border-red-100'}`}>{item.code_status}</span></td>
                            </tr>
                          ))}
                        </tbody>
                      </table>
                    </div>
                  )}
                </div>
                {isPreviewing && <div className="w-1/3 min-h-[500px] h-[700px] sticky top-8"><ZoomableImage src={inv.previewUrl} onClose={onClosePreview} /></div>}
              </div>
            )}

            {tab === 'RAW' && (
              <div className="space-y-6">
                <div className="flex items-center space-x-2 text-slate-400 mb-2"><Terminal className="w-4 h-4" /><span className="text-[10px] font-black uppercase tracking-widest">Document Stream</span></div>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <span className="text-[9px] font-black text-slate-400 uppercase">OCR Output ({inv.extractionMethod})</span>
                    <div className="bg-slate-900 rounded-[32px] p-8 font-mono text-[11px] text-slate-300 h-[400px] overflow-auto border border-slate-800 leading-relaxed whitespace-pre-wrap">{inv.data?.raw_text || "No local OCR data."}</div>
                  </div>
                  <div className="space-y-2">
                    <span className="text-[9px] font-black text-slate-400 uppercase">Gemini Vision (Transcription)</span>
                    <div className="bg-slate-950 rounded-[32px] p-8 font-mono text-[11px] text-indigo-300 h-[400px] overflow-auto border border-indigo-900 leading-relaxed whitespace-pre-wrap">{inv.data?.gemini_transcription || "No Gemini transcription."}</div>
                  </div>
                </div>
              </div>
            )}

            {tab === 'EDI' && (
              <div className="space-y-6">
                <div className="flex items-center justify-between"><h4 className="text-sm font-black text-slate-900 uppercase tracking-widest">EDI X12 Stream</h4><div className="flex space-x-2"><button onClick={() => navigator.clipboard.writeText(inv.ediText)} className="flex items-center px-5 py-2.5 bg-slate-100 text-slate-600 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-slate-200 border border-slate-200 shadow-sm"><Copy className="w-3.5 h-3.5 mr-2" /> Copy</button><a href={`data:text/plain;charset=utf-8,${encodeURIComponent(inv.ediText)}`} download={ediDownloadName} className="flex items-center px-5 py-2.5 bg-indigo-600 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-indigo-700 shadow-xl"><Download className="w-3.5 h-3.5 mr-2" /> Download</a></div></div>
                <div className="bg-slate-950 rounded-[32px] p-10 font-mono text-[11px] text-emerald-400 leading-relaxed overflow-auto max-h-[500px] border border-slate-800 shadow-2xl">
                  {inv.ediText.split('~').map((seg, i) => (<div key={i} className="mb-1 hover:bg-white/5 rounded px-2 transition-colors"><span className="text-emerald-800 mr-4 select-none">{(i+1).toString().padStart(3, '0')}</span>{seg}<span className="text-emerald-700 opacity-50">~</span></div>))}
                </div>
              </div>
            )}

            {tab === 'TAGS' && (
              <div className="space-y-12">
