import { CodeValidationResult } from '../types';

export const validateUPC = (code: string): boolean => {
  const clean = code.replace(/\D/g, ''); // Strip all non-digits
  if (clean.length !== 12) return false;
  if (/^(.)\1+$/.test(clean)) return false; // Reject repeated digits

  let sum = 0;
  for (let i = 0; i < 11; i++) {
    sum += parseInt(clean[i]) * (i % 2 === 0 ? 3 : 1);
  }
  const checkDigit = (10 - (sum % 10)) % 10;
  return checkDigit === parseInt(clean[11]);
};

export const validateEAN = (code: string): boolean => {
  const clean = code.replace(/\D/g, ''); // Strip all non-digits
  if (clean.length !== 13) return false;
  if (/^(.)\1+$/.test(clean)) return false;

  let sum = 0;
  for (let i = 0; i < 12; i++) {
    sum += parseInt(clean[i]) * (i % 2 === 0 ? 1 : 3);
  }
  const checkDigit = (10 - (sum % 10)) % 10;
  return checkDigit === parseInt(clean[12]);
};

export const validateSSCC = (code: string): boolean => {
  const clean = code.replace(/\D/g, ''); // Strip all non-digits
  if (clean.length !== 18) return false;

  let sum = 0;
  for (let i = 0; i < 17; i++) {
    sum += parseInt(clean[i]) * (i % 2 === 0 ? 3 : 1);
  }
  const checkDigit = (10 - (sum % 10)) % 10;
  return checkDigit === parseInt(clean[17]);
};

export const validateCode = (value: string): CodeValidationResult => {
  if (!value) return { value: '', type: 'UNKNOWN', isValid: false };

  // Try cleaning strictly for numeric matches first
  const strictlyDigits = value.replace(/\D/g, '');

  if (strictlyDigits.length === 12) {
    return { value: strictlyDigits, type: 'UPC-A', isValid: validateUPC(strictlyDigits) };
  }
  if (strictlyDigits.length === 11) {
    const padded = '0' + strictlyDigits;
    return { value: padded, type: 'UPC-A', isValid: validateUPC(padded) };
  }
  if (strictlyDigits.length === 13) {
    return { value: strictlyDigits, type: 'EAN-13', isValid: validateEAN(strictlyDigits) };
  }
  if (strictlyDigits.length === 18) {
    return { value: strictlyDigits, type: 'SSCC-18', isValid: validateSSCC(strictlyDigits) };
  }

  // Alphanumeric UCI logic (keeps hyphens/dots if they exist)
  const cleanAlpha = value.replace(/\s+/g, '');
  if (cleanAlpha.length >= 8 && cleanAlpha.length <= 30 && /^[A-Z0-9\-_.]+$/i.test(cleanAlpha)) {
    return { value: cleanAlpha, type: 'UCI', isValid: true };
  }

  return { value: cleanAlpha, type: 'UNKNOWN', isValid: false };
};

