const getBase64 = (file: File): Promise<string> => {
  return new Promise((resolve) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => resolve((reader.result as string).split(',')[1]);
  });
};

export const transcribeOnly = async (files: File[]): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const parts = await Promise.all(files.map(async (f) => ({
    inlineData: { mimeType: f.type, data: await getBase64(f) }
  })));

  const prompt = "Transcribe only clearly visible text from these documents. Group by logical sections. Do not guess. Return plain text.";
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: { parts: [...parts, { text: prompt }] }
  });

  return response.text || "";
};

export const extractInvoiceData = async (
  files: File[],
  ocrContext: string
): Promise<DocumentResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const parts = await Promise.all(files.map(async (f) => ({
    inlineData: { mimeType: f.type, data: await getBase64(f) }
  })));

  const prompt = `
    Act as "Invoice2EDI + RetailTag Agent". 
    Goal: Extract data from these images and return exactly ONE JSON object following the schema.

    CRITICAL RULES:
    1. Strip spaces from UPCs; exactly 12 digits for UPC-A (pad with 0 if 11).
    2. Pricing: Calculate RETAIL = COST / (1 - MARGIN). 
       Defaults: alcohol 0.18, tobacco 0.12, energy 0.25, snacks 0.35, grocery 0.20, other 0.20.
    3. EDI: Build X12 810 segments with "~" terminator and "*" separator.
    4. Labels: should_generate=true if any valid UPC/GTIN/UCI exists.

    JSON SCHEMA:
    {
      "doc_id": "string",
      "doc_type": "invoice|receipt|unknown",
      "vendor": {"name":"", "address":"", "city":"", "state":"", "zip":"", "phone":""},
      "buyer": {"name":"", "address":"", "city":"", "state":"", "zip":""},
      "invoice": {"number":"", "date":"YYYY-MM-DD", "po":"", "currency":"USD"},
      "line_items": [
        {"line_no":1, "description":"", "qty":1, "uom":"EA", "unit_price":0.0, "line_total":0.0, "code_value":"", "code_type":"UPC-A|UCI", "category":"snacks", "margin_percent":0.35, "retail_price":0.0}
      ],
      "pricing": {"total_cost":0.0, "total_retail":0.0, "average_margin":0.0},
      "edi_810": {"version":"X12 004010", "segments":[], "edi_string":""},
      "labels": {"should_generate":true, "reason":"", "valid_from":"", "valid_to":"", "label_items":[]},
      "quality": {"status":"ok|needs_review", "issues":[], "field_confidence":{}}
    }

    OCR Context (HINT): ${ocrContext}
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: { parts: [...parts, { text: prompt }] },
    config: { responseMimeType: "application/json" }
  });

  try {
    return JSON.parse(response.text);
  } catch (e) {
    throw new Error("Failed to parse AI response. Retrying with transcription only.");
  }
};

import { DocumentResult } from '../types';

export const generateEDI810FromData = (data: DocumentResult): string => {
  const segments: string[] = [];
  const inv = data.invoice;
  const vendor = data.vendor;
  const buyer = data.buyer;

  // Header
  segments.push(`ST*810*0001`);

  const dateStr = inv.date.replace(/[-/]/g, '');
  if (inv.po) {
    segments.push(`BIG*${dateStr}*${inv.number}**${inv.po}`);
  } else {
    segments.push(`BIG*${dateStr}*${inv.number}`);
  }

  // Seller
  if (vendor.name) {
    segments.push(`N1*SU*${vendor.name.toUpperCase().substring(0, 35)}`);
    if (vendor.address) segments.push(`N3*${vendor.address.toUpperCase().substring(0, 35)}`);
    if (vendor.city) segments.push(`N4*${vendor.city.toUpperCase()}*${(vendor.state || '').toUpperCase()}*${(vendor.zip || '').replace(/\D/g, '')}`);
  }

  // Buyer
  if (buyer.name) {
    segments.push(`N1*BY*${buyer.name.toUpperCase().substring(0, 35)}`);
    if (buyer.address) segments.push(`N3*${buyer.address.toUpperCase().substring(0, 35)}`);
    if (buyer.city) segments.push(`N4*${buyer.city.toUpperCase()}*${(buyer.state || '').toUpperCase()}*${(buyer.zip || '').replace(/\D/g, '')}`);
  }

  // Items
  data.line_items.forEach((it) => {
    const upcPart = it.code_value ? `**UP*${it.code_value}` : '';
    segments.push(`IT1*${it.line_no}*${it.qty}*${it.uom}*${it.unit_price}${upcPart}`);
    if (it.description) segments.push(`PID*F****${it.description.toUpperCase().substring(0, 80)}`);
    if (it.retail_price) segments.push(`CTP**RTL*${it.retail_price.toFixed(2)}`);
  });

  // Totals
  const totalCents = Math.round(data.pricing.total_cost * 100);
  segments.push(`TDS*${totalCents}`);
  segments.push(`CTT*${data.line_items.length}`);

  segments.push(`SE*${segments.length + 1}*0001`);

  return segments.join('~') + '~';
};

import { jsPDF } from 'jspdf';
import JsBarcode from 'jsbarcode';
import { DocumentResult } from '../types';

export const generateRetailLabelPDF = async (data: DocumentResult): Promise<Blob | null> => {
  if (!data.labels.should_generate || data.labels.label_items.length === 0) return null;

  const doc = new jsPDF({ orientation: 'p', unit: 'mm', format: 'a4' });
  const margin = 10;
  const colWidth = 63;
  const rowHeight = 45;
  const cols = 3;

  doc.setFont('helvetica', 'bold');
  doc.setFontSize(10);
  doc.text(`Retail Tags: ${data.invoice.number || 'Batch'}`, margin, margin);
  doc.setFontSize(7);
  doc.text(`Valid: ${data.labels.valid_from} - ${data.labels.valid_to}`, margin, margin + 4);
  doc.line(margin, margin + 6, 200, margin + 6);

  let currentX = margin;
  let currentY = margin + 12;

  for (let i = 0; i < data.labels.label_items.length; i++) {
    const item = data.labels.label_items[i];

    // Border
    doc.setDrawColor(240);
    doc.rect(currentX, currentY, colWidth - 2, rowHeight - 2);

    // Price (Large)
    doc.setFontSize(18);
    doc.setTextColor(0);
    doc.setFont('helvetica', 'bold');
    doc.text(`$${item.retail_price.toFixed(2)}`, currentX + colWidth / 2, currentY + 12, { align: 'center' });

    // Description
    doc.setFontSize(7);
    doc.text(item.description_short.toUpperCase(), currentX + colWidth / 2, currentY + 18, { align: 'center' });

    // Barcode
    try {
      const canvas = document.createElement('canvas');
      let format = 'CODE128';
      let cleanCode = item.barcode_value.replace(/\s+/g, '');

      if (item.barcode_type === 'UPC-A') {
        format = 'UPC';
        cleanCode = cleanCode.replace(/\D/g, '');
      }

      JsBarcode(canvas, cleanCode, {
        format, displayValue: false, margin: 0, width: 4, height: 50, background: "#ffffff"
      });

      const imgData = canvas.toDataURL('image/png');
      doc.addImage(imgData, 'PNG', currentX + 8, currentY + 22, colWidth - 18, 14);
    } catch (err) {
      doc.setFontSize(5);
      doc.setTextColor(200, 0, 0);
      doc.text('BARCODE RENDER ERROR', currentX + colWidth / 2, currentY + 28, { align: 'center' });
    }

    // Value
    doc.setFontSize(8);
    doc.setTextColor(50);
    doc.setFont('helvetica', 'normal');
    doc.text(item.barcode_value, currentX + colWidth / 2, currentY + rowHeight - 4, { align: 'center' });

    // Move to next spot
    if ((i + 1) % cols === 0) {
      currentX = margin;
      currentY += rowHeight;
    } else {
      currentX += colWidth;
    }

    if (currentY + rowHeight > 280 && i < data.labels.label_items.length - 1) {
      doc.addPage();
      currentX = margin;
      currentY = margin + 12;
    }
  }

  return doc.output('blob');
};

