           {batch.invoices.map(inv => (
             <button key={inv.id} onClick={() => setExpandedDoc(inv.id)} className={`w-full p-4 rounded-2xl text-[10px] font-black uppercase tracking-widest text-left transition-all ${expandedDoc === inv.id ? 'bg-slate-900 text-white shadow-xl' : 'text-slate-500 hover:bg-slate-50'}`}>
               {inv.sellerName || 'Processing...'}
             </button>
           ))}
        </div>
        <button onClick={startOver} className="mt-8 py-5 bg-slate-900 text-white rounded-[24px] font-black uppercase text-[10px] tracking-[0.2em] shadow-2xl flex items-center justify-center"><RotateCcw className="w-4 h-4 mr-3" />New Batch</button>
