      <main className="flex-1 p-16 max-w-7xl mx-auto">
        {expandedDoc ? (
          <DocResultView 
            inv={batch.invoices.find(i => i.id === expandedDoc)!} 
            isPreviewing={previewingDocId === expandedDoc}
