export default App;

export type AppStep = 'UPLOAD' | 'PROCESSING' | 'RESULTS';

export type DocType = 'invoice' | 'receipt' | 'unknown';

export interface Party {
  name: string;
  address: string;
  city: string;
  state: string;
  zip: string;
  account_id?: string;
  phone?: string;
}

export interface LineItem {
  line_no: number;
  description: string;
  qty: number | null;
  uom: string;
  unit_price: number | null; // Cost
  line_total: number | null;
  code_type: string;
  code_value: string;
  code_status: 'VALID' | 'INVALID' | 'UNVERIFIED';
  category: string;
  margin_percent: number;
  retail_price: number;
}

export interface LabelItem {
  description_short: string;
  barcode_value: string;
  barcode_type: string;
  retail_price: number;
  sku_or_item: string;
}

export interface DocumentResult {
  doc_id: string;
  doc_type: DocType;
  vendor: Party;
  buyer: Party;
  invoice: {
    number: string;
    date: string;
    po?: string;
    currency: string;
  };
  line_items: LineItem[];
  pricing: {
    total_cost: number;
    total_retail: number;
    average_margin: number;
  };
  edi_810: {
    version: string;
    segments: string[];
    edi_string: string;
  };
  labels: {
    should_generate: boolean;
    reason: string;
    valid_from: string;
    valid_to: string;
    label_items: LabelItem[];
  };
  quality: {
    status: 'ok' | 'needs_review';
    issues: string[];
    field_confidence: Record<string, number>;
  };
  raw_text?: string;
}

export interface InvoiceState {
  id: string;
  files: File[];
  previewUrls: string[];
  status: 'QUEUED' | 'RUNNING' | 'DONE' | 'NEEDS_REVIEW';
  progress: number;
  currentTask: string;
  sellerName: string;
  data: DocumentResult | null;
  pdfBlobUrl: string | null;
  retryCount: number;
  extractionMethod: 'OCR' | 'HYBRID' | 'GEMINI';
}

export interface BatchState {
  name: string;
  invoices: InvoiceState[];
}

export enum ProcessingStep {
  RUNNING_OCR = 'RUNNING_OCR',
  UNDERSTANDING_INVOICE = 'UNDERSTANDING_INVOICE',
  GENERATING_EDI = 'GENERATING_EDI',
  GENERATING_PDF = 'GENERATING_PDF',
  COMPLETED = 'COMPLETED'
}

// Missing types for logistics and barcode services
export interface DetectedCode {
  value: string;
  type: string;
  price?: number;
  unit?: string;
  description?: string;
  dateLeft?: string;
  dateRight?: string;
}

export interface CodeValidationResult {
  value: string;
  type: string;
  isValid: boolean;
}

