import { DocumentResult } from '../types';

/**
 * Generates an EDI 810 X12 stream from extracted document data.
 */
export const generateEDI810FromData = (data: DocumentResult | null): string => {
  if (!data) return '';
  const segments: string[] = [];

  // Transaction Header
  segments.push(`ST*810*0001`);

  // BIG Segment: BIG*<YYYYMMDD>*<InvoiceNumber>***
  const dateStr = (data.invoice.date || '').replace(/[-/]/g, '');
  const invNo = data.invoice.number || '';
  const poNo = data.invoice.po || '';

  // Standard X12 BIG segment formatting
  if (poNo) {
    segments.push(`BIG*${dateStr}*${invNo}**${poNo}*`);
  } else {
    segments.push(`BIG*${dateStr}*${invNo}***`);
  }

  // N1 Loop (Seller)
  if (data.vendor.name) {
    segments.push(`N1*SU*${data.vendor.name.toUpperCase().substring(0, 35)}`);
    if (data.vendor.address) segments.push(`N3*${data.vendor.address.toUpperCase().substring(0, 35)}`);
    if (data.vendor.city) {
      const city = data.vendor.city.toUpperCase();
      const state = (data.vendor.state || '').toUpperCase();
      const zip = (data.vendor.zip || '').replace(/[^\d]/g, '');
      segments.push(`N4*${city}*${state}*${zip}`);
    }
  }

  // N1 Loop (Buyer)
  if (data.buyer.name) {
    segments.push(`N1*BY*${data.buyer.name.toUpperCase().substring(0, 35)}`);
    if (data.buyer.address) segments.push(`N3*${data.buyer.address.toUpperCase().substring(0, 35)}`);
    if (data.buyer.city) {
      const city = data.buyer.city.toUpperCase();
      const state = (data.buyer.state || '').toUpperCase();
      const zip = (data.buyer.zip || '').replace(/[^\d]/g, '');
      segments.push(`N4*${city}*${state}*${zip}`);
    }
  }

  // IT1 Loops
  data.line_items.forEach((item) => {
    const qty = item.qty || 0;
    const price = item.unit_price || 0;
    const uom = item.uom || 'CA';

    // Include UP qualifier only for valid identifiers
    const upPart = item.code_status === 'VALID' ? `**UP*${item.code_value}` : '';
    segments.push(`IT1*${item.line_no}*${qty}*${uom}*${price}${upPart}`);

    if (item.description) {
      segments.push(`PID*F****${item.description.toUpperCase().substring(0, 80)}`);
    }
  });

  // TDS - Amount Summary
  if (data.pricing.total_cost !== null) {
    const cents = Math.round(data.pricing.total_cost * 100);
    segments.push(`TDS*${cents}`);
  }

  // CTT - Transaction Totals
  segments.push(`CTT*${data.line_items.length}`);

  // SE - Trailer
  const segCount = segments.length + 1;
  segments.push(`SE*${segCount}*0001`);

  return segments.join('~') + '~';
};

import { jsPDF } from 'jspdf';
import JsBarcode from 'jsbarcode';
import { DocumentResult } from '../types';

/**
 * Generates a retail label sheet PDF from extracted document data.
 */
export const generateRetailLabelPDF = async (data: DocumentResult): Promise<Blob | null> => {
  const validCodes = data.line_items.filter(it => it.code_status === 'VALID' || it.code_value);
  if (validCodes.length === 0) return null;

  const doc = new jsPDF({ orientation: 'p', unit: 'mm', format: 'a4' });
  const margin = 10;
  const colWidth = 63;
  const rowHeight = 45;
  const cols = 3;

  doc.setFont('helvetica', 'bold');
  doc.setFontSize(10);
  doc.text(`Logistic Tags: ${data.invoice.number || 'Batch'}`, margin, margin);
  doc.line(margin, margin + 2, 200, margin + 2);

  let currentX = margin;
  let currentY = margin + 10;

  for (let i = 0; i < data.line_items.length; i++) {
    const item = data.line_items[i];
    if (!item.code_value) continue;

    // Label Frame
    doc.setDrawColor(240);
    doc.rect(currentX, currentY, colWidth - 2, rowHeight - 2);

    // Header Meta
    doc.setFontSize(5);
    doc.setTextColor(150);
    doc.text(new Date().toLocaleDateString(), currentX + 3, currentY + 4);

    // Price Display
    doc.setFontSize(16);
    doc.setTextColor(0);
    doc.setFont('helvetica', 'bold');
    const price = item.retail_price ? `$${item.retail_price.toFixed(2)}` : '$---';
    doc.text(price, currentX + colWidth / 2, currentY + 10, { align: 'center' });

    // Description
    doc.setFontSize(6);
    const desc = item.description.toUpperCase().substring(0, 30);
    doc.text(desc, currentX + colWidth / 2, currentY + 15, { align: 'center' });

    // Barcode Generation
    if (item.code_status !== 'VALID') {
      doc.setDrawColor(255, 230, 230);
      doc.setFillColor(255, 245, 245);
      doc.roundedRect(currentX + 8, currentY + 18, colWidth - 18, 16, 2, 2, 'FD');
      doc.setFontSize(6);
      doc.setTextColor(200, 0, 0);
      doc.text('INVALID — EDIT REQUIRED', currentX + colWidth / 2, currentY + 25, { align: 'center' });
      doc.setFontSize(5);
      doc.text(item.code_value, currentX + colWidth / 2, currentY + 28, { align: 'center' });
    } else {
      try {
        const canvas = document.createElement('canvas');
        let format = 'CODE128';
        if (item.code_type === 'UPC-A') format = 'UPC';
        if (item.code_type === 'EAN-13') format = 'EAN13';

        JsBarcode(canvas, item.code_value, {
          format,
          displayValue: false,
          margin: 0,
          width: 4,
          height: 50,
          background: "#ffffff"
        });

        const imgData = canvas.toDataURL('image/png');
        doc.addImage(imgData, 'PNG', currentX + 8, currentY + 18, colWidth - 18, 16);
      } catch (err) {
        doc.setFontSize(6);
        doc.setTextColor(200, 0, 0);
        doc.text('RENDER ERROR', currentX + colWidth / 2, currentY + 26, { align: 'center' });
      }
    }

    // Human Readable Format
    doc.setFontSize(8);
    doc.setTextColor(0);
    doc.setFont('helvetica', 'normal');
    doc.text(item.code_value, currentX + colWidth / 2, currentY + rowHeight - 6, { align: 'center' });

    // Cell Positioning Logic
    if ((i + 1) % cols === 0) {
      currentX = margin;
      currentY += rowHeight;
    } else {
      currentX += colWidth;
    }

    if (currentY + rowHeight > 280) {
      doc.addPage();
      currentX = margin;
      currentY = margin + 10;
    }
  }

  return doc.output('blob');
};

import { GoogleGenAI } from "@google/genai";
import { DocumentResult } from "../types";

const getBase64 = (file: File): Promise<string> => {
  return new Promise((resolve) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => resolve((reader.result as string).split(',')[1]);
  });
};

export const transcribeOnly = async (files: File[]): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const parts = await Promise.all(files.map(async (f) => ({
    inlineData: { mimeType: f.type, data: await getBase64(f) }
  })));

  const prompt = "Transcribe only clearly visible text from these documents. Group by logical sections. Do not guess. Return plain text. Focus on Vendor headers, Totals, and Line Items.";
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: { parts: [...parts, { text: prompt }] }
  });

  return response.text || "";
};

const normalizeData = (data: any): DocumentResult => {
  // Ensure basic structure exists to prevent "Cannot read properties of undefined"
  return {
    doc_id: data.doc_id || Math.random().toString(36).substring(7),
    doc_type: data.doc_type || 'unknown',
    vendor: {
      name: data.vendor?.name || '',
      address: data.vendor?.address || '',
      city: data.vendor?.city || '',
      state: data.vendor?.state || '',
      zip: data.vendor?.zip || '',
      phone: data.vendor?.phone || ''
    },
    buyer: {
      name: data.buyer?.name || '',
      address: data.buyer?.address || '',
      city: data.buyer?.city || '',
      state: data.buyer?.state || '',
      zip: data.buyer?.zip || ''
    },
    invoice: {
      number: data.invoice?.number || '',
      date: data.invoice?.date || '',
      po: data.invoice?.po || '',
      currency: data.invoice?.currency || 'USD'
    },
    line_items: Array.isArray(data.line_items) ? data.line_items.map((it: any, idx: number) => ({
      line_no: it.line_no || idx + 1,
      description: it.description || 'Unknown Item',
      qty: typeof it.qty === 'number' ? it.qty : 1,
      uom: it.uom || 'EA',
      unit_price: typeof it.unit_price === 'number' ? it.unit_price : 0,
      line_total: typeof it.line_total === 'number' ? it.line_total : 0,
      code_value: it.code_value || '',
      code_type: it.code_type || 'UPC-A',
      code_status: it.code_status || 'UNVERIFIED',
      category: it.category || 'other',
      margin_percent: typeof it.margin_percent === 'number' ? it.margin_percent : 0.2,
      retail_price: typeof it.retail_price === 'number' ? it.retail_price : 0
    })) : [],
    pricing: {
      total_cost: typeof data.pricing?.total_cost === 'number' ? data.pricing.total_cost : 0,
      total_retail: typeof data.pricing?.total_retail === 'number' ? data.pricing.total_retail : 0,
      average_margin: typeof data.pricing?.average_margin === 'number' ? data.pricing.average_margin : 0
    },
    edi_810: {
      version: data.edi_810?.version || 'X12 004010',
      segments: Array.isArray(data.edi_810?.segments) ? data.edi_810.segments : [],
      edi_string: data.edi_810?.edi_string || ''
    },
    labels: {
      should_generate: !!data.labels?.should_generate,
      reason: data.labels?.reason || '',
      valid_from: data.labels?.valid_from || '',
      valid_to: data.labels?.valid_to || '',
      label_items: Array.isArray(data.labels?.label_items) ? data.labels.label_items : []
    },
    quality: {
      status: data.quality?.status || 'needs_review',
      issues: Array.isArray(data.quality?.issues) ? data.quality.issues : [],
      field_confidence: data.quality?.field_confidence || { total: 0.5 }
    },
    raw_text: data.raw_text || ''
  };
};

export const extractInvoiceData = async (
  files: File[],
  ocrContext: string
): Promise<DocumentResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const parts = await Promise.all(files.map(async (f) => ({
    inlineData: { mimeType: f.type, data: await getBase64(f) }
  })));

  const prompt = `
    Act as "Invoice2EDI + RetailTag Agent". 
    Goal: Extract data from these images and return exactly ONE JSON object following the schema.

    CRITICAL RULES:
    1. Strip spaces from UPCs; exactly 12 digits for UPC-A. Preserve leading zeros.
    2. Pricing: Calculate RETAIL = COST / (1 - MARGIN). 
       Defaults: alcohol 0.18, tobacco 0.12, energy 0.25, snacks 0.35, grocery 0.20, other 0.20.
    3. EDI: Build X12 810 segments with "~" terminator and "*" separator.
    4. Labels: should_generate=true if any valid UPC/GTIN/UCI exists.
    5. If a field is missing, leave as empty string or null. Do not guess wildly.

    JSON SCHEMA:
    {
      "doc_id": "string",
      "doc_type": "invoice|receipt|unknown",
      "vendor": {"name":"", "address":"", "city":"", "state":"", "zip":"", "phone":""},
      "buyer": {"name":"", "address":"", "city":"", "state":"", "zip":""},
      "invoice": {"number":"", "date":"YYYY-MM-DD", "po":"", "currency":"USD"},
      "line_items": [
        {"line_no":1, "description":"", "qty":1, "uom":"EA", "unit_price":0.0, "line_total":0.0, "code_value":"", "code_type":"UPC-A|UCI", "category":"snacks", "margin_percent":0.35, "retail_price":0.0}
      ],
      "pricing": {"total_cost":0.0, "total_retail":0.0, "average_margin":0.0},
      "edi_810": {"version":"X12 004010", "segments":[], "edi_string":""},
      "labels": {"should_generate":true, "reason":"", "valid_from":"", "valid_to":"", "label_items":[]},
      "quality": {"status":"ok|needs_review", "issues":[], "field_confidence":{"total":0.9, "vendor":0.8, "line_items":0.7}}
    }

    OCR Context (HINT): ${ocrContext}
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: { parts: [...parts, { text: prompt }] },
    config: { responseMimeType: "application/json" }
  });

  try {
    const text = response.text || "{}";
    const rawData = JSON.parse(text);
    return normalizeData(rawData);
  } catch (e) {
    console.error("AI JSON Parse Error:", e);
    // Return empty normalized object rather than throwing to avoid whole job failure
    return normalizeData({});
  }
};

