  FileCheck, ChevronDown, ChevronUp, RefreshCw, ExternalLink, 
  Settings2, Package, ZoomIn, ZoomOut, Maximize2, X, Search, 
  User, Truck, FileText, Barcode, HelpCircle, Plus, Terminal,
  ClipboardCheck, ShoppingCart, Percent, RotateCw, Wand2, Image as ImageIcon
} from 'lucide-react';
import { 
  AppStep, BatchState, InvoiceState, DocumentResult, LineItem 
} from './types';
import { runOCRPipeline } from './services/ocrService';
import { preprocessForOCR } from './services/imagePreprocessor';
import { extractInvoiceData, transcribeOnly } from './services/geminiService';
import { generateEDI810FromData } from './services/ediService';
import { generateRetailLabelPDF } from './services/pdfService';
import JsBarcode from 'jsbarcode';

// --- Sub-components ---

const BarcodePreview: React.FC<{ code: string; type: string }> = ({ code, type }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  useEffect(() => {
    if (canvasRef.current && code) {
      try {
        let format = 'CODE128';
        let cleanCode = code;
        if (type === 'UPC-A') { format = 'UPC'; cleanCode = code.replace(/\D/g, ''); }
        JsBarcode(canvasRef.current, cleanCode, {
          format, displayValue: true, fontSize: 14, height: 50, width: 2, margin: 10, background: "#ffffff"
        });
      } catch (err) { console.error("Barcode render error", err); }
    }
  }, [code, type]);
  return (
    <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm flex flex-col items-center">
      <canvas ref={canvasRef} className="max-w-full h-auto" />
    </div>
  );
};

const ZoomableImage: React.FC<{ src: string; rotation: number; onClose: () => void }> = ({ src, rotation, onClose }) => {
  const [zoom, setZoom] = useState(1);
  const [position, setPosition] = useState({ x: 0, y: 0 });
  const [isDragging, setIsDragging] = useState(false);
  const [dragStart, setDragStart] = useState({ x: 0, y: 0 });

  const handleZoomIn = () => setZoom(prev => Math.min(prev + 0.5, 5));
  const handleZoomOut = () => setZoom(prev => Math.max(prev - 0.5, 1));
  const handleReset = () => { setZoom(1); setPosition({ x: 0, y: 0 }); };

  const handleMouseDown = (e: React.MouseEvent) => {
    if (zoom > 1) { 
      setIsDragging(true); 
      setDragStart({ x: e.clientX - position.x, y: e.clientY - position.y }); 
    }
  };
  const handleMouseMove = (e: React.MouseEvent) => {
    if (isDragging) setPosition({ x: e.clientX - dragStart.x, y: e.clientY - dragStart.y });
  };
  const handleMouseUp = () => setIsDragging(false);

  return (
    <div className="flex flex-col h-full bg-slate-900 rounded-3xl overflow-hidden border border-slate-700 shadow-2xl">
      <div className="p-4 border-b border-slate-800 flex items-center justify-between bg-slate-900/50 backdrop-blur-md sticky top-0 z-10">
        <div className="flex items-center space-x-2">
          <button onClick={handleZoomOut} className="p-2 text-slate-400 hover:text-white hover:bg-slate-800 rounded-xl transition-all"><ZoomOut className="w-5 h-5" /></button>
          <span className="text-[10px] font-black text-slate-500 w-12 text-center uppercase tracking-widest">{Math.round(zoom * 100)}%</span>
          <button onClick={handleZoomIn} className="p-2 text-slate-400 hover:text-white hover:bg-slate-800 rounded-xl transition-all"><ZoomIn className="w-5 h-5" /></button>
          <button onClick={handleReset} className="p-2 text-slate-400 hover:text-white hover:bg-slate-800 rounded-xl transition-all"><Maximize2 className="w-5 h-5" /></button>
        </div>
        <button onClick={onClose} className="p-2 text-slate-400 hover:text-red-500 hover:bg-red-500/10 rounded-xl transition-all"><X className="w-5 h-5" /></button>
      </div>
      <div className="flex-1 overflow-hidden cursor-grab active:cursor-grabbing relative" onMouseDown={handleMouseDown} onMouseMove={handleMouseMove} onMouseUp={handleMouseUp} onMouseLeave={handleMouseUp}>
        <div className="w-full h-full flex items-center justify-center transition-transform duration-200 ease-out" style={{ transform: `translate(${position.x}px, ${position.y}px) scale(${zoom})`, transformOrigin: 'center' }}>
          <img src={src} alt="Invoice" className="max-w-full max-h-full object-contain pointer-events-none shadow-2xl" style={{ transform: `rotate(${rotation}deg)` }} />
        </div>
      </div>
      <div className="p-4 bg-slate-800/50 text-center"><p className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em]">Hold & Drag to Pan when zoomed</p></div>
    </div>
  );
};

// --- Main App ---

const App: React.FC = () => {
  const [step, setStep] = useState<AppStep>('UPLOAD');
  const [batch, setBatch] = useState<BatchState>({
    name: 'Batch_' + new Date().toISOString().slice(0, 10),
    invoices: []
  });
  const [expandedDoc, setExpandedDoc] = useState<string | null>(null);
  const [previewingDocId, setPreviewingDocId] = useState<string | null>(null);
  const [rotations, setRotations] = useState<Record<string, number>>({});

  const startOver = () => {
    batch.invoices.forEach(inv => { inv.previewUrls.forEach(url => URL.revokeObjectURL(url)); if (inv.pdfBlobUrl) URL.revokeObjectURL(inv.pdfBlobUrl); });
    setBatch({ name: 'Batch_' + new Date().toISOString().slice(0, 10), invoices: [] });
    setStep('UPLOAD');
    setPreviewingDocId(null);
  };

  const handleFiles = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!e.target.files) return;
    const files = Array.from(e.target.files) as File[];
    const newInvoices: InvoiceState[] = files.map(file => ({
      id: Math.random().toString(36).substring(7),
      files: [file], previewUrls: [URL.createObjectURL(file)], status: 'QUEUED', progress: 0,
      currentTask: 'Ready', sellerName: 'Waiting to process...', data: null, pdfBlobUrl: null, retryCount: 0, extractionMethod: 'OCR'
    }));
    setBatch(prev => ({ ...prev, invoices: [...prev.invoices, ...newInvoices] }));
  };

  const isResultWeak = (data: DocumentResult | null) => {
    if (!data) return true;
    if (!data.invoice || !data.invoice.number || !data.invoice.date) return true;
    if (!data.vendor || !data.vendor.name || !data.buyer || !data.buyer.name) return true;
    if (!data.line_items || data.line_items.length === 0) return true;
    if (!data.pricing || data.pricing.total_cost === 0) return true;
    return false;
  };

  const processInvoice = async (inv: InvoiceState) => {
    updateInv(inv.id, { status: 'RUNNING', progress: 5, currentTask: 'Pass 1: Standard OCR...' });
    let finalData: DocumentResult | null = null;
    let method: 'OCR' | 'HYBRID' | 'GEMINI' = 'OCR';
    let bestRawText = '';

    try {
      // Pass 1: Standard OCR
      const enhancedUrl1 = await preprocessForOCR(inv.files[0]);
      const ocr1 = await runOCRPipeline(enhancedUrl1);
      bestRawText = ocr1.fullText;

      updateInv(inv.id, { progress: 30, currentTask: 'Analyzing Pass 1...' });
      const data1 = await extractInvoiceData(inv.files, ocr1.fullText);
      finalData = data1;

      // Pass 2: Deep Analysis (Hybrid)
      if (isResultWeak(data1)) {
        updateInv(inv.id, { progress: 45, currentTask: 'Pass 2: Deep AI Extraction...' });
        method = 'HYBRID';
        const data2 = await extractInvoiceData(inv.files, ocr1.fullText + "\n[REQUEST_DEEP_SEARCH]"); 
        finalData = data2;

        // Pass 3: Gemini Vision Transcription
        if (isResultWeak(data2)) {
          updateInv(inv.id, { progress: 70, currentTask: 'Pass 3: Vision Transcription...' });
          method = 'GEMINI';
          const transcription = await transcribeOnly(inv.files);
          bestRawText = transcription;
          const data3 = await extractInvoiceData(inv.files, transcription);
          finalData = data3;
        }
      }

      if (finalData) {
        finalData.raw_text = bestRawText;
        updateInv(inv.id, { progress: 90, currentTask: 'Building Final Output...' });
        const pdf = await generateRetailLabelPDF(finalData);
        const pdfUrl = pdf ? URL.createObjectURL(pdf) : null;

        updateInv(inv.id, {
          status: (finalData.quality && finalData.quality.status === 'ok') ? 'DONE' : 'NEEDS_REVIEW',
          progress: 100, currentTask: 'Complete',
          sellerName: finalData.vendor?.name || 'Not detected',
          data: finalData, pdfBlobUrl: pdfUrl, extractionMethod: method
        });
      }
    } catch (err: any) {
      console.error("Processing failed for", inv.id, err);
      updateInv(inv.id, { 
        status: 'NEEDS_REVIEW', 
        currentTask: `Review Required: ${err.message || 'Error'}`, 
        extractionMethod: 'GEMINI' 
      });
    }
  };

  const processBatch = async () => {
    setStep('PROCESSING');
    for (let inv of batch.invoices) {
      if (inv.status === 'DONE') continue;
      await processInvoice(inv);
    }
    setStep('RESULTS');
    if (batch.invoices.length > 0) setExpandedDoc(batch.invoices[0].id);
  };

  const updateInv = (id: string, updates: Partial<InvoiceState>) => {
    setBatch(prev => ({ ...prev, invoices: prev.invoices.map(i => i.id === id ? { ...i, ...updates } : i) }));
  };

  const handleEdit = (invId: string, idx: number, field: keyof LineItem, val: any) => {
    setBatch(prev => {
      const inv = prev.invoices.find(i => i.id === invId);
      if (!inv || !inv.data) return prev;
      const newItems = [...inv.data.line_items];
      newItems[idx] = { ...newItems[idx], [field]: val };

      const it = newItems[idx];
      if (field === 'margin_percent' || field === 'unit_price') {
        const margin = it.margin_percent || 0;
        const cost = it.unit_price || 0;
        it.retail_price = margin >= 1 ? cost : cost / (1 - margin);
      }
      if (field === 'retail_price') {
        const cost = it.unit_price || 0;
        const retail = it.retail_price || 0;
        it.margin_percent = retail > 0 ? (retail - cost) / retail : 0;
      }

      const newData = { ...inv.data, line_items: newItems };
      return { ...prev, invoices: prev.invoices.map(i => i.id === invId ? { ...i, data: newData } : i) };
    });
  };

  const syncChanges = async (invId: string) => {
    const inv = batch.invoices.find(i => i.id === invId);
    if (!inv || !inv.data) return;
    const newEdi = generateEDI810FromData(inv.data);
    const newPdf = await generateRetailLabelPDF(inv.data);
    const newData = { ...inv.data, edi_810: { ...inv.data.edi_810, edi_string: newEdi } };
    updateInv(invId, { data: newData, pdfBlobUrl: newPdf ? URL.createObjectURL(newPdf) : null });
  };

  const rotate = (id: string) => {
    setRotations(prev => ({ ...prev, [id]: (prev[id] || 0) + 90 }));
  };

  const currentActiveInv = batch.invoices.find(i => i.id === expandedDoc);

  if (step === 'UPLOAD') {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-8">
        <div className="max-w-4xl w-full">
          <header className="text-center mb-12">
            <h1 className="text-4xl font-black text-slate-900 tracking-tight flex items-center justify-center">
              <Package className="w-10 h-10 mr-4 text-indigo-600" />
              Invoice2EDI Agent
            </h1>
            <p className="text-slate-500 font-medium mt-2 tracking-wide uppercase text-xs">High-Precision Logistics Center</p>
          </header>
          <div className="bg-white rounded-[40px] shadow-2xl border border-slate-200 p-12 overflow-hidden relative">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-12">
              <div className="space-y-6">
                <div className="relative group border-2 border-dashed border-slate-300 rounded-[32px] p-12 text-center hover:bg-indigo-50 transition-all cursor-pointer">
                  <input type="file" multiple accept="image/*" onChange={handleFiles} className="absolute inset-0 opacity-0 cursor-pointer" />
                  <Upload className="w-12 h-12 text-indigo-500 mx-auto mb-4" />
                  <p className="font-black text-slate-900">Upload Vendors</p>
                  <p className="text-xs text-slate-400 mt-1 uppercase font-bold tracking-widest">Supports 1–4 invoice images</p>
                </div>
              </div>
              <div className="flex flex-col h-[300px]">
                <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Current Queue ({batch.invoices.length})</h3>
                <div className="flex-1 space-y-3 overflow-y-auto pr-2 scrollbar-thin">
                  {batch.invoices.length === 0 ? (
                    <div className="h-full flex flex-col items-center justify-center border-2 border-dashed border-slate-100 rounded-[32px] text-slate-200">
                      <ImageIcon className="w-10 h-10 mb-2 opacity-10" />
                      <span className="text-[9px] font-black uppercase tracking-widest">No files selected</span>
                    </div>
                  ) : batch.invoices.map(inv => (
                    <div key={inv.id} className="flex items-center p-3 bg-slate-50 border border-slate-200 rounded-2xl">
                      <img src={inv.previewUrls[0]} className="w-10 h-10 rounded-lg object-cover mr-4" />
                      <span className="text-xs font-bold text-slate-600 truncate flex-1">{inv.files[0].name}</span>
                      <button onClick={() => setBatch(p => ({...p, invoices: p.invoices.filter(i => i.id !== inv.id)}))} className="p-2 text-slate-300 hover:text-red-500"><Trash2 className="w-4 h-4" /></button>
                    </div>
                  ))}
                </div>
                {batch.invoices.length > 0 && (
                  <button onClick={processBatch} className="mt-6 w-full py-5 bg-slate-900 text-white rounded-[24px] font-black uppercase text-xs tracking-widest shadow-xl flex items-center justify-center group active:scale-95 transition-all">
                    Process Batch Run
                    <ChevronRight className="w-4 h-4 ml-2 group-hover:translate-x-1 transition-transform" />
                  </button>
                )}
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  }

  if (step === 'PROCESSING') {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-8">
        <div className="max-w-2xl w-full bg-white rounded-[40px] shadow-2xl p-16 text-center border border-slate-200">
          <Loader2 className="w-12 h-12 text-indigo-600 animate-spin mx-auto mb-8" />
          <h2 className="text-3xl font-black text-slate-900 mb-4 tracking-tight">Agent at Work</h2>
          <p className="text-slate-400 text-sm mb-12 uppercase font-bold tracking-widest">Running automated 3-pass extraction...</p>
          <div className="space-y-4 text-left mt-12">
            {batch.invoices.map(inv => (
              <div key={inv.id} className="p-6 bg-slate-50 rounded-[24px] border border-slate-100">
                <div className="flex items-center justify-between mb-2">
                  <span className="text-[10px] font-black uppercase text-slate-900 truncate">{inv.files[0].name}</span>
                  <span className="text-[9px] font-black text-indigo-600 uppercase tracking-widest">{inv.currentTask}</span>
                </div>
                <div className="h-1.5 bg-slate-200 rounded-full overflow-hidden">
                  <div className="h-full bg-indigo-600 transition-all duration-700" style={{ width: `${inv.progress}%` }} />
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 flex">
      <aside className="w-80 bg-white border-r border-slate-200 h-screen sticky top-0 p-8 flex flex-col shadow-lg z-10">
        <div className="flex items-center space-x-4 mb-12">
          <div className="bg-slate-900 p-3 rounded-2xl text-white shadow-xl"><FileDigit className="w-6 h-6" /></div>
          <span className="font-black text-xl text-slate-900 tracking-tight">Output Hub</span>
        </div>
        <div className="flex-1 space-y-4 overflow-y-auto pr-2 scrollbar-thin">
           {batch.invoices.map(inv => (
             <button key={inv.id} onClick={() => setExpandedDoc(inv.id)} className={`w-full p-5 rounded-2xl text-[10px] font-black uppercase tracking-[0.1em] text-left transition-all group ${expandedDoc === inv.id ? 'bg-slate-900 text-white shadow-2xl' : 'text-slate-500 hover:bg-slate-50'}`}>
               <div className="truncate flex items-center">
                 {inv.status === 'DONE' ? <CheckCircle className="w-3 h-3 mr-2 text-emerald-400" /> : <AlertCircle className="w-3 h-3 mr-2 text-amber-400" />}
                 {inv.sellerName || 'Processing...'}
               </div>
               <div className={`text-[8px] opacity-60 mt-2 font-mono flex items-center justify-between`}>
                 <span>ID: {inv.id.toUpperCase()}</span>
                 <span className="bg-slate-100 group-hover:bg-slate-200 text-slate-600 px-1.5 py-0.5 rounded-md uppercase text-[7px]">{inv.extractionMethod}</span>
               </div>
             </button>
           ))}
        </div>
        <button onClick={startOver} className="mt-8 py-5 bg-slate-900 text-white rounded-[24px] font-black uppercase text-[10px] tracking-[0.2em] shadow-2xl flex items-center justify-center active:scale-95 transition-all"><RotateCcw className="w-4 h-4 mr-3" />New Batch</button>
      </aside>

      <main className="flex-1 p-16 max-w-7xl mx-auto h-screen overflow-y-auto">
        {currentActiveInv ? (
          <DocResultView 
            inv={currentActiveInv} 
            isPreviewing={previewingDocId === expandedDoc}
            rotation={rotations[expandedDoc!] || 0}
            onTogglePreview={() => setPreviewingDocId(p => p ? null : expandedDoc)}
            onRotate={() => rotate(expandedDoc!)}
            onEdit={handleEdit}
            onSync={syncChanges}
            onReprocess={() => processInvoice(currentActiveInv)}
          />
        ) : (
          <div className="h-full flex flex-col items-center justify-center text-slate-300">
            <LayoutGrid className="w-24 h-24 mb-6 opacity-10" />
            <p className="font-black uppercase tracking-widest text-sm text-slate-400">Select a document to review</p>
          </div>
        )}
      </main>
    </div>
  );
};

const DocResultView: React.FC<{ 
  inv: InvoiceState; isPreviewing: boolean; rotation: number; onTogglePreview: () => void; onRotate: () => void; onEdit: any; onSync: any; onReprocess: any;
}> = ({ inv, isPreviewing, rotation, onTogglePreview, onRotate, onEdit, onSync, onReprocess }) => {
  const [tab, setTab] = useState<'SUMMARY' | 'EDIT' | 'EDI' | 'TAGS' | 'RAW'>('SUMMARY');

  if (!inv.data) {
    return (
      <div className="flex flex-col items-center justify-center h-full space-y-4">
        <Loader2 className="w-10 h-10 text-indigo-600 animate-spin" />
        <p className="text-[10px] font-black uppercase tracking-widest text-slate-400">Loading document state...</p>
        <div className="text-xs text-slate-400 text-center max-w-xs mt-4">
          Status: {inv.currentTask}
        </div>
      </div>
    );
  }

  return (
    <div className="animate-in fade-in duration-500">
      <div className="flex items-center justify-between mb-12">
        <div className="flex items-center space-x-6">
          <div onClick={onTogglePreview} className="relative cursor-pointer group shadow-xl rounded-[24px]">
            <img src={inv.previewUrls[0]} className="w-20 h-20 rounded-[24px] object-cover border-2 border-white group-hover:opacity-75 transition-all" style={{ transform: `rotate(${rotation}deg)` }} />
            <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity"><Search className="text-white w-6 h-6" /></div>
          </div>
          <div>
            <h2 className="text-3xl font-black text-slate-900 tracking-tight leading-none mb-2">{inv.data.invoice?.number || 'Not detected'}</h2>
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center">
              <User className="w-3 h-3 mr-2 text-indigo-500" />
              {inv.data.vendor?.name || 'Not detected'}
            </p>
          </div>
        </div>
        <div className="flex items-center space-x-6">
           <div className="flex space-x-2">
             <button onClick={onRotate} className="p-3 bg-white border border-slate-200 rounded-2xl text-slate-400 hover:text-indigo-600 transition-all shadow-sm active:scale-90" title="Rotate"><RotateCw className="w-5 h-5" /></button>
             <button onClick={onReprocess} className="p-3 bg-white border border-slate-200 rounded-2xl text-slate-400 hover:text-indigo-600 transition-all shadow-sm active:scale-90" title="Reprocess Document"><Wand2 className="w-5 h-5" /></button>
           </div>
           <StatusBadge status={inv.data.quality?.status} />
           <div className="text-right">
             <p className="text-[10px] font-black text-slate-400 uppercase mb-1">Total Cost</p>
             <p className="text-2xl font-black text-slate-900">
               {inv.data.pricing?.total_cost > 0 ? `$${inv.data.pricing.total_cost.toFixed(2)}` : 'Not detected'}
             </p>
           </div>
        </div>
      </div>

      <div className="bg-white rounded-[40px] border border-slate-200 shadow-2xl overflow-hidden min-h-[600px] flex flex-col">
        <div className="flex bg-slate-50 border-b border-slate-100 px-8">
          <TabBtn label="Summary" active={tab === 'SUMMARY'} onClick={() => setTab('SUMMARY')} />
          <TabBtn label="Inventory" active={tab === 'EDIT'} onClick={() => setTab('EDIT')} />
          <TabBtn label="EDI Stream" active={tab === 'EDI'} onClick={() => setTab('EDI')} />
          {inv.data.labels?.should_generate && <TabBtn label="Retail Tags" active={tab === 'TAGS'} onClick={() => setTab('TAGS')} />}
          <TabBtn label="Raw Context" active={tab === 'RAW'} onClick={() => setTab('RAW')} />
        </div>

        <div className="p-10 flex-1 overflow-x-auto">
          {tab === 'SUMMARY' && (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-10 h-full animate-in fade-in duration-300">
              <div className="space-y-8">
                <SectionHeader icon={<User />} label="Entity Profile" />
                <div className="bg-slate-50 p-8 rounded-[32px] border border-slate-100 space-y-4 shadow-inner">
                  <SummaryRow label="Supplier" value={inv.data.vendor?.name || 'Not detected'} />
                  <SummaryRow label="Buyer" value={inv.data.buyer?.name || 'Not detected'} />
                  <SummaryRow label="Date" value={inv.data.invoice?.date || 'Not detected'} />
                  <SummaryRow label="Location" value={inv.data.buyer?.city ? `${inv.data.buyer.city}, ${inv.data.buyer.state}` : 'Not detected'} />
                </div>
                <SectionHeader icon={<Percent />} label="Intelligence Summary" />
                <div className="grid grid-cols-3 gap-4">
                  <StatCard label="Method" value={inv.extractionMethod} />
                  <StatCard label="Issues" value={inv.data.quality?.issues?.length || 0} />
                  <StatCard label="Confidence" value="High" />
                </div>
              </div>
              <div className="bg-indigo-50/20 p-10 rounded-[40px] border border-indigo-100">
                <SectionHeader icon={<Search className="text-indigo-400" />} label="Analysis Notes" />
                <div className="space-y-4">
                  {inv.data.quality?.issues?.length > 0 ? (
                    inv.data.quality.issues.map((iss: string, i: number) => (
                      <div key={i} className="flex items-center space-x-3 text-amber-600 bg-white p-4 rounded-2xl border border-amber-100 text-[10px] font-bold uppercase tracking-widest shadow-sm">
                        <AlertCircle className="w-4 h-4 shrink-0" />
                        <span>{iss}</span>
                      </div>
                    ))
                  ) : (
                    <p className="text-slate-600 italic font-medium leading-relaxed bg-white/50 p-6 rounded-3xl border border-white">No critical issues detected. Extraction facts verified via {inv.extractionMethod}.</p>
                  )}
                </div>
                <div className="mt-12 space-y-3">
