import { GoogleGenAI } from "@google/genai";
import { DocumentResult } from "../types";

const getBase64 = (file: File): Promise<string> => {
  return new Promise((resolve) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => resolve((reader.result as string).split(',')[1]);
  });
};

export const transcribeOnly = async (files: File[]): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const parts = await Promise.all(files.map(async (f) => ({
    inlineData: { mimeType: f.type, data: await getBase64(f) }
  })));

  const prompt = "Transcribe only clearly visible text from these documents. Group by logical sections. Do not guess. Return plain text. Focus on Vendor headers, Totals, and Line Items.";
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: { parts: [...parts, { text: prompt }] }
  });

  return response.text || "";
};

const normalizeData = (data: any): DocumentResult => {
  // Ensure basic structure exists to prevent "Cannot read properties of undefined"
  return {
    doc_id: data.doc_id || Math.random().toString(36).substring(7),
    doc_type: data.doc_type || 'unknown',
    vendor: {
      name: data.vendor?.name || '',
      address: data.vendor?.address || '',
      city: data.vendor?.city || '',
      state: data.vendor?.state || '',
      zip: data.vendor?.zip || '',
      phone: data.vendor?.phone || ''
    },
    buyer: {
      name: data.buyer?.name || '',
      address: data.buyer?.address || '',
      city: data.buyer?.city || '',
      state: data.buyer?.state || '',
      zip: data.buyer?.zip || ''
    },
    invoice: {
      number: data.invoice?.number || '',
      date: data.invoice?.date || '',
      po: data.invoice?.po || '',
      currency: data.invoice?.currency || 'USD'
    },
    line_items: Array.isArray(data.line_items) ? data.line_items.map((it: any, idx: number) => ({
      line_no: it.line_no || idx + 1,
      description: it.description || 'Unknown Item',
      qty: typeof it.qty === 'number' ? it.qty : 1,
      uom: it.uom || 'EA',
      unit_price: typeof it.unit_price === 'number' ? it.unit_price : 0,
      line_total: typeof it.line_total === 'number' ? it.line_total : 0,
      code_value: String(it.code_value || '').replace(/\s+/g, ''),
      code_type: it.code_type || 'UPC-A',
      code_status: it.code_status || 'UNVERIFIED',
      category: it.category || 'other',
      margin_percent: typeof it.margin_percent === 'number' ? it.margin_percent : 0.2,
      retail_price: typeof it.retail_price === 'number' ? it.retail_price : 0
    })) : [],
    pricing: {
      total_cost: typeof data.pricing?.total_cost === 'number' ? data.pricing.total_cost : 0,
      total_retail: typeof data.pricing?.total_retail === 'number' ? data.pricing.total_retail : 0,
      average_margin: typeof data.pricing?.average_margin === 'number' ? data.pricing.average_margin : 0
    },
    edi_810: {
      version: data.edi_810?.version || 'X12 004010',
      segments: Array.isArray(data.edi_810?.segments) ? data.edi_810.segments : [],
      edi_string: data.edi_810?.edi_string || ''
    },
    labels: {
      should_generate: !!data.labels?.should_generate,
      reason: data.labels?.reason || '',
      valid_from: data.labels?.valid_from || '',
      valid_to: data.labels?.valid_to || '',
      label_items: Array.isArray(data.labels?.label_items) ? data.labels.label_items : []
    },
    quality: {
      status: data.quality?.status || 'needs_review',
      issues: Array.isArray(data.quality?.issues) ? data.quality.issues : [],
      field_confidence: data.quality?.field_confidence || { total: 0.5 }
    },
    raw_text: data.raw_text || ''
  };
};

export const extractInvoiceData = async (
  files: File[],
  ocrContext: string
): Promise<DocumentResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const parts = await Promise.all(files.map(async (f) => ({
    inlineData: { mimeType: f.type, data: await getBase64(f) }
  })));

  const prompt = `
    Act as "Invoice2EDI + RetailTag Agent". 
    Goal: Extract data from these images and return exactly ONE JSON object following the schema.

    CRITICAL RULES:
    1. EXTRACT ALL UPCs/BARCODES: Look at the right-hand column and product headers.
    2. UPC FORMATTING: Strip ALL spaces. Preserve leading zeros. 
       - If it looks like a UPC-A, it MUST be exactly 12 digits.
       - If only 11 digits are found, check if a leading zero is missing.
    3. PRICE CALCULATIONS: Calculate RETAIL = COST / (1 - MARGIN). 
       - Use these margins: alcohol 0.18, tobacco 0.12, energy 0.25, energy 0.25, snacks 0.35, grocery 0.20, other 0.20.
       - IMPORTANT: Do not leave retail_price as 0 if unit_price > 0.
    4. EDI: Build X12 810 segments with "~" terminator and "*" separator.
    5. If a field is missing, leave as empty string or null.

    JSON SCHEMA:
    {
      "doc_id": "string",
      "doc_type": "invoice|receipt|unknown",
      "vendor": {"name":"", "address":"", "city":"", "state":"", "zip":"", "phone":""},
      "buyer": {"name":"", "address":"", "city":"", "state":"", "zip":""},
      "invoice": {"number":"", "date":"YYYY-MM-DD", "po":"", "currency":"USD"},
      "line_items": [
        {"line_no":1, "description":"", "qty":1, "uom":"EA", "unit_price":0.0, "line_total":0.0, "code_value":"", "code_type":"UPC-A|UCI", "category":"snacks", "margin_percent":0.35, "retail_price":0.0}
      ],
      "pricing": {"total_cost":0.0, "total_retail":0.0, "average_margin":0.0},
      "edi_810": {"version":"X12 004010", "segments":[], "edi_string":""},
      "labels": {"should_generate":true, "reason":"", "valid_from":"", "valid_to":"", "label_items":[]},
      "quality": {"status":"ok|needs_review", "issues":[], "field_confidence":{"total":0.9, "vendor":0.8, "line_items":0.7}}
    }

    OCR Context (HINT): ${ocrContext}
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: { parts: [...parts, { text: prompt }] },
    config: { responseMimeType: "application/json" }
  });

  try {
    const text = response.text || "{}";
    const rawData = JSON.parse(text);
    return normalizeData(rawData);
  } catch (e) {
    console.error("AI JSON Parse Error:", e);
    // Return empty normalized object rather than throwing to avoid whole job failure
    return normalizeData({});
  }
};

