import { CodeValidationResult } from '../types';

export const validateUPC = (code: string): boolean => {
  const clean = code.replace(/\D/g, ''); // Ensure only digits
  if (clean.length !== 12) return false;

  let sum = 0;
  for (let i = 0; i < 11; i++) {
    sum += parseInt(clean[i]) * (i % 2 === 0 ? 3 : 1);
  }
  const checkDigit = (10 - (sum % 10)) % 10;
  return checkDigit === parseInt(clean[11]);
};

export const validateEAN = (code: string): boolean => {
  const clean = code.replace(/\D/g, '');
  if (clean.length !== 13) return false;

  let sum = 0;
  for (let i = 0; i < 12; i++) {
    sum += parseInt(clean[i]) * (i % 2 === 0 ? 1 : 3);
  }
  const checkDigit = (10 - (sum % 10)) % 10;
  return checkDigit === parseInt(clean[12]);
};

export const validateSSCC = (code: string): boolean => {
  const clean = code.replace(/\D/g, '');
  if (clean.length !== 18) return false;

  let sum = 0;
  for (let i = 0; i < 17; i++) {
    sum += parseInt(clean[i]) * (i % 2 === 0 ? 3 : 1);
  }
  const checkDigit = (10 - (sum % 10)) % 10;
  return checkDigit === parseInt(clean[17]);
};

export const validateCode = (value: string): CodeValidationResult => {
  if (!value) return { value: '', type: 'UNKNOWN', isValid: false };
  const clean = value.replace(/\s+/g, '');

  // 12 digits: Check if it's a valid UPC-A
  if (clean.length === 12 && /^\d+$/.test(clean)) {
    return { value: clean, type: 'UPC-A', isValid: validateUPC(clean) };
  }

  // 11 digits: Try padding with 0 (very common in systems)
  if (clean.length === 11 && /^\d+$/.test(clean)) {
    const padded = '0' + clean;
    return { value: padded, type: 'UPC-A', isValid: validateUPC(padded) };
  }

  // 13 digits: EAN-13
  if (clean.length === 13 && /^\d+$/.test(clean)) {
    return { value: clean, type: 'EAN-13', isValid: validateEAN(clean) };
  }

  if (clean.length === 18 && /^\d+$/.test(clean)) {
    return { value: clean, type: 'SSCC-18', isValid: validateSSCC(clean) };
  }

  if (clean.length >= 8 && clean.length <= 25 && /^[A-Z0-9]+$/i.test(clean)) {
    return { value: clean, type: 'UCI', isValid: true };
  }

  return { value: clean, type: 'UNKNOWN', isValid: false };
};

import { GoogleGenAI } from "@google/genai";
import { DocumentResult } from "../types";
import { validateCode } from "./validationService";

const getBase64 = (file: File): Promise<string> => {
  return new Promise((resolve) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => resolve((reader.result as string).split(',')[1]);
  });
};

export const transcribeOnly = async (files: File[]): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const parts = await Promise.all(files.map(async (f) => ({
    inlineData: { mimeType: f.type, data: await getBase64(f) }
  })));

  const prompt = "Transcribe every single piece of text from these documents. Be extremely thorough. Focus on headers, line items (quantity, description, price, UPC), and the final totals at the bottom.";
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: { parts: [...parts, { text: prompt }] }
  });

  return response.text || "";
};

const normalizeData = (data: any): DocumentResult => {
  const line_items = Array.isArray(data.line_items) ? data.line_items.map((it: any, idx: number) => {
    const rawCode = String(it.code_value || '').replace(/\s+/g, '');
    const validation = validateCode(rawCode);

    // Ensure margin is a whole number (e.g., 18 instead of 0.18)
    let margin = typeof it.margin_percent === 'number' ? it.margin_percent : 20;
    if (margin > 0 && margin < 1) margin = Math.round(margin * 100);

    return {
      line_no: it.line_no || idx + 1,
      description: it.description || 'Unknown Item',
      qty: typeof it.qty === 'number' ? it.qty : 1,
      uom: it.uom || 'EA',
      unit_price: typeof it.unit_price === 'number' ? it.unit_price : 0,
      line_total: typeof it.line_total === 'number' ? it.line_total : 0,
      code_value: validation.value || rawCode,
      code_type: validation.type || it.code_type || 'UPC-A',
      code_status: validation.isValid ? 'VALID' : 'INVALID',
      category: it.category || 'other',
      margin_percent: margin,
      retail_price: typeof it.retail_price === 'number' ? it.retail_price : 0
    };
  }) : [];

  const quality_issues = Array.isArray(data.quality?.issues) ? data.quality.issues : [];

  // Check for presence of key fields to determine status
  const hasCriticalData = !!(data.vendor?.name && data.invoice?.number && line_items.length > 0);

  return {
    doc_id: data.doc_id || Math.random().toString(36).substring(7),
    doc_type: data.doc_type || 'unknown',
    vendor: {
      name: data.vendor?.name || '',
      address: data.vendor?.address || '',
      city: data.vendor?.city || '',
      state: data.vendor?.state || '',
      zip: data.vendor?.zip || '',
      phone: data.vendor?.phone || ''
    },
    buyer: {
      name: data.buyer?.name || '',
      address: data.buyer?.address || '',
      city: data.buyer?.city || '',
      state: data.buyer?.state || '',
      zip: data.buyer?.zip || ''
    },
    invoice: {
      number: data.invoice?.number || '',
      date: data.invoice?.date || '',
      po: data.invoice?.po || '',
      currency: data.invoice?.currency || 'USD'
    },
    line_items,
    pricing: {
      total_cost: typeof data.pricing?.total_cost === 'number' ? data.pricing.total_cost : 0,
      total_retail: typeof data.pricing?.total_retail === 'number' ? data.pricing.total_retail : 0,
      average_margin: typeof data.pricing?.average_margin === 'number' ? data.pricing.average_margin : 0
    },
    edi_810: {
      version: data.edi_810?.version || 'X12 004010',
      segments: Array.isArray(data.edi_810?.segments) ? data.edi_810.segments : [],
      edi_string: data.edi_810?.edi_string || ''
    },
    labels: {
      should_generate: !!data.labels?.should_generate,
      reason: data.labels?.reason || '',
      valid_from: data.labels?.valid_from || '',
      valid_to: data.labels?.valid_to || '',
      label_items: Array.isArray(data.labels?.label_items) ? data.labels.label_items : []
    },
    quality: {
      status: hasCriticalData ? 'ok' : 'needs_review',
      issues: quality_issues,
      field_confidence: data.quality?.field_confidence || { total: 0.5 }
    },
    raw_text: data.raw_text || ''
  };
};

export const extractInvoiceData = async (
  files: File[],
  ocrContext: string
): Promise<DocumentResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const parts = await Promise.all(files.map(async (f) => ({
    inlineData: { mimeType: f.type, data: await getBase64(f) }
  })));

  const prompt = `
    Act as a World-Class Logistics and Retail Data Specialist.
    TASK: Extract high-precision data from the provided invoice/receipt images.

    CRITICAL FIELDS TO FIND:
    - Vendor Name (The big logo/header at the top).
    - Total Cost (Look for "TOTAL", "AMOUNT DUE", "GRAND TOTAL").
    - Invoice Number / Receipt ID.
    - Date of transaction.
    - Line Items: For each item, find Quantity, Description, Unit Cost, and UPC/Barcode.

    SPECIAL HANDLING:
    - MARGIN: Return as whole numbers (e.g. 18 for 18%). 
    - BARCODES: Look for 12 or 13-digit numbers. Strip spaces. Preserve leading zeros. 
    - ALCOHOL: If an item is Beer, Wine, or Spirits, set category to "alcohol".
    - COMPLETENESS CHECK: If you cannot find the "Total" or the bottom of the slip, add "Incomplete screenshot: ending may be missing" to quality.issues.

    RETURN FORMAT: Exactly one JSON object matching the schema below.

    {
      "doc_id": "string",
      "doc_type": "invoice|receipt",
      "vendor": {"name": "...", "address": "...", "city": "...", "state": "...", "zip": "...", "phone": "..."},
      "buyer": {"name": "...", "address": "...", "city": "...", "state": "...", "zip": "..."},
      "invoice": {"number": "...", "date": "YYYY-MM-DD", "po": "...", "currency": "USD"},
      "line_items": [
        {
          "line_no": 1,
          "description": "...",
          "qty": 1,
          "uom": "EA",
          "unit_price": 0.0,
          "line_total": 0.0,
          "code_value": "...",
          "code_type": "UPC-A|EAN-13|UCI",
          "category": "alcohol|snacks|grocery|other",
          "margin_percent": 18,
          "retail_price": 0.0
        }
      ],
      "pricing": {"total_cost": 0.0, "total_retail": 0.0, "average_margin": 0.0},
      "edi_810": {"version": "X12 004010", "segments": [], "edi_string": ""},
      "labels": {"should_generate": true, "reason": "...", "valid_from": "...", "valid_to": "...", "label_items": []},
      "quality": {"status": "ok|needs_review", "issues": [], "field_confidence": {"total": 0.9}}
    }

    Contextual OCR Hint (use only if vision is blurry):
    ${ocrContext}
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: { parts: [...parts, { text: prompt }] },
    config: { 
      responseMimeType: "application/json",
      temperature: 0.1 
    }
  });

  try {
    const text = response.text || "{}";
    const rawData = JSON.parse(text);
    return normalizeData(rawData);
  } catch (e) {
    console.error("AI JSON Parse Error:", e);
    return normalizeData({});
  }
};

