import { DocumentResult } from '../types';

/**
 * Generates an enterprise-grade EDI 810 X12 stream from extracted document data.
 * Adheres to standard X12 4010/5010 conventions.
 */
export const generateEDI810FromData = (data: DocumentResult | null): string => {
  if (!data) return '';
  const segments: string[] = [];
  const delimiter = '*';
  const terminator = '~';

  // --- Header ---
  // ST: Transaction Set Header
  // ST * Transaction Set ID (810) * Control Number
  segments.push(`ST${delimiter}810${delimiter}0001`);

  // BIG: Beginning Segment for Invoice
  // BIG * Date * Invoice Number * PO Date * PO Number * Release * Change Order * Trans Type
  const dateStr = (data.invoice.date || '').replace(/[-/]/g, '');
  const invNo = data.invoice.number || '';
  const poNo = data.invoice.po || '';
  // Transaction type 'DI' for Debit Invoice (standard)
  segments.push(`BIG${delimiter}${dateStr}${delimiter}${invNo}${delimiter}${delimiter}${poNo}${delimiter}${delimiter}${delimiter}DI`);

  // CUR: Currency
  // CUR * Entity Identifier (BY) * Currency Code
  if (data.invoice.currency) {
    segments.push(`CUR${delimiter}BY${delimiter}${data.invoice.currency.toUpperCase()}`);
  }

  // REF: Reference Identifiers
  // REF * Qualifier (IA - Vendor ID) * ID
  if (data.vendor.account_id) {
    segments.push(`REF${delimiter}IA${delimiter}${data.vendor.account_id}`);
  }
  // REF * Qualifier (PO - Purchase Order)
  if (poNo) {
    segments.push(`REF${delimiter}PO${delimiter}${poNo}`);
  }

  // --- N1 Loop: Seller (Vendor) ---
  if (data.vendor.name) {
    segments.push(`N1${delimiter}SU${delimiter}${data.vendor.name.toUpperCase().substring(0, 60)}`);
    if (data.vendor.address) {
      segments.push(`N3${delimiter}${data.vendor.address.toUpperCase().substring(0, 55)}`);
    }
    if (data.vendor.city) {
      const city = data.vendor.city.toUpperCase();
      const state = (data.vendor.state || '').toUpperCase();
      const zip = (data.vendor.zip || '').replace(/[^\d]/g, '');
      segments.push(`N4${delimiter}${city}${delimiter}${state}${delimiter}${zip}`);
    }
    if (data.vendor.phone) {
      segments.push(`PER${delimiter}IC${delimiter}SALES${delimiter}TE${delimiter}${data.vendor.phone.replace(/\D/g, '')}`);
    }
  }

  // --- N1 Loop: Buyer ---
  if (data.buyer.name) {
    segments.push(`N1${delimiter}BY${delimiter}${data.buyer.name.toUpperCase().substring(0, 60)}`);
    if (data.buyer.address) {
      segments.push(`N3${delimiter}${data.buyer.address.toUpperCase().substring(0, 55)}`);
    }
    if (data.buyer.city) {
      const city = data.buyer.city.toUpperCase();
      const state = (data.buyer.state || '').toUpperCase();
      const zip = (data.buyer.zip || '').replace(/[^\d]/g, '');
      segments.push(`N4${delimiter}${city}${delimiter}${state}${delimiter}${zip}`);
    }
  }

  // --- IT1 Loops: Line Items ---
  data.line_items.forEach((item) => {
    const qty = item.qty || 0;
    const price = item.unit_price || 0;
    const uom = item.uom || 'EA';

    // Determine the correct product qualifier
    // UP = UPC, EN = EAN, VN = Vendor Number
    let qualifier = 'VN';
    if (item.code_type === 'UPC-A') qualifier = 'UP';
    if (item.code_type === 'EAN-13') qualifier = 'EN';
    if (item.code_type === 'UCI') qualifier = 'VN';

    const codeValue = item.code_value ? `${delimiter}${qualifier}${delimiter}${item.code_value}` : '';

    // IT1 * Line# * Qty * UOM * UnitPrice * Basis * Qualifier * ProductID
    segments.push(`IT1${delimiter}${item.line_no}${delimiter}${qty}${delimiter}${uom}${delimiter}${price}${delimiter}${delimiter}${codeValue}`);

    // PID: Product Description
    if (item.description) {
      segments.push(`PID${delimiter}F${delimiter}${delimiter}${delimiter}${delimiter}${item.description.toUpperCase().substring(0, 80)}`);
    }
  });

  // --- Summary ---
  // TDS: Total Amount
  // TDS * Total Amount (in cents for X12)
  if (data.pricing.total_cost !== null) {
    const cents = Math.round(data.pricing.total_cost * 100);
    segments.push(`TDS${delimiter}${cents}`);
  }

  // CTT: Transaction Totals
  // CTT * Number of line items
  segments.push(`CTT${delimiter}${data.line_items.length}`);

  // SE: Transaction Set Trailer
  // SE * Segment Count * Control Number
  const segCount = segments.length + 1;
  segments.push(`SE${delimiter}${segCount}${delimiter}0001`);

  return segments.join(terminator) + terminator;
};

