import { GoogleGenAI } from "@google/genai";
import { DocumentResult } from "../types";
import { validateCode } from "./validationService";

const getBase64 = (file: File): Promise<string> => {
  return new Promise((resolve) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => resolve((reader.result as string).split(',')[1]);
  });
};

export const transcribeOnly = async (files: File[]): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const parts = await Promise.all(files.map(async (f) => ({
    inlineData: { mimeType: f.type, data: await getBase64(f) }
  })));

  const prompt = "Transcribe every single piece of text from these documents. Focus on Vendor Name, Total, Date, and Line Items.";
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: { parts: [...parts, { text: prompt }] }
  });

  return response.text || "";
};

const normalizeData = (data: any): DocumentResult => {
  const line_items = Array.isArray(data.line_items) ? data.line_items.map((it: any, idx: number) => {
    const rawCode = String(it.code_value || '').replace(/\s+/g, '');
    const validation = validateCode(rawCode);

    let margin = typeof it.margin_percent === 'number' ? it.margin_percent : 20;
    if (margin > 0 && margin < 1) margin = Math.round(margin * 100);

    return {
      line_no: it.line_no || idx + 1,
      description: it.description || 'Unknown Item',
      qty: typeof it.qty === 'number' ? it.qty : 1,
      uom: it.uom || 'EA',
      unit_price: typeof it.unit_price === 'number' ? it.unit_price : 0,
      line_total: typeof it.line_total === 'number' ? it.line_total : 0,
      code_value: validation.value || rawCode,
      code_type: validation.type || it.code_type || 'UPC-A',
      code_status: validation.isValid ? 'VALID' : 'INVALID',
      category: it.category || 'other',
      margin_percent: margin,
      retail_price: typeof it.retail_price === 'number' ? it.retail_price : 0
    };
  }) : [];

  const quality_issues = Array.isArray(data.quality?.issues) ? data.quality.issues : [];
  const hasCriticalData = !!(data.vendor?.name && (data.pricing?.total_cost > 0 || line_items.length > 0));

  return {
    doc_id: data.doc_id || Math.random().toString(36).substring(7),
    doc_type: data.doc_type || 'invoice',
    vendor: {
      name: data.vendor?.name || '',
      address: data.vendor?.address || '',
      city: data.vendor?.city || '',
      state: data.vendor?.state || '',
      zip: data.vendor?.zip || '',
      phone: data.vendor?.phone || ''
    },
    buyer: {
      name: data.buyer?.name || '',
      address: data.buyer?.address || '',
      city: data.buyer?.city || '',
      state: data.buyer?.state || '',
      zip: data.buyer?.zip || ''
    },
    invoice: {
      number: data.invoice?.number || '',
      date: data.invoice?.date || '',
      po: data.invoice?.po || '',
      currency: data.invoice?.currency || 'USD'
    },
    line_items,
    pricing: {
      total_cost: typeof data.pricing?.total_cost === 'number' ? data.pricing.total_cost : 0,
      total_retail: typeof data.pricing?.total_retail === 'number' ? data.pricing.total_retail : 0,
      average_margin: typeof data.pricing?.average_margin === 'number' ? data.pricing.average_margin : 0
    },
    edi_810: {
      version: data.edi_810?.version || 'X12 004010',
      segments: Array.isArray(data.edi_810?.segments) ? data.edi_810.segments : [],
      edi_string: data.edi_810?.edi_string || ''
    },
    labels: {
      should_generate: !!data.labels?.should_generate,
      reason: data.labels?.reason || '',
      valid_from: data.labels?.valid_from || '',
      valid_to: data.labels?.valid_to || '',
      label_items: Array.isArray(data.labels?.label_items) ? data.labels.label_items : []
    },
    quality: {
      status: hasCriticalData ? 'ok' : 'needs_review',
      issues: quality_issues,
      field_confidence: data.quality?.field_confidence || { total: 0.9 }
    },
    raw_text: data.raw_text || ''
  };
};

export const extractInvoiceData = async (
  files: File[],
  ocrContext: string
): Promise<DocumentResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const parts = await Promise.all(files.map(async (f) => ({
    inlineData: { mimeType: f.type, data: await getBase64(f) }
  })));

  const prompt = `
    TASK: Extract high-precision logistics data from these images.

    1. VENDOR: Find the main brand/entity logo or text at the top.
    2. TOTAL: Find "GRAND TOTAL", "TOTAL", or "AMOUNT DUE".
    3. ITEMS: Extract Description, Qty, Unit Price, and UPC for every item.
    4. UPC FORMAT: Ensure barcodes are numeric strings (12 or 13 digits).

    OUTPUT: A single JSON object.
    {
      "vendor": {"name": "...", "address": "..."},
      "invoice": {"number": "...", "date": "..."},
      "line_items": [{"description": "...", "qty": 1, "unit_price": 0.0, "code_value": "..."}],
      "pricing": {"total_cost": 0.0},
      "quality": {"issues": []}
    }

    OCR Hint: ${ocrContext}
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: { parts: [...parts, { text: prompt }] },
    config: { responseMimeType: "application/json" }
  });

  try {
    const rawData = JSON.parse(response.text || "{}");
    return normalizeData(rawData);
  } catch (e) {
    console.error("JSON Parse Error:", e);
    return normalizeData({});
  }
};

import { DocumentResult } from '../types';

/**
 * Generates an enterprise-grade EDI 810 X12 stream from extracted document data.
 * Adheres to standard X12 4010/5010 conventions.
 */
export const generateEDI810FromData = (data: DocumentResult | null): string => {
  if (!data) return '';
  const segments: string[] = [];
  const delimiter = '*';
  const terminator = '~';

  // Helper to format date as CCYYMMDD
  const formatDate = (date: string) => (date || '').replace(/[-/]/g, '').substring(0, 8);
  const now = new Date().toISOString().split('T')[0].replace(/-/g, '');
  const time = new Date().toTimeString().split(' ')[0].replace(/:/g, '').substring(0, 4);

  // --- Envelopes (Simulated for high-fidelity preview) ---
  // ISA: Interchange Control Header
  segments.push(`ISA${delimiter}00${delimiter}          ${delimiter}00${delimiter}          ${delimiter}ZZ${delimiter}SENDERID       ${delimiter}ZZ${delimiter}RECEIVERID     ${delimiter}${now.substring(2)}${delimiter}${time}${delimiter}^${delimiter}00501${delimiter}000000001${delimiter}0${delimiter}P${delimiter}:`);

  // GS: Functional Group Header
  segments.push(`GS${delimiter}IN${delimiter}SENDERID${delimiter}RECEIVERID${delimiter}${now}${delimiter}${time}${delimiter}1${delimiter}X${delimiter}005010`);

  // --- Transaction Set ---
  // ST: Transaction Set Header
  segments.push(`ST${delimiter}810${delimiter}0001`);

  // BIG: Beginning Segment for Invoice
  const invDate = formatDate(data.invoice?.date) || now;
  const invNo = data.invoice?.number || 'INV-TEMP';
  const poNo = data.invoice?.po || 'PO-PENDING';
  segments.push(`BIG${delimiter}${invDate}${delimiter}${invNo}${delimiter}${delimiter}${poNo}${delimiter}${delimiter}${delimiter}DI`);

  // CUR: Currency
  if (data.invoice?.currency) {
    segments.push(`CUR${delimiter}SE${delimiter}${data.invoice.currency.toUpperCase()}`);
  }

  // REF: Reference Identifiers
  if (data.vendor?.account_id) {
    segments.push(`REF${delimiter}IA${delimiter}${data.vendor.account_id}`);
  }
  if (poNo && poNo !== 'PO-PENDING') {
    segments.push(`REF${delimiter}PO${delimiter}${poNo}`);
  }

  // --- N1 Loop: Seller (Vendor) ---
  const vName = (data.vendor?.name || 'UNKNOWN VENDOR').toUpperCase().substring(0, 60);
  segments.push(`N1${delimiter}SU${delimiter}${vName}`);
  if (data.vendor?.address) {
    segments.push(`N3${delimiter}${data.vendor.address.toUpperCase().substring(0, 55)}`);
  }
  if (data.vendor?.city) {
    const city = data.vendor.city.toUpperCase();
    const state = (data.vendor.state || 'XX').toUpperCase().substring(0, 2);
    const zip = (data.vendor.zip || '00000').replace(/[^\d]/g, '').substring(0, 5);
    segments.push(`N4${delimiter}${city}${delimiter}${state}${delimiter}${zip}`);
  }

  // --- N1 Loop: Buyer ---
  const bName = (data.buyer?.name || 'UNKNOWN BUYER').toUpperCase().substring(0, 60);
  segments.push(`N1${delimiter}BY${delimiter}${bName}`);
  if (data.buyer?.address) {
    segments.push(`N3${delimiter}${data.buyer.address.toUpperCase().substring(0, 55)}`);
  }
  if (data.buyer?.city) {
    const city = data.buyer.city.toUpperCase();
    const state = (data.buyer.state || 'XX').toUpperCase().substring(0, 2);
    const zip = (data.buyer.zip || '00000').replace(/[^\d]/g, '').substring(0, 5);
    segments.push(`N4${delimiter}${city}${delimiter}${state}${delimiter}${zip}`);
  }

  // --- IT1 Loops: Line Items ---
  (data.line_items || []).forEach((item, idx) => {
    const qty = item.qty || 1;
    const price = item.unit_price || 0;
    const uom = item.uom || 'EA';

    let qualifier = 'VN';
    if (item.code_type === 'UPC-A') qualifier = 'UP';
    if (item.code_type === 'EAN-13') qualifier = 'EN';

    const lineNo = item.line_no || (idx + 1);
    const codeValue = item.code_value ? `${delimiter}${qualifier}${delimiter}${item.code_value}` : '';

    segments.push(`IT1${delimiter}${lineNo}${delimiter}${qty}${delimiter}${uom}${delimiter}${price}${delimiter}${delimiter}${codeValue}`);

    if (item.description) {
      segments.push(`PID${delimiter}F${delimiter}${delimiter}${delimiter}${delimiter}${item.description.toUpperCase().substring(0, 80)}`);
    }
  });

  // --- Summary ---
  // TDS: Total Amount (in cents)
  const totalCost = data.pricing?.total_cost || 0;
  const cents = Math.round(totalCost * 100);
  segments.push(`TDS${delimiter}${cents}`);

  // CTT: Transaction Totals
  segments.push(`CTT${delimiter}${(data.line_items || []).length}`);

  // SE: Transaction Set Trailer
  // Segment count includes ST but not ISA/GS/GE/IEA usually in raw X12, 
  // but for the 810 block it's standard to count from ST to SE.
  const tsSegmentsCount = segments.findIndex(s => s.startsWith('ST'));
  const tsCount = segments.length - tsSegmentsCount + 1;
  segments.push(`SE${delimiter}${tsCount}${delimiter}0001`);

  // GE/IEA: Functional Group and Interchange Trailers
  segments.push(`GE${delimiter}1${delimiter}1`);
  segments.push(`IEA${delimiter}1${delimiter}000000001`);

  return segments.join(terminator) + terminator;
};

