export const validateUPC = (code: string): boolean => {
  const clean = code.replace(/\D/g, ''); 
  if (clean.length !== 12) return false;

  let sum = 0;
  for (let i = 0; i < 11; i++) {
    sum += parseInt(clean[i]) * (i % 2 === 0 ? 3 : 1);
  }
  const checkDigit = (10 - (sum % 10)) % 10;
  return checkDigit === parseInt(clean[11]);
};

export const validateEAN = (code: string): boolean => {
  const clean = code.replace(/\D/g, '');
  if (clean.length !== 13) return false;

  let sum = 0;
  for (let i = 0; i < 12; i++) {
    sum += parseInt(clean[i]) * (i % 2 === 0 ? 1 : 3);
  }
  const checkDigit = (10 - (sum % 10)) % 10;
  return checkDigit === parseInt(clean[12]);
};

export const validateSSCC = (code: string): boolean => {
  const clean = code.replace(/\D/g, '');
  if (clean.length !== 18) return false;

  let sum = 0;
  for (let i = 0; i < 17; i++) {
    sum += parseInt(clean[i]) * (i % 2 === 0 ? 3 : 1);
  }
  const checkDigit = (10 - (sum % 10)) % 10;
  return checkDigit === parseInt(clean[17]);
};

export const validateCode = (value: string): CodeValidationResult => {
  if (!value) return { value: '', type: 'UNKNOWN', isValid: false };
  // Keep characters that are digits or common separators for initial clean but then strip for validation
  const clean = value.replace(/[^0-9]/g, '');

  if (clean.length === 12) {
    return { value: clean, type: 'UPC-A', isValid: validateUPC(clean) };
  }

  if (clean.length === 11) {
    const padded = '0' + clean;
    const isValid = validateUPC(padded);
    return { value: padded, type: 'UPC-A', isValid };
  }

  if (clean.length === 13) {
    return { value: clean, type: 'EAN-13', isValid: validateEAN(clean) };
  }

  if (clean.length === 18) {
    return { value: clean, type: 'SSCC-18', isValid: validateSSCC(clean) };
  }

  // Basic fallback for UCI/Serial patterns
  if (value.length >= 8 && value.length <= 25 && /^[A-Z0-9-]+$/i.test(value)) {
    return { value: value.toUpperCase(), type: 'UCI', isValid: true };
  }

  return { value: clean, type: 'UNKNOWN', isValid: false };
};

import { GoogleGenAI } from "@google/genai";
import { DocumentResult, LineItem } from "../types";
import { validateCode } from "./validationService";

const getBase64 = (file: File): Promise<string> => {
  return new Promise((resolve) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => resolve((reader.result as string).split(',')[1]);
  });
};

/**
 * Implements the round_to_retail_ending logic:
 * Round UP to 2 decimals then adjust to standard endings: .99, .49, .79, .95
 */
export const roundToRetailEnding = (retailRaw: number): number => {
  if (!retailRaw || retailRaw <= 0) return 0;

  const raw = Math.ceil(retailRaw * 100) / 100;
  const dollar = Math.floor(raw);
  const endings = [0.49, 0.79, 0.95, 0.99];

  const candidates = endings.map(e => dollar + e);
  const validCandidates = candidates.filter(c => c >= raw);

  if (validCandidates.length > 0) {
    return Math.min(...validCandidates);
  } else {
    // If no ending matches in the current dollar (e.g. raw is 5.995 -> 6.00)
    // bump to next dollar + 0.99
    return (dollar + 1) + 0.99;
  }
};

const normalizeData = (data: any): DocumentResult => {
  const base = data || {};

  const line_items = Array.isArray(base.line_items) ? base.line_items.map((it: any, idx: number) => {
    const rawCode = String(it.code_value || '').replace(/\s+/g, '');
    const validation = validateCode(rawCode);

    // Margin input normalization
    let margin = typeof it.margin_final_pct === 'number' ? it.margin_final_pct : 20;
    if (margin > 0 && margin <= 1) {
      margin = margin * 100;
    }

    const cost = typeof it.cost_unit === 'number' ? it.cost_unit : (typeof it.unit_price === 'number' ? it.unit_price : 0);

    // Retail calculation
    let retailUnit: number | null = null;
    if (cost > 0) {
      const m = Math.min(margin / 100, 0.95);
      const retailRaw = cost / (1 - m);
      retailUnit = roundToRetailEnding(retailRaw);
    }

    return {
      line_no: it.line_no || idx + 1,
      description: it.description || 'Unknown Item',
      qty: typeof it.qty === 'number' ? it.qty : 1,
      uom: it.uom || 'EA',
      cost_unit: cost,
      unit_price: cost,
      line_total: typeof it.line_total === 'number' ? it.line_total : (cost * (it.qty || 1)),
      code_value: validation.value || rawCode,
      code_type: validation.type || 'UPC-A',
      code_status: validation.isValid ? 'VALID' : (rawCode ? 'INVALID' : 'UNVERIFIED'),
      category: it.category || 'other',
      margin_suggested_pct: 20,
      margin_final_pct: margin,
      retail_unit: retailUnit,
      retail_price: retailUnit || 0
    };
  }) : [];

  const quality_issues = Array.isArray(base.quality?.issues) ? base.quality.issues : [];

  // Validation: Check if retail_unit is 0 while cost > 0
  line_items.forEach((it: LineItem) => {
    if (it.cost_unit && it.cost_unit > 0 && (!it.retail_unit || it.retail_unit === 0)) {
      quality_issues.push(`retail_calc_failed for line ${it.line_no}`);
      it.retail_unit = null;
      it.retail_price = 0;
    }
  });

  const hasCriticalData = !!(base.vendor?.name && (base.pricing?.total_cost > 0 || line_items.length > 0));

  return {
    doc_id: base.doc_id || Math.random().toString(36).substring(7),
    doc_type: base.doc_type || 'invoice',
    vendor: {
      name: base.vendor?.name || '',
      address: base.vendor?.address || '',
      city: base.vendor?.city || '',
      state: base.vendor?.state || '',
      zip: base.vendor?.zip || '',
      phone: base.vendor?.phone || ''
    },
    buyer: {
      name: base.buyer?.name || '',
      address: base.buyer?.address || '',
      city: base.buyer?.city || '',
      state: base.buyer?.state || '',
      zip: base.buyer?.zip || ''
    },
    invoice: {
      number: base.invoice?.number || '',
      date: base.invoice?.date || '',
      po: base.invoice?.po || '',
      currency: base.invoice?.currency || 'USD'
    },
    line_items,
    pricing: {
      total_cost: typeof base.pricing?.total_cost === 'number' ? base.pricing.total_cost : 
                  line_items.reduce((acc: number, curr: LineItem) => acc + (curr.line_total || 0), 0),
      total_retail: line_items.reduce((acc: number, curr: LineItem) => acc + ((curr.retail_unit || 0) * (curr.qty || 1)), 0),
      average_margin: line_items.length > 0 ? (line_items.reduce((acc: number, curr: LineItem) => acc + curr.margin_final_pct, 0) / line_items.length) : 0
    },
    edi_810: {
      version: 'X12 005010',
      segments: [],
      edi_string: base.edi_810?.edi_string || ''
    },
    labels: {
      should_generate: true,
      reason: base.labels?.reason || '',
      valid_from: base.labels?.valid_from || '',
      valid_to: base.labels?.valid_to || '',
      label_items: []
    },
    quality: {
      status: hasCriticalData ? 'ok' : 'needs_review',
      issues: quality_issues,
      field_confidence: base.quality?.field_confidence || { total: 0.85 }
    },
    raw_text: base.raw_text || ''
  };
};

export const extractInvoiceData = async (
  files: File[],
  ocrContext: string
): Promise<DocumentResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const parts = await Promise.all(files.map(async (f) => ({
    inlineData: { mimeType: f.type, data: await getBase64(f) }
  })));

  const prompt = `
    You are an invoice/receipt extractor and pricing engine.
    Output MUST be structured JSON.

    CRITICAL: Look for UPC codes which are often located UNDER the item description line. 
    They may contain hyphens (e.g., 71100-00088-1). Extract the full string.

    RETAIL + MARGIN RULES:
    - cost_unit is the invoice unit price.
    - margin_final_pct defaults to 20 or from category.
    - If margin > 1, treat as percent (e.g. 30 -> 30%).
    - retail_unit = cost_unit / (1 - (margin/100)).
    - Round retail_unit to the nearest UPWARD ending: .49, .79, .95, or .99.

    REQUIRED JSON FORMAT:
    {
      "vendor": {"name": "STRING", "address": "STRING", "city": "STRING", "state": "STRING", "zip": "STRING"},
      "invoice": {"number": "STRING", "date": "STRING", "po": "STRING", "currency": "USD"},
      "line_items": [
        {
          "line_no": 1,
          "description": "STRING",
          "qty": 1,
          "uom": "EA",
          "cost_unit": 0.0,
          "code_value": "STRING",
          "margin_final_pct": 20
        }
      ],
      "pricing": {"total_cost": 0.0},
      "quality": {"issues": []}
    }

    OCR Hint for context: ${ocrContext}
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: { parts: [...parts, { text: prompt }] },
      config: { responseMimeType: "application/json" }
    });

    const rawData = JSON.parse(response.text || "{}");
    return normalizeData(rawData);
  } catch (e) {
    console.error("Gemini extraction error:", e);
    return normalizeData({});
  }
};

