import { GoogleGenAI } from "@google/genai";
import { DocumentResult, LineItem } from "../types";
import { validateCode } from "./validationService";

const getBase64 = (file: File): Promise<string> => {
  return new Promise((resolve) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => resolve((reader.result as string).split(',')[1]);
  });
};

const normalizeData = (data: any): DocumentResult => {
  const base = data || {};

  const line_items = Array.isArray(base.line_items) ? base.line_items.map((it: any, idx: number) => {
    const rawCode = String(it.code_value || '').trim();
    const validation = validateCode(rawCode);

    const cost = typeof it.cost_unit === 'number' ? it.cost_unit : (typeof it.unit_price === 'number' ? it.unit_price : 0);

    return {
      line_no: it.line_no || idx + 1,
      description: it.description || 'Unknown Item',
      qty: typeof it.qty === 'number' ? it.qty : 1,
      uom: it.uom || 'EA',
      cost_unit: cost,
      unit_price: cost,
      line_total: typeof it.line_total === 'number' ? it.line_total : (cost * (it.qty || 1)),
      code_value: rawCode, // Keep raw value for better display
      code_type: validation.type || 'UPC-A',
      code_status: validation.isValid ? 'VALID' : (rawCode ? 'UNVERIFIED' : 'MISSING'),
      category: it.category || 'other',
      margin_suggested_pct: 0,
      margin_final_pct: 0,
      retail_unit: null,
      retail_price: 0
    };
  }) : [];

  const quality_issues = Array.isArray(base.quality?.issues) ? base.quality.issues : [];
  const hasCriticalData = !!(base.vendor?.name && (base.pricing?.total_cost > 0 || line_items.length > 0));

  return {
    doc_id: base.doc_id || Math.random().toString(36).substring(7),
    doc_type: base.doc_type || 'invoice',
    vendor: {
      name: base.vendor?.name || '',
      address: base.vendor?.address || '',
      city: base.vendor?.city || '',
      state: base.vendor?.state || '',
      zip: base.vendor?.zip || '',
      phone: base.vendor?.phone || ''
    },
    buyer: {
      name: base.buyer?.name || '',
      address: base.buyer?.address || '',
      city: base.buyer?.city || '',
      state: base.buyer?.state || '',
      zip: base.buyer?.zip || ''
    },
    invoice: {
      number: base.invoice?.number || '',
      date: base.invoice?.date || '',
      po: base.invoice?.po || '',
      currency: base.invoice?.currency || 'USD'
    },
    line_items,
    pricing: {
      total_cost: typeof base.pricing?.total_cost === 'number' ? base.pricing.total_cost : 
                  line_items.reduce((acc: number, curr: LineItem) => acc + (curr.line_total || 0), 0),
      total_retail: 0,
      average_margin: 0
    },
    edi_810: {
      version: 'X12 005010',
      segments: [],
      edi_string: base.edi_810?.edi_string || ''
    },
    labels: {
      should_generate: true,
      reason: base.labels?.reason || '',
      valid_from: '',
      valid_to: '',
      label_items: []
    },
    quality: {
      status: hasCriticalData ? 'ok' : 'needs_review',
      issues: quality_issues,
      field_confidence: base.quality?.field_confidence || { total: 0.85 }
    },
    raw_text: base.raw_text || ''
  };
};

export const extractInvoiceData = async (
  files: File[],
  ocrContext: string
): Promise<DocumentResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const parts = await Promise.all(files.map(async (f) => ({
    inlineData: { mimeType: f.type, data: await getBase64(f) }
  })));

  const prompt = `
    You are a high-precision invoice and receipt extractor.
    Output MUST be structured JSON.

    CRITICAL UPC INSTRUCTIONS:
    Receipts often list the item name on one line and the UPC on the line IMMEDIATELY BELOW IT.
    Example:
    "C6 ROCHER ART 36CT"
    "UPC 9-99999-60973-1"

    You must extract the description ("C6 ROCHER ART 36CT") and the code_value ("9-99999-60973-1").
    Do not skip these lines. They are the most important part of the document.

    NOTE: We are NOT extracting retail prices or margins at this stage. Focus only on cost and logistics data.

    REQUIRED JSON FORMAT:
    {
      "vendor": {"name": "STRING", "address": "STRING", "city": "STRING", "state": "STRING", "zip": "STRING"},
      "invoice": {"number": "STRING", "date": "STRING", "po": "STRING", "currency": "USD"},
      "line_items": [
        {
          "line_no": 1,
          "description": "STRING",
          "qty": 1,
          "uom": "EA",
          "cost_unit": 0.0,
          "code_value": "STRING (Full UPC found below description)"
        }
      ],
      "pricing": {"total_cost": 0.0}
    }

    OCR Hint for context: ${ocrContext}
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: { parts: [...parts, { text: prompt }] },
      config: { responseMimeType: "application/json" }
    });

    const rawData = JSON.parse(response.text || "{}");
    return normalizeData(rawData);
  } catch (e) {
    console.error("Gemini extraction error:", e);
    return normalizeData({});
  }
};

