import { jsPDF } from 'jspdf';
import JsBarcode from 'jsbarcode';
import { DocumentResult } from '../types';

/**
 * Generates a retail label sheet PDF from extracted document data.
 * Focuses on logistics data (Description + Barcode).
 */
export const generateRetailLabelPDF = async (data: DocumentResult): Promise<Blob | null> => {
  const validCodes = data.line_items.filter(it => it.code_value);
  if (validCodes.length === 0) return null;

  const doc = new jsPDF({ orientation: 'p', unit: 'mm', format: 'a4' });
  const margin = 10;
  const colWidth = 63;
  const rowHeight = 40;
  const cols = 3;

  doc.setFont('helvetica', 'bold');
  doc.setFontSize(10);
  doc.text(`Logistics Label Batch: ${data.invoice.number || 'Draft'}`, margin, margin);
  doc.line(margin, margin + 2, 200, margin + 2);

  let currentX = margin;
  let currentY = margin + 10;

  for (let i = 0; i < data.line_items.length; i++) {
    const item = data.line_items[i];
    if (!item.code_value) continue;

    // Label Frame
    doc.setDrawColor(240);
    doc.rect(currentX, currentY, colWidth - 2, rowHeight - 2);

    // Description (Primary focus)
    doc.setFontSize(7);
    doc.setTextColor(0);
    doc.setFont('helvetica', 'bold');
    const desc = item.description.toUpperCase().substring(0, 45);
    doc.text(desc, currentX + colWidth / 2, currentY + 8, { align: 'center' });

    // Barcode Generation
    try {
      const canvas = document.createElement('canvas');
      const cleanCode = item.code_value.replace(/[^0-9]/g, '');
      let format = 'CODE128';

      if (item.code_type === 'UPC-A' || cleanCode.length === 12) format = 'UPC';
      if (item.code_type === 'EAN-13' || cleanCode.length === 13) format = 'EAN13';

      JsBarcode(canvas, cleanCode, {
        format,
        displayValue: false,
        margin: 0,
        width: 4,
        height: 50,
        background: "#ffffff"
      });

      const imgData = canvas.toDataURL('image/png');
      doc.addImage(imgData, 'PNG', currentX + 6, currentY + 12, colWidth - 12, 18);
    } catch (err) {
      doc.setFontSize(6);
      doc.setTextColor(200, 0, 0);
      doc.text('BARCODE RENDER ERROR', currentX + colWidth / 2, currentY + 22, { align: 'center' });
    }

    // Human Readable Format
    doc.setFontSize(8);
    doc.setTextColor(0);
    doc.setFont('helvetica', 'normal');
    doc.text(item.code_value, currentX + colWidth / 2, currentY + rowHeight - 6, { align: 'center' });

    // Cell Positioning Logic
    if ((i + 1) % cols === 0) {
      currentX = margin;
      currentY += rowHeight;
    } else {
      currentX += colWidth;
    }

    if (currentY + rowHeight > 280) {
      doc.addPage();
      currentX = margin;
      currentY = margin + 10;
    }
  }

  return doc.output('blob');
};

import { GoogleGenAI, Type } from "@google/genai";
import { DocumentResult, LineItem } from "../types";
import { validateCode } from "./validationService";

const getBase64 = (file: File): Promise<string> => {
  return new Promise((resolve) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => resolve((reader.result as string).split(',')[1]);
  });
};

/**
 * Normalizes a single document result from Gemini output.
 */
export const normalizeData = (data: any, rawText?: string): DocumentResult => {
  const base = data || {};

  const line_items = Array.isArray(base.line_items) ? base.line_items.map((it: any, idx: number) => {
    const rawCode = String(it.code_value || '').trim();
    const validation = validateCode(rawCode);
    const cost = typeof it.cost_unit === 'number' ? it.cost_unit : 0;

    return {
      line_no: it.line_no || idx + 1,
      description: it.description || 'Unknown Item',
      qty: typeof it.qty === 'number' ? it.qty : 1,
      uom: it.uom || 'EA',
      cost_unit: cost,
      unit_price: cost,
      line_total: typeof it.line_total === 'number' ? it.line_total : (cost * (it.qty || 1)),
      code_value: rawCode,
      code_type: validation.type || 'UPC-A',
      code_status: validation.isValid ? 'VALID' : (rawCode ? 'UNVERIFIED' : 'MISSING'),
      category: it.category || 'other',
      margin_suggested_pct: 0,
      margin_final_pct: 0,
      retail_unit: null,
      retail_price: 0
    };
  }) : [];

  const quality_issues = Array.isArray(base.quality?.issues) ? base.quality.issues : [];
  const confidence = typeof base.quality?.confidence === 'number' ? base.quality.confidence : 85;
  const hasCriticalData = !!(base.vendor?.name && (base.pricing?.total_cost > 0 || line_items.length > 0));

  return {
    doc_id: base.doc_id || Math.random().toString(36).substring(7),
    doc_type: base.doc_type || 'invoice',
    vendor: {
      name: base.vendor?.name || '',
      address: base.vendor?.address || '',
      city: base.vendor?.city || '',
      state: base.vendor?.state || '',
      zip: base.vendor?.zip || '',
      phone: base.vendor?.phone || ''
    },
    buyer: {
      name: base.buyer?.name || '',
      address: base.buyer?.address || '',
      city: base.buyer?.city || '',
      state: base.buyer?.state || '',
      zip: base.buyer?.zip || ''
    },
    invoice: {
      number: base.invoice?.number || '',
      date: base.invoice?.date || '',
      po: base.invoice?.po || '',
      currency: base.invoice?.currency || 'USD'
    },
    line_items,
    pricing: {
      total_cost: typeof base.pricing?.total_cost === 'number' ? base.pricing.total_cost : 
                  line_items.reduce((acc: number, curr: LineItem) => acc + (curr.line_total || 0), 0),
      total_retail: 0,
      average_margin: 0
    },
    edi_810: {
      version: 'X12 005010',
      segments: [],
      edi_string: base.edi_810?.edi_string || ''
    },
    labels: {
      should_generate: true,
      reason: base.labels?.reason || '',
      valid_from: '',
      valid_to: '',
      label_items: []
    },
    quality: {
      status: hasCriticalData ? 'ok' : 'needs_review',
      issues: quality_issues,
      field_confidence: { total: confidence / 100 },
      notes: base.quality?.notes || ''
    },
    raw_text: rawText || ''
  };
};

/**
 * Advanced extraction that handles multi-image stitching.
 */
export const extractStitchedInvoiceData = async (
  files: File[]
): Promise<DocumentResult[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const parts = await Promise.all(files.map(async (f) => ({
    inlineData: { mimeType: f.type, data: await getBase64(f) }
  })));

  const prompt = `
    You are an "Invoice Stitching + EDI 810 Generator".
    TASK: Process the provided images which may be different pages or overlapping parts of the same invoice.

    CRITICAL BEHAVIOR:
    1. STITCHING: Compare all images. If they share the same Invoice #, Vendor, and Date, MERGE them into one structured document.
    2. DEDUPLICATION: Remove duplicate line items caused by photo overlaps.
    3. MULTIPLE INVOICES: If images belong to different invoice numbers, do NOT merge them. Return an array of results.
    4. UPC EXTRACTION: Capture UPC codes (often found below item names). Preserve dashes (e.g., 71100-00088-1).

    OUTPUT FORMAT:
    Return a JSON array of objects following this schema for each distinct invoice found:
    {
      "vendor": {"name": "...", "address": "..."},
      "buyer": {"name": "...", "address": "..."},
      "invoice": {"number": "...", "date": "...", "po": "..."},
      "line_items": [{"description": "...", "qty": 1, "cost_unit": 0.0, "code_value": "..."}],
      "pricing": {"total_cost": 0.0},
      "quality": {
        "confidence": 0-100,
        "issues": ["..."],
        "notes": "Explain stitching logic or conflicts found"
      }
    }
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: { parts: [...parts, { text: prompt }] },
      config: { responseMimeType: "application/json" }
    });

    const results = JSON.parse(response.text || "[]");
    const normalized = Array.isArray(results) 
      ? results.map(r => normalizeData(r))
      : [normalizeData(results)];

    return normalized;
  } catch (e) {
    console.error("Stitching extraction error:", e);
    return [];
  }
};

/**
 * Re-exporting roundToRetailEnding for utility in manual edits
 */
export const roundToRetailEnding = (retailRaw: number): number => {
  if (!retailRaw || retailRaw <= 0) return 0;
  const raw = Math.ceil(retailRaw * 100) / 100;
  const dollar = Math.floor(raw);
  const endings = [0.49, 0.79, 0.95, 0.99];
  const candidates = endings.map(e => dollar + e);
  const validCandidates = candidates.filter(c => c >= raw);
  return validCandidates.length > 0 ? Math.min(...validCandidates) : (dollar + 1) + 0.99;
};

