               </div>
               <div className={`text-[8px] opacity-60 mt-2 font-mono flex items-center justify-between`}>
                 <span>ID: {inv.id.toUpperCase()}</span>
                 <span className="bg-slate-100 group-hover:bg-slate-200 text-slate-600 px-1.5 py-0.5 rounded-md uppercase text-[7px]">MERGED</span>
               </div>
             </button>
           ))}
        </div>
        <button onClick={startOver} className="mt-8 py-5 bg-slate-900 text-white rounded-[24px] font-black uppercase text-[10px] tracking-[0.2em] shadow-2xl flex items-center justify-center active:scale-95 transition-all"><RotateCcw className="w-4 h-4 mr-3" />New Session</button>
      </aside>

      <main className="flex-1 p-16 max-w-7xl mx-auto h-screen overflow-y-auto">
        {currentActiveInv ? (
          <DocResultView 
            inv={currentActiveInv} 
            isPreviewing={previewingDocId === expandedDoc}
            onTogglePreview={() => setPreviewingDocId(p => p ? null : expandedDoc)}
            onEdit={handleEdit}
            onSync={syncChanges}
          />
        ) : (
          <div className="h-full flex flex-col items-center justify-center text-slate-300">
            <LayoutGrid className="w-24 h-24 mb-6 opacity-10" />
            <p className="font-black uppercase tracking-widest text-sm text-slate-400">Select results to review</p>
          </div>
        )}
      </main>
    </div>
  );
};

