export type AppStep = 'UPLOAD' | 'PROCESSING' | 'RESULTS';

export type DocType = 'invoice' | 'receipt' | 'unknown';

export interface Party {
  name: string;
  address: string;
  city: string;
  state: string;
  zip: string;
  account_id?: string;
  phone?: string;
}

export interface LineItem {
  line_no: number;
  description: string;
  qty: number | null;
  uom: string;
  cost_unit: number | null; // Unit Cost
  unit_price: number | null; // Alias for cost_unit for backwards compatibility
  line_total: number | null;
  code_type: string;
  code_value: string;
  code_status: 'VALID' | 'INVALID' | 'UNVERIFIED' | 'MISSING';
  category: string;
  margin_suggested_pct: number;
  margin_final_pct: number;
  retail_unit: number | null;
  retail_price: number; // Alias for retail_unit for backwards compatibility
}

export interface LabelItem {
  description_short: string;
  barcode_value: string;
  barcode_type: string;
  retail_price: number;
  sku_or_item: string;
}

export interface DocumentResult {
  doc_id: string;
  doc_type: DocType;
  vendor: Party;
  buyer: Party;
  invoice: {
    number: string;
    date: string;
    po?: string;
    currency: string;
  };
  line_items: LineItem[];
  pricing: {
    total_cost: number;
    total_retail: number;
    average_margin: number;
  };
  edi_810: {
    version: string;
    segments: string[];
    edi_string: string;
  };
  labels: {
    should_generate: boolean;
    reason: string;
    valid_from: string;
    valid_to: string;
    label_items: LabelItem[];
  };
  quality: {
    status: 'ok' | 'needs_review';
    issues: string[];
    field_confidence: Record<string, number>;
    notes?: string;
  };
  raw_text?: string;
}

export interface InvoiceState {
  id: string;
  files: File[];
  previewUrls: string[];
  status: 'QUEUED' | 'RUNNING' | 'DONE' | 'NEEDS_REVIEW';
  progress: number;
  currentTask: string;
  sellerName: string;
  data: DocumentResult | null;
  pdfBlobUrl: string | null;
  retryCount: number;
  extractionMethod: 'OCR' | 'HYBRID' | 'GEMINI';
}

export interface BatchState {
  name: string;
  invoices: InvoiceState[];
}

export enum ProcessingStep {
  RUNNING_OCR = 'RUNNING_OCR',
  UNDERSTANDING_INVOICE = 'UNDERSTANDING_INVOICE',
  GENERATING_EDI = 'GENERATING_EDI',
  GENERATING_PDF = 'GENERATING_PDF',
  COMPLETED = 'COMPLETED'
}

export interface DetectedCode {
  value: string;
  type: string;
  price?: number;
  unit?: string;
  description?: string;
  dateLeft?: string;
  dateRight?: string;
}

export interface CodeValidationResult {
  value: string;
  type: string;
  isValid: boolean;
}

import { DocumentResult } from '../types';

/**
 * Converts DocumentResult into a CSV string.
 * Optimized for spreadsheet imports (Excel, Sheets, etc.)
 */
export const generateCSVFromData = (data: DocumentResult): string => {
  const headers = [
    'Line #',
    'UPC/GTIN',
    'Description',
    'Qty',
    'UOM',
    'Unit Cost',
    'Line Total',
    'Vendor',
    'Invoice #',
    'Date'
  ];

  const rows = data.line_items.map(item => {
    // Escape double quotes in descriptions/vendor names
    const desc = (item.description || '').replace(/"/g, '""');
    const vendor = (data.vendor?.name || '').replace(/"/g, '""');
    const invNo = (data.invoice?.number || '').replace(/"/g, '""');

    // We wrap values in quotes to handle commas within fields
    return [
      item.line_no,
      `"${item.code_value || ''}"`, // Quoted to prevent scientific notation in Excel for long UPCs
      `"${desc}"`,
      item.qty || 0,
      `"${item.uom || 'EA'}"`,
      (item.cost_unit || 0).toFixed(2),
      (item.line_total || 0).toFixed(2),
      `"${vendor}"`,
      `"${invNo}"`,
      `"${data.invoice?.date || ''}"`
    ].join(',');
  });

  return [headers.join(','), ...rows].join('\n');
};

