                 <span>ID: {inv.id.toUpperCase()}</span>
                 <span className="bg-slate-100 group-hover:bg-slate-200 text-slate-600 px-1.5 py-0.5 rounded-md uppercase text-[7px]">MERGED</span>
               </div>
