        <button onClick={startOver} className="mt-8 py-5 bg-slate-900 text-white rounded-[24px] font-black uppercase text-[10px] tracking-[0.2em] shadow-2xl flex items-center justify-center active:scale-95 transition-all"><RotateCcw className="w-4 h-4 mr-3" />New Session</button>
