                  <Upload className="w-12 h-12 text-indigo-500 mx-auto mb-4" />
                  <p className="font-black text-slate-900">Drop Invoice Photos</p>
                  <p className="text-xs text-slate-400 mt-1 uppercase font-bold tracking-widest">Select 2-4 photos to stitch together</p>
