import { jsPDF } from 'jspdf';
import JsBarcode from 'jsbarcode';
import { DocumentResult } from '../types';

/**
 * Generates a retail label sheet PDF from extracted document data.
 * Focuses on logistics data (Description + Barcode).
 */
export const generateRetailLabelPDF = async (data: DocumentResult): Promise<Blob | null> => {
  const validCodes = data.line_items.filter(it => it.code_value);
  if (validCodes.length === 0) return null;

  const doc = new jsPDF({ orientation: 'p', unit: 'mm', format: 'a4' });
  const margin = 10;
  const colWidth = 63;
  const rowHeight = 40;
  const cols = 3;

  doc.setFont('helvetica', 'bold');
  doc.setFontSize(10);
  doc.text(`Logistics Label Batch: ${data.invoice.number || 'Draft'}`, margin, margin);
  doc.line(margin, margin + 2, 200, margin + 2);

  let currentX = margin;
  let currentY = margin + 10;

  for (let i = 0; i < data.line_items.length; i++) {
    const item = data.line_items[i];
    if (!item.code_value) continue;

    // Label Frame
    doc.setDrawColor(240);
    doc.rect(currentX, currentY, colWidth - 2, rowHeight - 2);

    // Description (Primary focus)
    doc.setFontSize(7);
    doc.setTextColor(0);
    doc.setFont('helvetica', 'bold');
    const desc = item.description.toUpperCase().substring(0, 45);
    doc.text(desc, currentX + colWidth / 2, currentY + 8, { align: 'center' });

    // Barcode Generation
    try {
      const canvas = document.createElement('canvas');
      const cleanCode = item.code_value.replace(/[^0-9]/g, '');
      let format = 'CODE128';

      if (item.code_type === 'UPC-A' && cleanCode.length === 12) {
        format = 'UPC';
      } else if (item.code_type === 'EAN-13' && cleanCode.length === 13) {
        format = 'EAN13';
      }

      const renderOptions = {
        format,
        displayValue: false,
        margin: 0,
        width: 4,
        height: 50,
        background: "#ffffff"
      };

      try {
        JsBarcode(canvas, cleanCode, renderOptions);
      } catch (innerErr) {
        // Fallback to generic CODE128 for invalid/noisy UPC/EAN checksums
        JsBarcode(canvas, cleanCode, { ...renderOptions, format: 'CODE128' });
      }

      const imgData = canvas.toDataURL('image/png');
      doc.addImage(imgData, 'PNG', currentX + 6, currentY + 12, colWidth - 12, 18);
    } catch (err) {
      doc.setFontSize(6);
      doc.setTextColor(200, 0, 0);
      doc.text('BARCODE RENDER ERROR', currentX + colWidth / 2, currentY + 22, { align: 'center' });
    }

    // Human Readable Format
    doc.setFontSize(8);
    doc.setTextColor(0);
    doc.setFont('helvetica', 'normal');
    doc.text(item.code_value, currentX + colWidth / 2, currentY + rowHeight - 6, { align: 'center' });

    // Cell Positioning Logic
    if ((i + 1) % cols === 0) {
      currentX = margin;
      currentY += rowHeight;
    } else {
      currentX += colWidth;
    }

    if (currentY + rowHeight > 280) {
      doc.addPage();
      currentX = margin;
      currentY = margin + 10;
    }
  }

  return doc.output('blob');
};

