const getBase64 = (file: File): Promise<string> => {
  return new Promise((resolve) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => resolve((reader.result as string).split(',')[1]);
  });
};

/**
 * Normalizes a complex lossless result into the App's state.
 */
export const normalizeData = (data: any, sections: any): DocumentResult => {
  const base = data || {};

  const line_items = Array.isArray(base.line_items) ? base.line_items.map((it: any, idx: number) => {
    const rawCode = String(it.upc || it.item_id_or_sku || '').trim();
    const validation = validateCode(rawCode);
    const cost = typeof it.unit_cost === 'number' ? it.unit_cost : parseFloat(String(it.unit_cost || '0').replace(/[^0-9.]/g, ''));

    return {
      line_no: it.line_no || idx + 1,
      upc: it.upc || '',
      item_id_or_sku: it.item_id_or_sku || '',
      description: it.description || 'Unknown Item',
      qty_purchased: it.qty_purchased || 1,
      uom_purchased: it.uom_purchased || 'EA',
      packaging_level: it.packaging_level || '',
      pack_structure_raw: it.pack_structure_raw || '',
      units_per_case: it.units_per_case || '',
      container_size_value: it.container_size_value || '',
      container_size_uom: it.container_size_uom || '',
      container_type: it.container_type || '',
      retail_units_total: it.retail_units_total || '',
      packaging_interpretation_note: it.packaging_interpretation_note || '',
      unit_cost: cost,
      extended_amount: parseFloat(String(it.extended_amount || '0').replace(/[^0-9.]/g, '')),
      retail_ssp_msrp: parseFloat(String(it.retail_ssp_msrp || '0').replace(/[^0-9.]/g, '')),
      discount_amount: it.discount_amount || '',
      discount_percent: it.discount_percent || '',
      promo_amount: it.promo_amount || '',
      deposit_dp_crv: it.deposit_dp_crv || '',
      net_amount: parseFloat(String(it.net_amount || '0').replace(/[^0-9.]/g, '')),
      tax_flags: it.tax_flags || '',
      extra_fields: it.extra_fields || [],
      // Standard App Mappings
      code_value: rawCode,
      code_type: validation.type || 'UPC-A',
      code_status: validation.isValid ? 'VALID' : (rawCode ? 'UNVERIFIED' : 'MISSING'),
      category: 'other'
    };
  }) : [];

  const totalCost = base.header_fields?.totals?.total_cost || 0;

  return {
    doc_id: Math.random().toString(36).substring(7),
    doc_type: 'invoice',
    invoice_identity: {
      vendor_name: base.invoice_identity?.vendor_name || 'Unknown',
      buyer_name: base.invoice_identity?.buyer_name || '',
      invoice_number: base.invoice_identity?.invoice_number || '',
      invoice_date: base.invoice_identity?.invoice_date || '',
      confidence_score_0_to_100: base.invoice_identity?.confidence_score_0_to_100 || 85,
      source_images_count: base.invoice_identity?.source_images_count || 1
    },
    header_fields: {
      vendor: base.header_fields?.vendor || {},
      buyer: base.header_fields?.buyer || {},
      delivery: base.header_fields?.delivery || {},
      payment_terms: base.header_fields?.payment_terms || {},
      totals: {
        total_cost: totalCost,
        subtotal: base.header_fields?.totals?.subtotal,
        tax: base.header_fields?.totals?.tax,
        fees: base.header_fields?.totals?.fees,
        discounts: base.header_fields?.totals?.discounts
      },
      route_driver_sales: base.header_fields?.route_driver_sales || {},
      extra_fields: base.header_fields?.extra_fields || []
    },
    line_items,
    edi_810: {
      edi_string: sections.edi || ''
    },
    sections_raw: sections,
    quality: {
      status: (totalCost > 0 || line_items.length > 0) ? 'ok' : 'needs_review',
      issues: base.warnings || [],
      field_confidence: { total: (base.invoice_identity?.confidence_score_0_to_100 || 85) / 100 }
    }
  };
};

export const extractStitchedInvoiceData = async (
  files: File[]
): Promise<DocumentResult[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const parts = await Promise.all(files.map(async (f) => ({
    inlineData: { mimeType: f.type, data: await getBase64(f) }
  })));

  const systemInstruction = `
    You are a senior convenience-store back-office manager + EDI specialist (20–30 years experience).
    You are extremely strict about NOT losing any information.

    MISSION:
    1) Stitch photos belonging to the same invoice.
    2) Extract ALL header + line item details.
    3) Build a "ZERO-LOSS" record. Nothing is discarded.
    4) Capture QUANTITY vs PACK/CASE/UNITS logic specifically.

    OUTPUT STRUCTURE:
    SECTION 1: LOSSLESS FULL INVOICE JSON (Wrap in \`\`\`json ... \`\`\`)
    SECTION 2: POS IMPORT PREVIEW (CSV STYLE) (Wrap in \`\`\`csv ... \`\`\`)
    SECTION 3: EDI 810 (005010) (Wrap in \`\`\`text ... \`\`\`)
    SECTION 4: EXTRA FIELDS NOT IN EDI (ZERO-LOSS) (Plain text list)

    RULES:
    - Never assume or invent values.
    - If multiple invoices detected, output MULTIPLE_INVOICES_DETECTED.
    - Use strict CCYYMMDD for EDI dates.
    - Follow all specific fields for packaging (qty_purchased, pack_structure_raw, etc.)
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: { parts: [...parts, { text: "Stitch and extract these photos. ZERO LOSS." }] },
      config: { 
        systemInstruction,
        temperature: 0.1
      }
    });

    const text = response.text || "";
    if (text.includes("MULTIPLE_INVOICES_DETECTED")) {
      console.warn("Multiple invoices found in batch.");
    }

    // Helper to extract content between specific markers
    const extractSection = (fullText: string, startMarker: string, endMarker: string) => {
      const startIdx = fullText.indexOf(startMarker);
      if (startIdx === -1) return "";
      const content = fullText.substring(startIdx + startMarker.length);
      const endIdx = content.indexOf(endMarker);
      return endIdx === -1 ? content.trim() : content.substring(0, endIdx).trim();
    };

    const jsonStr = extractSection(text, "```json", "```");
    const csvStr = extractSection(text, "```csv", "```");
    const ediStr = extractSection(text, "SECTION 3: EDI 810", "SECTION 4:"); 
    // The EDI is often in a text block, let's refine the extraction
    const refinedEdi = ediStr.includes("```") ? extractSection(ediStr, "```", "```") : ediStr;
    const extraStr = text.substring(text.indexOf("SECTION 4:") + "SECTION 4:".length).trim();

    try {
      const jsonData = JSON.parse(jsonStr);
      const sections = {
        json: jsonStr,
        csv: csvStr,
        edi: refinedEdi,
        extra: extraStr
      };

      // For simplicity of this demo, we assume one stitched result. 
      // If the AI outputs a list of JSONs, we could iterate.
      return [normalizeData(jsonData, sections)];
    } catch (parseErr) {
      console.error("JSON parse error on Gemini result", parseErr, jsonStr);
      return [];
    }

  } catch (e) {
    console.error("Stitching extraction error:", e);
    return [];
  }
};

export const roundToRetailEnding = (retailRaw: number): number => {
  if (!retailRaw || retailRaw <= 0) return 0;
  const raw = Math.ceil(retailRaw * 100) / 100;
  const dollar = Math.floor(raw);
  const endings = [0.49, 0.79, 0.95, 0.99];
  const candidates = endings.map(e => dollar + e);
  const validCandidates = candidates.filter(c => c >= raw);
  return validCandidates.length > 0 ? Math.min(...validCandidates) : (dollar + 1) + 0.99;
};

