const getBase64 = (file: File): Promise<string> => {
  return new Promise((resolve) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => resolve((reader.result as string).split(',')[1]);
  });
};

/**
 * Normalizes a complex lossless result into the App's state.
 * Handles variations in field names to ensure zero-loss extraction.
 */
export const normalizeData = (rawData: any): DocumentResult => {
  // Extract sections from the new unified JSON structure
  const base = rawData.lossless_json || {};
  const sections = {
    json: JSON.stringify(base, null, 2),
    csv: rawData.csv_preview || "",
    edi: rawData.edi_810_text || "",
    extra: rawData.extra_fields_audit_text || ""
  };

  const line_items = Array.isArray(base.line_items) ? base.line_items.map((it: any, idx: number) => {
    const rawCode = String(it.upc || it.item_id_or_sku || it.code_value || '').trim();
    const validation = validateCode(rawCode);

    // Robust numeric parsing
    const parseNum = (val: any) => {
      if (typeof val === 'number') return val;
      if (!val) return 0;
      const cleaned = String(val).replace(/[^0-9.-]/g, '');
      return parseFloat(cleaned) || 0;
    };

    const unitCost = parseNum(it.unit_cost || it.unit_price || it.cost);
    const extAmount = parseNum(it.extended_amount || it.line_total || it.total);

    return {
      line_no: it.line_no || idx + 1,
      upc: it.upc || '',
      item_id_or_sku: it.item_id_or_sku || '',
      description: it.description || 'Unknown Item',
      qty_purchased: it.qty_purchased || it.qty || 1,
      uom_purchased: it.uom_purchased || it.uom || 'EA',
      packaging_level: it.packaging_level || '',
      pack_structure_raw: it.pack_structure_raw || '',
      units_per_case: it.units_per_case || '',
      container_size_value: it.container_size_value || '',
      container_size_uom: it.container_size_uom || '',
      container_type: it.container_type || '',
      retail_units_total: it.retail_units_total || '',
      packaging_interpretation_note: it.packaging_interpretation_note || '',
      unit_cost: unitCost,
      extended_amount: extAmount,
      retail_ssp_msrp: parseNum(it.retail_ssp_msrp || it.msrp || it.retail),
      discount_amount: it.discount_amount || '',
      discount_percent: it.discount_percent || '',
      promo_amount: it.promo_amount || '',
      deposit_dp_crv: it.deposit_dp_crv || '',
      net_amount: parseNum(it.net_amount || extAmount),
      tax_flags: it.tax_flags || '',
      extra_fields: it.extra_fields || [],
      // Standard App Mappings
      code_value: rawCode,
      code_type: validation.type || 'UPC-A',
      code_status: validation.isValid ? 'VALID' : (rawCode ? 'UNVERIFIED' : 'MISSING'),
      category: 'other'
    };
  }) : [];

  const totals = base.header_fields?.totals || {};
  const totalCost = parseNum(totals.total_cost || totals.total_amount || totals.net_amount || 0);

  return {
    doc_id: Math.random().toString(36).substring(7),
    doc_type: 'invoice',
    invoice_identity: {
      vendor_name: base.invoice_identity?.vendor_name || 'Unknown Vendor',
      buyer_name: base.invoice_identity?.buyer_name || '',
      invoice_number: base.invoice_identity?.invoice_number || '',
      invoice_date: base.invoice_identity?.invoice_date || '',
      confidence_score_0_to_100: base.invoice_identity?.confidence_score_0_to_100 || 85,
      source_images_count: base.invoice_identity?.source_images_count || 1,
      po: base.invoice_identity?.po || '',
      currency: base.invoice_identity?.currency || 'USD'
    },
    header_fields: {
      vendor: base.header_fields?.vendor || {},
      buyer: base.header_fields?.buyer || {},
      delivery: base.header_fields?.delivery || {},
      payment_terms: base.header_fields?.payment_terms || {},
      totals: {
        total_cost: totalCost,
        subtotal: parseNum(totals.subtotal),
        tax: parseNum(totals.tax),
        fees: parseNum(totals.fees),
        discounts: parseNum(totals.discounts)
      },
      route_driver_sales: base.header_fields?.route_driver_sales || {},
      extra_fields: base.header_fields?.extra_fields || []
    },
    line_items,
    edi_810: {
      edi_string: sections.edi || ''
    },
    sections_raw: sections,
    quality: {
      status: (totalCost > 0 || line_items.length > 0) ? 'ok' : 'needs_review',
      issues: base.warnings || [],
      field_confidence: { total: (base.invoice_identity?.confidence_score_0_to_100 || 85) / 100 }
    }
  };

  function parseNum(val: any) {
    if (typeof val === 'number') return val;
    if (!val) return 0;
    const cleaned = String(val).replace(/[^0-9.-]/g, '');
    return parseFloat(cleaned) || 0;
  }
};

export const extractStitchedInvoiceData = async (
  files: File[]
): Promise<DocumentResult[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const parts = await Promise.all(files.map(async (f) => ({
    inlineData: { mimeType: f.type, data: await getBase64(f) }
  })));

  const systemInstruction = `
    You are a senior convenience-store back-office manager + EDI specialist.
    Your mission is ZERO-LOSS extraction from invoice photos.

    STITCHING: Match multiple photos that belong to the same invoice and merge their lines.
    PACKAGING: Capture qty_purchased, pack_structure_raw (e.g. 4/6), units_per_case, and container_size.

    OUTPUT: You must return a SINGLE JSON object with the following keys:
    1. "lossless_json": The complete structured record (header_fields, line_items, invoice_identity, warnings).
    2. "csv_preview": A CSV string representing the POS import.
    3. "edi_810_text": A valid X12 810 EDI string using '*' and '~'.
    4. "extra_fields_audit_text": A plain text description of all extra fields captured.

    Strictly follow the JSON schema provided in the request context. Never omit fields. If data is missing, use "".
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: { parts: [...parts, { text: "Audit these photos. Return the combined JSON results including EDI and CSV. If multiple invoices, separate them." }] },
      config: { 
        systemInstruction,
        temperature: 0.1,
        responseMimeType: "application/json"
      }
    });

    const resultText = response.text || "{}";
    const rawResult = JSON.parse(resultText);

    // Handle the case where the model returns an array of invoices or a single object
    if (Array.isArray(rawResult)) {
      return rawResult.map(res => normalizeData(res));
    } else if (rawResult.lossless_json) {
      return [normalizeData(rawResult)];
    } else {
      // Fallback if the AI didn't nest it exactly as requested but gave some JSON
      return [normalizeData({ lossless_json: rawResult })];
    }

  } catch (e) {
    console.error("Critical Stitching extraction error:", e);
    throw e;
  }
};

export const roundToRetailEnding = (retailRaw: number): number => {
  if (!retailRaw || retailRaw <= 0) return 0;
  const raw = Math.ceil(retailRaw * 100) / 100;
  const dollar = Math.floor(raw);
  const endings = [0.49, 0.79, 0.95, 0.99];
  const candidates = endings.map(e => dollar + e);
  const validCandidates = candidates.filter(c => c >= raw);
  return validCandidates.length > 0 ? Math.min(...validCandidates) : (dollar + 1) + 0.99;
};

