        throw new Error("No data could be extracted from these images. Please ensure they are clear invoice or receipt photos.");
      }

      const newInvoiceStates: InvoiceState[] = await Promise.all(results.map(async (data) => {
        setProcessingStatus(`Finalizing Logistics for ${data.invoice_identity.vendor_name}...`);

        const pdf = await generateRetailLabelPDF(data);
        const pdfUrl = pdf ? URL.createObjectURL(pdf) : null;

        return {
