import { GoogleGenAI, Type } from "@google/genai";
import { DocumentResult, LineItem, ExtraField } from "../types";
import { validateCode } from "./validationService";

const getBase64 = (file: File): Promise<string> => {
  return new Promise((resolve) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => resolve((reader.result as string).split(',')[1]);
  });
};

/**
 * Normalizes a complex lossless result into the App's state.
 * Implements Rule 5: Robust Pricing and Zero-Loss Mapping.
 */
export const normalizeData = (rawData: any, rawSections: any): DocumentResult => {
  const base = rawData || {};

  // Robust numeric parsing
  const parseNum = (val: any) => {
    if (typeof val === 'number') return val;
    if (!val || val === "") return null;
    const cleaned = String(val).replace(/[^0-9.-]/g, '');
    const parsed = parseFloat(cleaned);
    return isNaN(parsed) ? null : parsed;
  };

  const line_items = Array.isArray(base.line_items) ? base.line_items.map((it: any, idx: number) => {
    const rawCode = String(it.upc_gtin?.value || it.item_id?.value || it.upc || '').trim();
    const validation = validateCode(rawCode);

    // Rule 5: Pricing Heuristics (Unit Cost Calculation)
    const netTotal = parseNum(it.net_line_total?.value || it.extended_amount || it.amount);
    const qty = parseNum(it.qty_purchased?.value || it.qty) || 1;
    const gross = parseNum(it.gross_price?.value || it.unit_price);

    let unitCost = gross;
    if (!unitCost && netTotal) {
      unitCost = netTotal / qty;
    }

    return {
      line_no: it.line_no || idx + 1,
      upc: it.upc_gtin?.value || it.upc || '',
      item_id_or_sku: it.item_id?.value || it.item_id || '',
      description: it.description?.value || it.description || 'Unknown Item',
      qty_purchased: qty,
      uom_purchased: it.uom_purchased?.value || it.uom || 'EA',
      packaging_level: it.packaging_level || '',
      pack_structure_raw: it.pack_structure_raw?.value || '',
      units_per_case: it.units_per_case?.value || '',
      container_size_value: it.container_size_raw?.value || '',
      container_size_uom: '', // Derived if needed
      container_type: '',
      retail_units_total: '',
      packaging_interpretation_note: it.packaging_interpretation_note || '',
      unit_cost: unitCost,
      extended_amount: netTotal,
      retail_ssp_msrp: parseNum(it.retail_price?.value),
      discount_amount: it.discount?.value || '',
      discount_percent: '',
      promo_amount: '',
      deposit_dp_crv: it.deposit?.value || '',
      net_amount: netTotal,
      tax_flags: it.tax_flags || '',
      extra_fields: it.extra_fields || [],
      // App Internal
      code_value: rawCode,
      code_type: validation.type || 'UPC-A',
      code_status: validation.isValid ? 'VALID' : (rawCode ? 'UNVERIFIED' : 'MISSING'),
      category: 'other'
    };
  }) : [];

  const totals = base.totals || {};
  const totalDue = parseNum(totals.total_due?.value || totals.invoice_total?.value || 0);

  return {
    doc_id: Math.random().toString(36).substring(7),
    doc_type: 'invoice',
    invoice_identity: {
      vendor_name: base.header?.vendor_name?.value || 'Unknown Vendor',
      buyer_name: base.header?.buyer_name?.value || '',
      invoice_number: base.header?.invoice_number?.value || '',
      invoice_date: base.header?.invoice_date?.value || '',
      confidence_score_0_to_100: base.confidence_overall || 85,
      source_images_count: base.header?.source_images_count || 1,
      po: base.header?.po_number?.value || '',
      currency: base.header?.currency?.value || 'USD'
    },
    header_fields: {
      vendor: {
        name: base.header?.vendor_name?.value || '',
        address: base.header?.vendor_address?.value || '',
        city: '', state: '', zip: '',
        phone: base.header?.vendor_phone?.value || ''
      },
      buyer: {
        name: base.header?.buyer_name?.value || '',
        address: base.header?.buyer_address?.value || '',
        city: '', state: '', zip: '',
        account_id: base.header?.['customer_id/account']?.value || ''
      },
      delivery: base.header?.delivery_datetime?.value || {},
      payment_terms: base.header?.terms?.value || {},
      totals: {
        total_cost: totalDue || 0,
        subtotal: parseNum(totals.subtotal?.value),
        tax: parseNum(totals.total_tax?.value),
        fees: 0,
        discounts: parseNum(totals.total_discount?.value)
      },
      route_driver_sales: base.header?.route_stop_driver_salesrep?.value || {},
      extra_fields: base.extra_fields_header || []
    },
    line_items,
    edi_810: {
      edi_string: rawSections.edi || ''
    },
    sections_raw: rawSections,
    quality: {
      status: (totalDue > 0 || line_items.length > 0) ? 'ok' : 'needs_review',
      issues: base.parsing_warnings || [],
      field_confidence: { total: (base.confidence_overall || 85) / 100 }
    }
  };
};

export const extractStitchedInvoiceData = async (
  files: File[]
): Promise<DocumentResult[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const parts = await Promise.all(files.map(async (f) => ({
    inlineData: { mimeType: f.type, data: await getBase64(f) }
  })));

  const systemInstruction = `
    You are a senior convenience-store back-office manager + EDI specialist.
    Your mission: ZERO-LOSS extraction from invoice photos.

    1. STITCHING: Match multiple photos for the same invoice.
    2. PACKAGING: Capture qty, pack_structure, units_per_case.
    3. PRICING: NEVER default to 0.00. Calculate unit cost from (net_line_total / qty) if PRICE is missing.
    4. ZERO LOSS: If a field doesn't map, use extra_fields.

    You must return a JSON response matching the provided schema.
  `;

  // Define strict response schema for reliable JSON parsing
  // Fix: Type.OBJECT must have non-empty properties defined
  const valueWithEvidence = {
    type: Type.OBJECT,
    properties: {
      value: { type: Type.STRING },
      confidence: { type: Type.NUMBER },
      evidence: { type: Type.STRING }
    }
  };

  const schema = {
    type: Type.OBJECT,
    properties: {
      document_groups: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            lossless_json: {
              type: Type.OBJECT,
              properties: {
                header: { 
                  type: Type.OBJECT,
                  properties: {
                    vendor_name: valueWithEvidence,
                    vendor_address: valueWithEvidence,
                    vendor_phone: valueWithEvidence,
                    buyer_name: valueWithEvidence,
                    buyer_address: valueWithEvidence,
                    "customer_id/account": valueWithEvidence,
                    invoice_number: valueWithEvidence,
                    invoice_date: valueWithEvidence,
                    delivery_datetime: valueWithEvidence,
                    terms: valueWithEvidence,
                    po_number: valueWithEvidence,
                    route_stop_driver_salesrep: valueWithEvidence,
                    currency: valueWithEvidence
                  }
                },
                totals: { 
                  type: Type.OBJECT, 
                  properties: {
                    invoice_total: valueWithEvidence,
                    total_due: valueWithEvidence,
                    total_discount: valueWithEvidence,
                    total_deposit: valueWithEvidence,
                    total_tax: valueWithEvidence,
                    total_credits: valueWithEvidence,
                    subtotal: valueWithEvidence
                  }
                },
                line_items: { 
                  type: Type.ARRAY, 
                  items: { 
                    type: Type.OBJECT,
                    properties: {
                      line_no: { type: Type.NUMBER },
                      item_id: valueWithEvidence,
                      upc_gtin: valueWithEvidence,
                      description: valueWithEvidence,
                      qty_purchased: valueWithEvidence,
                      uom_purchased: valueWithEvidence,
                      units_per_case: valueWithEvidence,
                      pack_structure_raw: valueWithEvidence,
                      container_size_raw: valueWithEvidence,
                      retail_price: valueWithEvidence,
                      gross_price: valueWithEvidence,
                      discount: valueWithEvidence,
                      deposit: valueWithEvidence,
                      sugar_fee: valueWithEvidence,
                      net_line_total: valueWithEvidence
                    }
                  } 
                },
                confidence_overall: { type: Type.NUMBER },
                parsing_warnings: { type: Type.ARRAY, items: { type: Type.STRING } }
              }
            },
            csv_preview: { type: Type.STRING },
            edi_810_text: { type: Type.STRING },
            extra_fields_audit_text: { type: Type.STRING }
          }
        }
      }
    },
    required: ["document_groups"]
  };

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: { parts: [...parts, { text: "Stitch and audit these photos. ZERO LOSS." }] },
      config: { 
        systemInstruction,
        temperature: 0.1,
        responseMimeType: "application/json",
        responseSchema: schema
      }
    });

    const result = JSON.parse(response.text || "{}");

    if (!result.document_groups || !Array.isArray(result.document_groups)) {
      throw new Error("Invalid response format from AI.");
    }

    return result.document_groups.map((group: any) => {
      const sections = {
        json: JSON.stringify(group.lossless_json, null, 2),
        csv: group.csv_preview || "",
        edi: group.edi_810_text || "",
        extra: group.extra_fields_audit_text || ""
      };
      return normalizeData(group.lossless_json, sections);
    });

  } catch (e) {
    console.error("Extraction error:", e);
    throw new Error("Could not process images. " + (e instanceof Error ? e.message : "Unknown error."));
  }
};

export const roundToRetailEnding = (retailRaw: number): number => {
  if (!retailRaw || retailRaw <= 0) return 0;
  const raw = Math.ceil(retailRaw * 100) / 100;
  const dollar = Math.floor(raw);
  const endings = [0.49, 0.79, 0.95, 0.99];
  const candidates = endings.map(e => dollar + e);
  const validCandidates = candidates.filter(c => c >= raw);
  return validCandidates.length > 0 ? Math.min(...validCandidates) : (dollar + 1) + 0.99;
};
